window.trendingPapers = {
    "today": [{"paper": {"id": "2605.22355", "authors": [{"_id": "6a0fc10ea53a61ce2e422c9a", "user": {"_id": "6964ab352fb9f77cbe8c9854", "avatarUrl": "/avatars/2c4734b40bb98d162837fbe6b128f7d7.svg", "isPro": false, "fullname": "Hanyu Guo", "user": "MaoPaJia", "type": "user", "name": "MaoPaJia"}, "name": "Hanyu Guo", "status": "claimed_verified", "statusLastChangedAt": "2026-05-22T16:08:45.926Z", "hidden": false}, {"_id": "6a0fc10ea53a61ce2e422c9b", "name": "Jiedong Yang", "hidden": false}, {"_id": "6a0fc10ea53a61ce2e422c9c", "name": "Chao Chen", "hidden": false}, {"_id": "6a0fc10ea53a61ce2e422c9d", "user": {"_id": "682eeb11d28d9650c926abb0", "avatarUrl": "/avatars/3c8a34cc61aa2330ffcb52446a9afe70.svg", "isPro": false, "fullname": "LONGFEI XU", "user": "Xufew", "type": "user", "name": "Xufew"}, "name": "Longfei Xu", "status": "claimed_verified", "statusLastChangedAt": "2026-05-22T16:08:49.010Z", "hidden": false}, {"_id": "6a0fc10ea53a61ce2e422c9e", "name": "Kaikui Liu", "hidden": false}, {"_id": "6a0fc10ea53a61ce2e422c9f", "name": "Xiangxiang Chu", "hidden": false}], "publishedAt": "2026-05-21T00:00:00.000Z", "submittedOnDailyAt": "2026-05-22T00:00:00.000Z", "title": "TransitLM: A Large-Scale Dataset and Benchmark for Map-Free Transit Route Generation", "submittedOnDailyBy": {"_id": "66d255e3947594430c723ff6", "avatarUrl": "/avatars/c56e4792332a01bf34085a75ee64916e.svg", "isPro": false, "fullname": "xiaochonglinghu", "user": "xiaochonglinghu", "type": "user", "name": "xiaochonglinghu"}, "summary": "Public transit route planning traditionally depends on structured map infrastructure and complex routing engines, and no existing dataset supports training models to bypass this dependency. We present TransitLM, a large-scale dataset of over 13 million transit route planning records from four Chinese cities covering 120,845 stations and 13,666 lines, released as a continual pre-training corpus and benchmark data for three evaluation tasks with complementary metrics. Experiments show that an LLM trained on TransitLM produces structurally valid routes at high accuracy and implicitly grounds arbitrary GPS coordinates to appropriate stations without any explicit mapping. These results demonstrate that transit route planning can be learned entirely from data, enabling end-to-end, map-free route generation directly from origin-destination information. The dataset and benchmark are available at https://huggingface.co/datasets/GD-ML/TransitLM, with evaluation code at https://github.com/HotTricker/TransitLM.", "upvotes": 162, "discussionId": "6a0fc10ea53a61ce2e422ca0", "githubRepo": "https://github.com/HotTricker/TransitLM", "githubRepoAddedBy": "user", "ai_summary": "TransitLM dataset enables end-to-end transit route planning using large language models trained on structured transit data, eliminating the need for traditional map-based approaches.", "ai_keywords": ["large language models", "transit route planning", "structured map infrastructure", "routing engines", "continual pre-training", "evaluation tasks", "GPS coordinates", "origin-destination information"], "githubStars": 107, "organization": {"_id": "67d11771890254196d3174e5", "name": "GD-ML", "fullname": "AMAP-ML", "avatar": "https://cdn-avatars.huggingface.co/v1/production/uploads/67d116c47be76de1a40873ca/s5ukAx9E36ZZIKvbpBRi4.png"}, "summary_zh": "<ul>\n    <li>TransitLM\u662f\u4e00\u4e2a\u5927\u89c4\u6a21\u7684\u6570\u636e\u96c6\uff0c\u5305\u62ec\u6765\u81ea\u56db\u4e2a\u4e2d\u56fd\u57ce\u5e02\u76841300\u591a\u4e07\u6761\u516c\u5171\u4ea4\u901a\u8def\u7ebf\u89c4\u5212\u8bb0\u5f55\u3002</li>\n    <li>\u8be5\u6570\u636e\u96c6\u6db5\u76d6\u4e86120,845\u4e2a\u7ad9\u70b9\u548c13,666\u6761\u7ebf\u8def\uff0c\u65e8\u5728\u66ff\u4ee3\u4f20\u7edf\u7684\u5730\u56fe\u57fa\u7840\u8bbe\u65bd\u548c\u590d\u6742\u8def\u7531\u5f15\u64ce\u3002</li>\n    <li>\u5b9e\u9a8c\u8868\u660e\uff0c\u57fa\u4e8eTransitLM\u8bad\u7ec3\u7684\u5927\u578b\u8bed\u8a00\u6a21\u578b\u53ef\u4ee5\u63d0\u4f9b\u9ad8\u51c6\u786e\u7387\u7684\u6709\u6548\u8def\u7ebf\u89c4\u5212\u3002</li>\n    <li>\u8be5\u6a21\u578b\u53ef\u4ee5\u6839\u636e\u539f\u70b9\u548c\u76ee\u7684\u5730\u4fe1\u606f\u751f\u6210\u8def\u7ebf\uff0c\u800c\u65e0\u9700\u4f9d\u8d56\u4efb\u4f55\u660e\u786e\u7684\u5730\u56fe\u3002</li>\n    <li>\u6570\u636e\u96c6\u548c\u57fa\u51c6\u6d4b\u8bd5\u53ef\u5728\u6307\u5b9a\u7f51\u5740\u83b7\u53d6\uff0c\u4e3a\u7814\u7a76\u548c\u5f00\u53d1\u63d0\u4f9b\u652f\u6301\u3002</li>\n</ul>", "summary_simple": "<ul>\n    <li>TransitLM is a new dataset with over 13 million records for planning public transit routes in four Chinese cities.</li>\n    <li>It includes data from 120,845 stations and 13,666 transit lines.</li>\n    <li>The dataset allows for training models to generate transit routes without needing traditional maps.</li>\n    <li>Experiments show that a language model trained on this dataset can create accurate routes and link GPS coordinates to the right stations.</li>\n    <li>The dataset and related code are available online for use and evaluation.</li>\n</ul>"}, "publishedAt": "2026-05-20T20:00:00.000Z", "title": "TransitLM: A Large-Scale Dataset and Benchmark for Map-Free Transit Route Generation", "summary": "Public transit route planning traditionally depends on structured map infrastructure and complex routing engines, and no existing dataset supports training models to bypass this dependency. We present TransitLM, a large-scale dataset of over 13 million transit route planning records from four Chinese cities covering 120,845 stations and 13,666 lines, released as a continual pre-training corpus and benchmark data for three evaluation tasks with complementary metrics. Experiments show that an LLM trained on TransitLM produces structurally valid routes at high accuracy and implicitly grounds arbitrary GPS coordinates to appropriate stations without any explicit mapping. These results demonstrate that transit route planning can be learned entirely from data, enabling end-to-end, map-free route generation directly from origin-destination information. The dataset and benchmark are available at https://huggingface.co/datasets/GD-ML/TransitLM, with evaluation code at https://github.com/HotTricker/TransitLM.", "thumbnail": "https://cdn-thumbnails.huggingface.co/social-thumbnails/papers/2605.22355.png", "numComments": 2, "submittedBy": {"_id": "66d255e3947594430c723ff6", "avatarUrl": "/avatars/c56e4792332a01bf34085a75ee64916e.svg", "fullname": "xiaochonglinghu", "name": "xiaochonglinghu", "type": "user", "isPro": false, "isHf": false, "isHfAdmin": false, "isMod": false, "followerCount": 9, "isUserFollowing": false}, "organization": {"_id": "67d11771890254196d3174e5", "name": "GD-ML", "fullname": "AMAP-ML", "avatar": "https://cdn-avatars.huggingface.co/v1/production/uploads/67d116c47be76de1a40873ca/s5ukAx9E36ZZIKvbpBRi4.png"}, "isAuthorParticipating": false}, {"paper": {"id": "2605.22109", "authors": [{"_id": "6a0fb91ea53a61ce2e422c1c", "name": "Caixin Kang", "hidden": false}, {"_id": "6a0fb91ea53a61ce2e422c1d", "name": "Tianyu Yan", "hidden": false}, {"_id": "6a0fb91ea53a61ce2e422c1e", "name": "Sitong Gong", "hidden": false}, {"_id": "6a0fb91ea53a61ce2e422c1f", "name": "Mingfang Zhang", "hidden": false}, {"_id": "6a0fb91ea53a61ce2e422c20", "name": "Liangyang Ouyang", "hidden": false}, {"_id": "6a0fb91ea53a61ce2e422c21", "name": "Ruicong Liu", "hidden": false}, {"_id": "6a0fb91ea53a61ce2e422c22", "name": "Bo Zheng", "hidden": false}, {"_id": "6a0fb91ea53a61ce2e422c23", "name": "Huchuan Lu", "hidden": false}, {"_id": "6a0fb91ea53a61ce2e422c24", "name": "Kaipeng Zhang", "hidden": false}, {"_id": "6a0fb91ea53a61ce2e422c25", "name": "Yoichi Sato", "hidden": false}, {"_id": "6a0fb91ea53a61ce2e422c26", "name": "Yifei Huang", "hidden": false}], "publishedAt": "2026-05-21T00:00:00.000Z", "submittedOnDailyAt": "2026-05-22T00:00:00.000Z", "title": "Perception or Prejudice: Can MLLMs Go Beyond First Impressions of Personality?", "submittedOnDailyBy": {"_id": "63a286c7f30c4642278ed11a", "avatarUrl": "/avatars/974fe4f3023791e97228c53330e9b4f3.svg", "isPro": false, "fullname": "Tim Kang", "user": "Ukpkmkkk", "type": "user", "name": "Ukpkmkkk"}, "summary": "Multimodal Large Language Models (MLLMs) are increasingly deployed in human-facing roles where personality perception is critical, yet existing benchmarks evaluate this capability solely on numerical Big Five score prediction, leaving open whether models truly perceive personality through behavioral understanding or merely prejudge through superficial pattern matching. We address this gap with three contributions. (i) A new task: we formalize Grounded Personality Reasoning (GPR), which requires MLLMs to anchor each Big Five rating in observable evidence through a chain of rating, reasoning, and grounding. (ii) A new dataset: we release MM-OCEAN (1,104 videos, 5,320 MCQs), produced by a multi-agent pipeline with human verification, with timestamped behavioral observations, evidence-grounded trait analyses, and seven categories of cue-grounding MCQs. (iii) Benchmark and analysis: we design a three-tier evaluation (rating, reasoning, grounding) plus four sample-level failure-mode metrics: Prejudice Rate (PR), Confabulation Rate (CR), Integration-failure Rate (IR), and Holistic-grounding Rate (HR), and benchmark 27 MLLMs (13 closed, 14 open). The analysis uncovers a striking Prejudice Gap: across the field, 51% of correct ratings are not grounded in retrieved cues, and the Holistic-Grounding Rate spans only 0-33.5%. These findings expose a disconnect between getting the right score and reasoning for the right reason, charting a roadmap for grounded social cognition in MLLMs.", "upvotes": 151, "discussionId": "6a0fb91fa53a61ce2e422c27", "githubRepo": "https://github.com/kkkcx/MM-OCEAN", "githubRepoAddedBy": "user", "ai_summary": "Researchers introduce a new task and dataset for evaluating personality reasoning in multimodal language models, revealing significant gaps between accurate predictions and grounded reasoning processes.", "ai_keywords": ["Multimodal Large Language Models", "Big Five score prediction", "Grounded Personality Reasoning", "MM-OCEAN dataset", "chain of rating", "reasoning", "and grounding", "multi-agent pipeline", "behavioral observations", "evidence-grounded trait analyses", "cue-grounding MCQs", "three-tier evaluation", "Prejudice Rate", "Confabulation Rate", "Integration-failure Rate", "Holistic-grounding Rate"], "githubStars": 5, "organization": {"_id": "6a0fbe68162dc5d32a0057a0", "name": "utokyo-ai", "fullname": "The University of Tokyo", "avatar": "https://cdn-avatars.huggingface.co/v1/production/uploads/63a286c7f30c4642278ed11a/jNLYa73JGG4k3ywpoD_9k.png"}, "summary_zh": "<ul>\n    <li>\u591a\u6a21\u6001\u5927\u8bed\u8a00\u6a21\u578b\uff08MLLMs\uff09\u5728\u9700\u8981\u7406\u89e3\u4e2a\u6027\u7684\u91cd\u8981\u89d2\u8272\u4e2d\u8d8a\u6765\u8d8a\u591a\u5730\u88ab\u5e94\u7528\u3002</li>\n    <li>\u63d0\u51fa\u4e86\u4e00\u79cd\u65b0\u4efb\u52a1\uff1a\u57fa\u4e8e\u53ef\u89c2\u5bdf\u8bc1\u636e\u5bf9\u4e94\u5927\u6027\u683c\u7279\u5f81\u8fdb\u884c\u63a8\u7406\uff08GPR\uff09\u3002</li>\n    <li>\u53d1\u5e03\u4e86\u4e00\u4e2a\u65b0\u6570\u636e\u96c6MM-OCEAN\uff0c\u5305\u62ec1104\u4e2a\u89c6\u9891\u548c5320\u4e2a\u591a\u9879\u9009\u62e9\u9898\uff0c\u6db5\u76d6\u884c\u4e3a\u89c2\u5bdf\u548c\u4e2a\u6027\u5206\u6790\u3002</li>\n    <li>\u8bbe\u8ba1\u4e86\u4e09\u5c42\u6b21\u7684\u8bc4\u4f30\u6807\u51c6\uff0c\u5e76\u5206\u6790\u4e8627\u4e2aMLLMs\u7684\u8868\u73b0\uff0c\u53d1\u73b0\u4e86\u660e\u663e\u7684\u504f\u89c1\u5dee\u8ddd\u3002</li>\n    <li>\u7ed3\u679c\u663e\u793a\uff0c\u867d\u7136\u8bc4\u5206\u6b63\u786e\uff0c\u4f46\u7f3a\u4e4f\u57fa\u4e8e\u8bc1\u636e\u7684\u63a8\u7406\uff0c\u63d0\u793aMLLMs\u5728\u793e\u4f1a\u8ba4\u77e5\u65b9\u9762\u7684\u4e0d\u8db3\u3002</li>\n</ul>", "summary_simple": "<ul>\n    <li>Multimodal Large Language Models (MLLMs) are used in roles where understanding personality is important, but current tests only measure their ability to predict personality scores.</li>\n    <li>The authors introduce a new task called Grounded Personality Reasoning (GPR) that requires MLLMs to support personality ratings with clear evidence.</li>\n    <li>They created a new dataset named MM-OCEAN, which includes over 1,100 videos and multiple-choice questions, with detailed behavioral observations and analyses.</li>\n    <li>The study includes a three-part evaluation system and various metrics to assess how well MLLMs understand personality, revealing a significant gap in their grounding of personality ratings.</li>\n    <li>Findings show that many correct ratings do not rely on actual behavioral cues, highlighting a need for better reasoning in MLLMs' social understanding.</li>\n</ul>"}, "publishedAt": "2026-05-20T20:00:00.000Z", "title": "Perception or Prejudice: Can MLLMs Go Beyond First Impressions of Personality?", "summary": "Multimodal Large Language Models (MLLMs) are increasingly deployed in human-facing roles where personality perception is critical, yet existing benchmarks evaluate this capability solely on numerical Big Five score prediction, leaving open whether models truly perceive personality through behavioral understanding or merely prejudge through superficial pattern matching. We address this gap with three contributions. (i) A new task: we formalize Grounded Personality Reasoning (GPR), which requires MLLMs to anchor each Big Five rating in observable evidence through a chain of rating, reasoning, and grounding. (ii) A new dataset: we release MM-OCEAN (1,104 videos, 5,320 MCQs), produced by a multi-agent pipeline with human verification, with timestamped behavioral observations, evidence-grounded trait analyses, and seven categories of cue-grounding MCQs. (iii) Benchmark and analysis: we design a three-tier evaluation (rating, reasoning, grounding) plus four sample-level failure-mode metrics: Prejudice Rate (PR), Confabulation Rate (CR), Integration-failure Rate (IR), and Holistic-grounding Rate (HR), and benchmark 27 MLLMs (13 closed, 14 open). The analysis uncovers a striking Prejudice Gap: across the field, 51% of correct ratings are not grounded in retrieved cues, and the Holistic-Grounding Rate spans only 0-33.5%. These findings expose a disconnect between getting the right score and reasoning for the right reason, charting a roadmap for grounded social cognition in MLLMs.", "thumbnail": "https://cdn-thumbnails.huggingface.co/social-thumbnails/papers/2605.22109.png", "numComments": 1, "submittedBy": {"_id": "63a286c7f30c4642278ed11a", "avatarUrl": "/avatars/974fe4f3023791e97228c53330e9b4f3.svg", "fullname": "Tim Kang", "name": "Ukpkmkkk", "type": "user", "isPro": false, "isHf": false, "isHfAdmin": false, "isMod": false, "isUserFollowing": false}, "organization": {"_id": "6a0fbe68162dc5d32a0057a0", "name": "utokyo-ai", "fullname": "The University of Tokyo", "avatar": "https://cdn-avatars.huggingface.co/v1/production/uploads/63a286c7f30c4642278ed11a/jNLYa73JGG4k3ywpoD_9k.png"}, "isAuthorParticipating": false}, {"paper": {"id": "2605.21467", "authors": [{"_id": "6a0e89f1164dbbc68a26c5de", "user": {"_id": "6523afa7389ef6864de004a1", "avatarUrl": "/avatars/cdf04857038a7c8abadd2e2306835ebe.svg", "isPro": false, "fullname": "KaiyiZhang", "user": "Cardlnal", "type": "user", "name": "Cardlnal"}, "name": "Kaiyi Zhang", "status": "claimed_verified", "statusLastChangedAt": "2026-05-21T19:21:52.826Z", "hidden": false}, {"_id": "6a0e89f1164dbbc68a26c5df", "name": "Wei Wu", "hidden": false}, {"_id": "6a0e89f1164dbbc68a26c5e0", "name": "Yankai Lin", "hidden": false}], "publishedAt": "2026-05-20T00:00:00.000Z", "submittedOnDailyAt": "2026-05-22T00:00:00.000Z", "title": "DelTA: Discriminative Token Credit Assignment for Reinforcement Learning from Verifiable Rewards", "submittedOnDailyBy": {"_id": "6523afa7389ef6864de004a1", "avatarUrl": "/avatars/cdf04857038a7c8abadd2e2306835ebe.svg", "isPro": false, "fullname": "KaiyiZhang", "user": "Cardlnal", "type": "user", "name": "Cardlnal"}, "summary": "Reinforcement learning from verifiable rewards (RLVR) has emerged as a central technique for improving the reasoning capabilities of large language models. Despite its effectiveness, how response-level rewards translate into token-level probability changes remains poorly understood. We introduce a discriminator view of RLVR updates, showing that the policy-gradient update direction implicitly acts as a linear discriminator over token-gradient vectors and thereby determines which token probabilities are increased or decreased during learning. Under standard sequence-level RLVR, this discriminator is constructed from positive- and negative-side centroids formed by advantage-weighted averaging of token-gradient vectors. However, such centroid construction can be dominated by shared high-frequency patterns, such as formatting tokens, diluting sparse yet discriminative directions that better distinguish high-reward responses from low-reward ones. To address this limitation, we propose DelTA, a discriminative token credit assignment method that estimates token coefficients to amplify side-specific token-gradient directions and downweight shared or weakly discriminative ones. These coefficients reweight a self-normalized RLVR surrogate, making the effective side-wise centroids more contrastive and thereby reshaping the RLVR update direction. On seven mathematical benchmarks, DelTA outperforms the strongest same-scale baselines by 3.26 and 2.62 average points on Qwen3-8B-Base and Qwen3-14B-Base, respectively. Additional results on code generation, a different backbone, and out-of-domain evaluations further demonstrate the generalization ability of DelTA.", "upvotes": 124, "discussionId": "6a0e89f2164dbbc68a26c5e1", "githubRepo": "https://github.com/RUCBM/DelTA", "githubRepoAddedBy": "user", "ai_summary": "Reinforcement learning from verifiable rewards is enhanced through a discriminative token credit assignment method that improves reward-based training by amplifying distinctive token-gradient directions and reducing noise from shared patterns.", "ai_keywords": ["reinforcement learning from verifiable rewards", "policy-gradient update", "token-gradient vectors", "advantage-weighted averaging", "discriminative token credit assignment", "self-normalized RLVR surrogate", "side-wise centroids"], "githubStars": 4, "summary_zh": "<ul>\n    <li>\u589e\u5f3a\u5b66\u4e60\u901a\u8fc7\u53ef\u9a8c\u8bc1\u5956\u52b1\uff08RLVR\uff09\u662f\u63d0\u9ad8\u5927\u8bed\u8a00\u6a21\u578b\u63a8\u7406\u80fd\u529b\u7684\u91cd\u8981\u6280\u672f\u3002</li>\n    <li>\u76ee\u524d\u5c1a\u4e0d\u6e05\u695a\u54cd\u5e94\u7ea7\u5956\u52b1\u5982\u4f55\u8f6c\u5316\u4e3a\u6807\u8bb0\u7ea7\u6982\u7387\u53d8\u5316\u3002</li>\n    <li>\u6211\u4eec\u63d0\u51fa\u4e86\u4e00\u79cd\u5224\u522b\u5668\u89c6\u89d2\u6765\u770b\u5f85RLVR\u66f4\u65b0\uff0c\u8868\u660e\u7b56\u7565\u68af\u5ea6\u66f4\u65b0\u65b9\u5411\u4f5c\u4e3a\u7ebf\u6027\u5224\u522b\u5668\u5f71\u54cd\u6807\u8bb0\u6982\u7387\u7684\u6539\u53d8\u3002</li>\n    <li>\u901a\u8fc7\u4f20\u7edf\u7684RLVR\uff0c\u6784\u5efa\u7684\u5224\u522b\u5668\u53ef\u80fd\u53d7\u5230\u9ad8\u9891\u6a21\u5f0f\u7684\u5f71\u54cd\uff0c\u5bfc\u81f4\u533a\u5206\u9ad8\u5956\u52b1\u548c\u4f4e\u5956\u52b1\u54cd\u5e94\u7684\u80fd\u529b\u964d\u4f4e\u3002</li>\n    <li>\u6211\u4eec\u63d0\u51fa\u4e86DelTA\u65b9\u6cd5\uff0c\u901a\u8fc7\u91cd\u65b0\u52a0\u6743\u6807\u8bb0\u68af\u5ea6\u65b9\u5411\uff0c\u6539\u5584\u4e86RLVR\u7684\u66f4\u65b0\u65b9\u5411\uff0c\u5e76\u5728\u591a\u4e2a\u57fa\u51c6\u6d4b\u8bd5\u4e2d\u663e\u793a\u51fa\u4f18\u8d8a\u6027\u80fd\u3002</li>\n</ul>", "summary_simple": "<ul>\n    <li>Reinforcement learning from verifiable rewards (RLVR) helps improve how large language models understand and reason.</li>\n    <li>The way rewards at the response level affect individual tokens is not well understood.</li>\n    <li>A new method called DelTA has been introduced to improve how token probabilities are adjusted during learning.</li>\n    <li>DelTA focuses on amplifying important token directions and reducing the influence of common patterns that don't help distinguish between good and bad responses.</li>\n    <li>Tests show that DelTA performs better than existing methods on various tasks, including math problems and code generation.</li>\n</ul>"}, "publishedAt": "2026-05-19T20:00:00.000Z", "title": "DelTA: Discriminative Token Credit Assignment for Reinforcement Learning from Verifiable Rewards", "summary": "Reinforcement learning from verifiable rewards (RLVR) has emerged as a central technique for improving the reasoning capabilities of large language models. Despite its effectiveness, how response-level rewards translate into token-level probability changes remains poorly understood. We introduce a discriminator view of RLVR updates, showing that the policy-gradient update direction implicitly acts as a linear discriminator over token-gradient vectors and thereby determines which token probabilities are increased or decreased during learning. Under standard sequence-level RLVR, this discriminator is constructed from positive- and negative-side centroids formed by advantage-weighted averaging of token-gradient vectors. However, such centroid construction can be dominated by shared high-frequency patterns, such as formatting tokens, diluting sparse yet discriminative directions that better distinguish high-reward responses from low-reward ones. To address this limitation, we propose DelTA, a discriminative token credit assignment method that estimates token coefficients to amplify side-specific token-gradient directions and downweight shared or weakly discriminative ones. These coefficients reweight a self-normalized RLVR surrogate, making the effective side-wise centroids more contrastive and thereby reshaping the RLVR update direction. On seven mathematical benchmarks, DelTA outperforms the strongest same-scale baselines by 3.26 and 2.62 average points on Qwen3-8B-Base and Qwen3-14B-Base, respectively. Additional results on code generation, a different backbone, and out-of-domain evaluations further demonstrate the generalization ability of DelTA.", "thumbnail": "https://cdn-thumbnails.huggingface.co/social-thumbnails/papers/2605.21467.png", "numComments": 1, "submittedBy": {"_id": "6523afa7389ef6864de004a1", "avatarUrl": "/avatars/cdf04857038a7c8abadd2e2306835ebe.svg", "fullname": "KaiyiZhang", "name": "Cardlnal", "type": "user", "isPro": false, "isHf": false, "isHfAdmin": false, "isMod": false, "followerCount": 4, "isUserFollowing": false}, "isAuthorParticipating": true}, {"paper": {"id": "2605.14678", "authors": [{"_id": "6a0e7c1a164dbbc68a26c56f", "user": {"_id": "689ec537196ab997b13dc977", "avatarUrl": "https://cdn-avatars.huggingface.co/v1/production/uploads/689ec537196ab997b13dc977/yXA_pd8ndjBIIg1Hx59QJ.png", "isPro": false, "fullname": "Haoran Zhang", "user": "zzzhr97", "type": "user", "name": "zzzhr97"}, "name": "Haoran Zhang", "status": "claimed_verified", "statusLastChangedAt": "2026-05-21T19:22:15.982Z", "hidden": false}, {"_id": "6a0e7c1a164dbbc68a26c570", "name": "Luxin Xu", "hidden": false}, {"_id": "6a0e7c1a164dbbc68a26c571", "name": "Zhilin Wang", "hidden": false}, {"_id": "6a0e7c1a164dbbc68a26c572", "name": "Runquan Gui", "hidden": false}, {"_id": "6a0e7c1a164dbbc68a26c573", "name": "Shunkai Zhang", "hidden": false}, {"_id": "6a0e7c1a164dbbc68a26c574", "name": "Haodi Lei", "hidden": false}, {"_id": "6a0e7c1a164dbbc68a26c575", "name": "Zihao He", "hidden": false}, {"_id": "6a0e7c1a164dbbc68a26c576", "name": "Bingsu He", "hidden": false}, {"_id": "6a0e7c1a164dbbc68a26c577", "name": "Chicheng Qin", "hidden": false}, {"_id": "6a0e7c1a164dbbc68a26c578", "name": "Tong Zhu", "hidden": false}, {"_id": "6a0e7c1a164dbbc68a26c579", "name": "Xiaoye Qu", "hidden": false}, {"_id": "6a0e7c1a164dbbc68a26c57a", "name": "Yang Yang", "hidden": false}, {"_id": "6a0e7c1a164dbbc68a26c57b", "name": "Yu Cheng", "hidden": false}, {"_id": "6a0e7c1a164dbbc68a26c57c", "name": "Yafu Li", "hidden": false}], "publishedAt": "2026-05-19T00:00:00.000Z", "submittedOnDailyAt": "2026-05-22T00:00:00.000Z", "title": "\u03c0-Bench: Evaluating Proactive Personal Assistant Agents in Long-Horizon Workflows", "submittedOnDailyBy": {"_id": "689ec537196ab997b13dc977", "avatarUrl": "https://cdn-avatars.huggingface.co/v1/production/uploads/689ec537196ab997b13dc977/yXA_pd8ndjBIIg1Hx59QJ.png", "isPro": false, "fullname": "Haoran Zhang", "user": "zzzhr97", "type": "user", "name": "zzzhr97"}, "summary": "The rise of personal assistant agents, e.g., OpenClaw, highlights the growing potential of large language models to support users across everyday life and work. A core challenge in these settings is proactive assistance, since users often begin with underspecified requests and leave important needs, constraints, or preferences unstated. However, existing benchmarks rarely evaluate whether agents can identify and act on such hidden intents before they are explicitly stated, especially in sustained multi-turn interactions where user needs emerge gradually. To address this gap, we introduce \u03c0-Bench, a benchmark for proactive assistance comprising 100 multi-turn tasks across 5 domain-specific user personas. By incorporating hidden user intents, inter-task dependencies, and cross-session continuity, \u03c0-Bench evaluates agents' ability to anticipate and address user needs over extended interactions, jointly measuring proactivity and task completion in long-horizon trajectories that better reflect real-world use. Experiments show (1) proactive assistance remains challenging, (2) a clear distinction between task completion and proactivity, and (3) the value of prior interaction for proactive intent resolution in later tasks.", "upvotes": 79, "discussionId": "6a0e7c1a164dbbc68a26c57d", "projectPage": "https://simplified-reasoning.github.io/Pi-Bench", "githubRepo": "https://github.com/Simplified-Reasoning/Pi-Bench", "githubRepoAddedBy": "user", "ai_summary": "Proactive assistance in personal agent systems requires identifying hidden user intents through sustained multi-turn interactions, which current benchmarks fail to adequately evaluate.", "ai_keywords": ["personal assistant agents", "large language models", "proactive assistance", "user intents", "multi-turn interactions", "domain-specific user personas", "long-horizon trajectories", "task completion", "proactivity"], "githubStars": 31, "organization": {"_id": "6a03a74a34f1cffc0570e62d", "name": "Simplified-Reasoning", "fullname": "Simplified Reasoning", "avatar": "https://cdn-avatars.huggingface.co/v1/production/uploads/62495cb96ee7ee6b646db130/S-AqbmitJFm2PxXyZrX7H.jpeg"}, "summary_zh": "<ul>\n    <li>\u4e2a\u4eba\u52a9\u7406\u4ee3\u7406\u7684\u5174\u8d77\u5c55\u793a\u4e86\u5927\u578b\u8bed\u8a00\u6a21\u578b\u5728\u65e5\u5e38\u751f\u6d3b\u548c\u5de5\u4f5c\u4e2d\u7684\u6f5c\u529b\u3002</li>\n    <li>\u73b0\u6709\u7684\u8bc4\u4f30\u6807\u51c6\u5f88\u5c11\u6d4b\u8bd5\u4ee3\u7406\u5728\u7528\u6237\u672a\u660e\u786e\u8868\u8fbe\u9700\u6c42\u65f6\u7684\u4e3b\u52a8\u5e2e\u52a9\u80fd\u529b\u3002</li>\n    <li>\u6211\u4eec\u63d0\u51fa\u4e86\u03c0-Bench\u57fa\u51c6\uff0c\u7528\u4e8e\u8bc4\u4f30\u4e3b\u52a8\u5e2e\u52a9\uff0c\u5305\u542b100\u4e2a\u591a\u8f6e\u5bf9\u8bdd\u4efb\u52a1\u3002</li>\n    <li>\u03c0-Bench\u8003\u8651\u4e86\u9690\u85cf\u7528\u6237\u610f\u56fe\u548c\u4efb\u52a1\u95f4\u7684\u4f9d\u8d56\u6027\uff0c\u8bc4\u4f30\u4ee3\u7406\u5728\u957f\u671f\u4e92\u52a8\u4e2d\u7684\u9884\u89c1\u80fd\u529b\u3002</li>\n    <li>\u5b9e\u9a8c\u8868\u660e\uff0c\u4e3b\u52a8\u5e2e\u52a9\u4ecd\u5177\u6311\u6218\u6027\uff0c\u5e76\u5f3a\u8c03\u4e86\u4efb\u52a1\u5b8c\u6210\u548c\u4e3b\u52a8\u6027\u4e4b\u95f4\u7684\u533a\u522b\u3002</li>\n</ul>", "summary_simple": "<ul>\n    <li>Personal assistant agents like OpenClaw show potential for helping users in daily life and work.</li>\n    <li>Many user requests are vague, making it hard for agents to understand hidden needs.</li>\n    <li>Current tests don't measure how well agents can identify these hidden needs in ongoing conversations.</li>\n    <li>\u03c0-Bench is a new benchmark with 100 tasks designed to evaluate proactive support in various user scenarios.</li>\n    <li>Experiments reveal that proactive assistance is difficult, and prior interactions help agents understand user needs better.</li>\n</ul>"}, "publishedAt": "2026-05-18T20:00:00.000Z", "title": "\u03c0-Bench: Evaluating Proactive Personal Assistant Agents in Long-Horizon Workflows", "summary": "The rise of personal assistant agents, e.g., OpenClaw, highlights the growing potential of large language models to support users across everyday life and work. A core challenge in these settings is proactive assistance, since users often begin with underspecified requests and leave important needs, constraints, or preferences unstated. However, existing benchmarks rarely evaluate whether agents can identify and act on such hidden intents before they are explicitly stated, especially in sustained multi-turn interactions where user needs emerge gradually. To address this gap, we introduce \u03c0-Bench, a benchmark for proactive assistance comprising 100 multi-turn tasks across 5 domain-specific user personas. By incorporating hidden user intents, inter-task dependencies, and cross-session continuity, \u03c0-Bench evaluates agents' ability to anticipate and address user needs over extended interactions, jointly measuring proactivity and task completion in long-horizon trajectories that better reflect real-world use. Experiments show (1) proactive assistance remains challenging, (2) a clear distinction between task completion and proactivity, and (3) the value of prior interaction for proactive intent resolution in later tasks.", "thumbnail": "https://cdn-thumbnails.huggingface.co/social-thumbnails/papers/2605.14678.png", "numComments": 2, "submittedBy": {"_id": "689ec537196ab997b13dc977", "avatarUrl": "https://cdn-avatars.huggingface.co/v1/production/uploads/689ec537196ab997b13dc977/yXA_pd8ndjBIIg1Hx59QJ.png", "fullname": "Haoran Zhang", "name": "zzzhr97", "type": "user", "isPro": false, "isHf": false, "isHfAdmin": false, "isMod": false, "followerCount": 3, "isUserFollowing": false}, "organization": {"_id": "6a03a74a34f1cffc0570e62d", "name": "Simplified-Reasoning", "fullname": "Simplified Reasoning", "avatar": "https://cdn-avatars.huggingface.co/v1/production/uploads/62495cb96ee7ee6b646db130/S-AqbmitJFm2PxXyZrX7H.jpeg"}, "isAuthorParticipating": true}, {"paper": {"id": "2605.16928", "authors": [{"_id": "6a0c536165eb30f20d962828", "user": {"_id": "6409f2eb9989bcb11721d127", "avatarUrl": "/avatars/b25cad4b548281942c717a3acda0d96d.svg", "isPro": false, "fullname": "Richard ZHou", "user": "zykRichard", "type": "user", "name": "zykRichard"}, "name": "Yanke Zhou", "status": "claimed_verified", "statusLastChangedAt": "2026-05-20T17:12:43.333Z", "hidden": false}, {"_id": "6a0c536165eb30f20d962829", "name": "Yiduo Li", "hidden": false}, {"_id": "6a0c536165eb30f20d96282a", "name": "Hanlin Tang", "hidden": false}, {"_id": "6a0c536165eb30f20d96282b", "user": {"_id": "671b4660a3fd72a462e97330", "avatarUrl": "https://cdn-avatars.huggingface.co/v1/production/uploads/671b4660a3fd72a462e97330/QbIZR5DqA6sGBvzw0vstV.jpeg", "isPro": false, "fullname": "Maohua Li", "user": "Met4physics", "type": "user", "name": "Met4physics"}, "name": "Maohua Li", "status": "claimed_verified", "statusLastChangedAt": "2026-05-20T17:12:40.557Z", "hidden": false}, {"_id": "6a0c536165eb30f20d96282c", "name": "Kan Liu", "hidden": false}, {"_id": "6a0c536165eb30f20d96282d", "name": "Lan Tao", "hidden": false}, {"_id": "6a0c536165eb30f20d96282e", "name": "Lin Qu", "hidden": false}, {"_id": "6a0c536165eb30f20d96282f", "name": "Yuan Yao", "hidden": false}, {"_id": "6a0c536165eb30f20d962830", "name": "Xiaoxing Ma", "hidden": false}], "publishedAt": "2026-05-16T00:00:00.000Z", "submittedOnDailyAt": "2026-05-22T00:00:00.000Z", "title": "Full Attention Strikes Back: Transferring Full Attention into Sparse within Hundred Training Steps", "submittedOnDailyBy": {"_id": "6409f2eb9989bcb11721d127", "avatarUrl": "/avatars/b25cad4b548281942c717a3acda0d96d.svg", "isPro": false, "fullname": "Richard ZHou", "user": "zykRichard", "type": "user", "name": "zykRichard"}, "summary": "Long-context inference in large language models is bottlenecked by the quadratic cost of full attention. Existing efficient alternatives often rely either on native sparse training or on heuristic token eviction, creating an undesirable trade-off among efficiency, training cost, and accuracy. In this work, we show that full-attention LLMs are already intrinsically sparse and can be transformed into highly sparse models with only minimal adaptation. Our approach is built on three observations: (1) only a small subset of attention heads truly requires full long-context processing; (2) long-range retrieval is governed primarily by a low-dimensional subspace, allowing relevant tokens to be retrieved efficiently with a 16-dimensional indexer; and (3) the useful token budget is strongly query-dependent, making dynamic top-p selection more suitable than fixed top-k sparsification. Based on these insights, we propose RTPurbo, which retains the full KV cache only for retrieval heads and introduces a lightweight token indexer for sparse attention. By exploiting the model's intrinsic sparsity, RTPurbo achieves sparsification with only a few hundred training steps. Experiments on long-context benchmarks and reasoning tasks show that RTPurbo preserves near-lossless accuracy while delivering substantial efficiency gains, including up to a 9.36times prefill speedup at 1M context and about a 2.01times decode speedup. These results suggest that strong sparse inference can be obtained from standard full-attention training without expensive native sparse pretraining.", "upvotes": 73, "discussionId": "6a0c536165eb30f20d962831", "ai_summary": "RTPurbo leverages intrinsic sparsity in full-attention LLMs to achieve efficient long-context inference with minimal training overhead, enabling significant speedups while maintaining near-lossless accuracy.", "ai_keywords": ["full attention", "long-context inference", "attention heads", "sparse attention", "KV cache", "token indexer", "dynamic top-p selection", "intrinsic sparsity", "RTPurbo", "prefill speedup", "decode speedup"], "organization": {"_id": "6948e7d0a2a90d1cca14cbbc", "name": "RTP-LLM", "fullname": "RTP-LLM", "avatar": "https://cdn-avatars.huggingface.co/v1/production/uploads/6426d1afbc4f1d51f5479914/lgUmPC4DXPxlhRBDnHybm.webp"}, "summary_zh": "<ul>\n    <li>\u957f\u6587\u672c\u63a8\u7406\u5728\u5927\u8bed\u8a00\u6a21\u578b\u4e2d\u53d7\u9650\u4e8e\u5168\u6ce8\u610f\u529b\u7684\u5e73\u65b9\u6210\u672c\u3002</li>\n    <li>\u73b0\u6709\u7684\u9ad8\u6548\u66ff\u4ee3\u65b9\u6848\u901a\u5e38\u5728\u6548\u7387\u3001\u8bad\u7ec3\u6210\u672c\u548c\u51c6\u786e\u6027\u4e4b\u95f4\u5b58\u5728\u6743\u8861\u3002</li>\n    <li>\u6211\u4eec\u53d1\u73b0\u5168\u6ce8\u610f\u529b\u6a21\u578b\u672c\u8eab\u5df2\u7ecf\u5177\u6709\u7a00\u758f\u6027\uff0c\u53ef\u4ee5\u901a\u8fc7\u6700\u5c0f\u9002\u5e94\u6027\u8f6c\u5316\u4e3a\u9ad8\u5ea6\u7a00\u758f\u6a21\u578b\u3002</li>\n    <li>\u6211\u4eec\u63d0\u51fa\u7684RTPurbo\u65b9\u6cd5\u5229\u7528\u6a21\u578b\u7684\u5185\u5728\u7a00\u758f\u6027\uff0c\u4ec5\u4fdd\u7559\u68c0\u7d22\u5934\u7684KV\u7f13\u5b58\uff0c\u5e76\u5f15\u5165\u8f7b\u91cf\u7ea7\u7684\u6807\u8bb0\u7d22\u5f15\u5668\u3002</li>\n    <li>\u5b9e\u9a8c\u7ed3\u679c\u8868\u660e\uff0cRTPurbo\u5728\u4fdd\u6301\u63a5\u8fd1\u65e0\u635f\u51c6\u786e\u6027\u7684\u540c\u65f6\uff0c\u5b9e\u73b0\u4e86\u663e\u8457\u7684\u6548\u7387\u63d0\u5347\uff0c\u6bd4\u5982\u57281M\u4e0a\u4e0b\u6587\u4e0b\u901f\u5ea6\u63d0\u9ad8\u4e869.36\u500d\u3002</li>\n</ul>", "summary_simple": "<ul>\n    <li>Large language models struggle with long-context inference due to high computational costs of full attention.</li>\n    <li>Current efficient methods either require complex training or involve sacrificing accuracy for speed.</li>\n    <li>This study shows that full-attention models can be transformed into efficient sparse models with slight adjustments.</li>\n    <li>The proposed method, RTPurbo, uses a lightweight indexer and only retains full attention for certain heads, improving efficiency.</li>\n    <li>RTPurbo maintains high accuracy while significantly speeding up processing, achieving up to 9.36 times faster prefill and 2.01 times faster decoding.</li>\n</ul>"}, "publishedAt": "2026-05-15T20:00:00.000Z", "title": "Full Attention Strikes Back: Transferring Full Attention into Sparse within Hundred Training Steps", "summary": "Long-context inference in large language models is bottlenecked by the quadratic cost of full attention. Existing efficient alternatives often rely either on native sparse training or on heuristic token eviction, creating an undesirable trade-off among efficiency, training cost, and accuracy. In this work, we show that full-attention LLMs are already intrinsically sparse and can be transformed into highly sparse models with only minimal adaptation. Our approach is built on three observations: (1) only a small subset of attention heads truly requires full long-context processing; (2) long-range retrieval is governed primarily by a low-dimensional subspace, allowing relevant tokens to be retrieved efficiently with a 16-dimensional indexer; and (3) the useful token budget is strongly query-dependent, making dynamic top-p selection more suitable than fixed top-k sparsification. Based on these insights, we propose RTPurbo, which retains the full KV cache only for retrieval heads and introduces a lightweight token indexer for sparse attention. By exploiting the model's intrinsic sparsity, RTPurbo achieves sparsification with only a few hundred training steps. Experiments on long-context benchmarks and reasoning tasks show that RTPurbo preserves near-lossless accuracy while delivering substantial efficiency gains, including up to a 9.36times prefill speedup at 1M context and about a 2.01times decode speedup. These results suggest that strong sparse inference can be obtained from standard full-attention training without expensive native sparse pretraining.", "thumbnail": "https://cdn-thumbnails.huggingface.co/social-thumbnails/papers/2605.16928.png", "numComments": 1, "submittedBy": {"_id": "6409f2eb9989bcb11721d127", "avatarUrl": "/avatars/b25cad4b548281942c717a3acda0d96d.svg", "fullname": "Richard ZHou", "name": "zykRichard", "type": "user", "isPro": false, "isHf": false, "isHfAdmin": false, "isMod": false, "followerCount": 1, "isUserFollowing": false}, "organization": {"_id": "6948e7d0a2a90d1cca14cbbc", "name": "RTP-LLM", "fullname": "RTP-LLM", "avatar": "https://cdn-avatars.huggingface.co/v1/production/uploads/6426d1afbc4f1d51f5479914/lgUmPC4DXPxlhRBDnHybm.webp"}, "isAuthorParticipating": true}, {"paper": {"id": "2605.21850", "authors": [{"_id": "6a0fb25da53a61ce2e422bd2", "user": {"_id": "670a3bc3ada59c956f18cc17", "avatarUrl": "/avatars/1a853deca3ec206f47aec2c6abe3a146.svg", "isPro": false, "fullname": "SII-sqs", "user": "groundhogLLM", "type": "user", "name": "groundhogLLM"}, "name": "Qisheng Su", "status": "claimed_verified", "statusLastChangedAt": "2026-05-22T16:09:09.451Z", "hidden": false}, {"_id": "6a0fb25da53a61ce2e422bd3", "name": "Zhen Fang", "hidden": false}, {"_id": "6a0fb25da53a61ce2e422bd4", "name": "Shiting Huang", "hidden": false}, {"_id": "6a0fb25da53a61ce2e422bd5", "user": {"_id": "665d652e0f35c005de892108", "avatarUrl": "https://cdn-avatars.huggingface.co/v1/production/uploads/665d652e0f35c005de892108/OGLbgZekX-3XTBkwS8k86.jpeg", "isPro": false, "fullname": "Yu Zeng", "user": "YuZeng260", "type": "user", "name": "YuZeng260"}, "name": "Yu Zeng", "status": "claimed_verified", "statusLastChangedAt": "2026-05-22T16:09:03.514Z", "hidden": false}, {"_id": "6a0fb25da53a61ce2e422bd6", "name": "Yiming Zhao", "hidden": false}, {"_id": "6a0fb25da53a61ce2e422bd7", "name": "Kou Shi", "hidden": false}, {"_id": "6a0fb25da53a61ce2e422bd8", "name": "Ziao Zhang", "hidden": false}, {"_id": "6a0fb25da53a61ce2e422bd9", "user": {"_id": "64b02ec0e5000ae8a572ced5", "avatarUrl": "https://cdn-avatars.huggingface.co/v1/production/uploads/64b02ec0e5000ae8a572ced5/6ifLntBU2ICQK7SW8WxKU.png", "isPro": false, "fullname": "Lin Chen", "user": "Lin-Chen", "type": "user", "name": "Lin-Chen"}, "name": "Lin Chen", "status": "claimed_verified", "statusLastChangedAt": "2026-05-22T16:09:05.234Z", "hidden": false}, {"_id": "6a0fb25da53a61ce2e422bda", "name": "Zehui Chen", "hidden": false}, {"_id": "6a0fb25da53a61ce2e422bdb", "name": "Lijun Wu", "hidden": false}, {"_id": "6a0fb25da53a61ce2e422bdc", "name": "Feng Zhao", "hidden": false}], "publishedAt": "2026-05-21T00:00:00.000Z", "submittedOnDailyAt": "2026-05-22T00:00:00.000Z", "title": "ACC: Compiling Agent Trajectories for Long-Context Training", "submittedOnDailyBy": {"_id": "670a3bc3ada59c956f18cc17", "avatarUrl": "/avatars/1a853deca3ec206f47aec2c6abe3a146.svg", "isPro": false, "fullname": "SII-sqs", "user": "groundhogLLM", "type": "user", "name": "groundhogLLM"}, "summary": "Recent development of agents has renewed demand for long-context reasoning capacity of LLMs. However, training LLMs for this capacity requires costly long-document curation or heuristic context synthesis. We observe that agents produce massive trajectories when solving problems, invoking tools and receiving environment observations across many turns. The evidence needed to answer the original question is thus scattered throughout these turns, requiring integration of distant context segments. Nevertheless, standard agent SFT masks tool responses and only trains turn-level tool selection, creating a supervision blind spot where these scattered signals go unused. We propose Agent Context Compilation (ACC), which converts trajectories from search, software engineering, and database querying agents into long-context QA pairs that combine the original question with tool responses and environment observations gathered across multiple turns, training the model to answer directly without tool use. This makes the dependencies between the question and the evidence explicit, enabling direct supervision of long-context reasoning over distant segments without additional annotation. ACC is a simple but effective approach that can be combined with any existing long-context extension or training method, providing scalable supervised fine-tuning data. We validate ACC on long-range dependency modeling tasks through MRCR and GraphWalks, challenging benchmarks requiring cross-turn coreference resolution and graph traversal over extended contexts. Training Qwen3-30B-A3B with ACC achieves 68.3 on MRCR (+18.1) and 77.5 on GraphWalks (+7.6), results comparable to Qwen3-235B-A22B, while preserving general capabilities on GPQA, MMLU-Pro, AIME, and IFEval. Further mechanism analysis reveals that the ACC-trained model exhibits task-adaptive attention restructuring and expert specialization.", "upvotes": 51, "discussionId": "6a0fb25da53a61ce2e422bdd", "ai_summary": "Agent Context Compilation (ACC) enhances long-context reasoning in LLMs by converting multi-turn agent trajectories into structured QA pairs, enabling direct supervision of distant context integration without additional annotation.", "ai_keywords": ["long-context reasoning", "agent SFT", "tool responses", "environment observations", "trajectory conversion", "long-range dependency modeling", "cross-turn coreference resolution", "graph traversal", "supervised fine-tuning", "attention restructuring", "expert specialization"], "organization": {"_id": "67ff908ff0f413c693b7cd0c", "name": "ustc-community", "fullname": "University of Science and Technology of China", "avatar": "https://cdn-avatars.huggingface.co/v1/production/uploads/660c2d134ba2fcc848b03e21/j_f3uYYIFPH_4WJH9fKel.png"}, "summary_zh": "<ul>\n    <li>\u6700\u8fd1\uff0c\u667a\u80fd\u4f53\u7684\u53d1\u5c55\u589e\u52a0\u4e86\u5bf9\u5927\u578b\u8bed\u8a00\u6a21\u578b\uff08LLMs\uff09\u957f\u4e0a\u4e0b\u6587\u63a8\u7406\u80fd\u529b\u7684\u9700\u6c42\u3002</li>\n    <li>\u8bad\u7ec3LLMs\u7684\u8fd9\u79cd\u80fd\u529b\u9700\u8981\u6602\u8d35\u7684\u957f\u6587\u6863\u6574\u7406\u6216\u542f\u53d1\u5f0f\u4e0a\u4e0b\u6587\u5408\u6210\u3002</li>\n    <li>\u667a\u80fd\u4f53\u5728\u89e3\u51b3\u95ee\u9898\u65f6\u4ea7\u751f\u5927\u91cf\u7684\u8f68\u8ff9\uff0c\u8fd9\u4e9b\u8f68\u8ff9\u4e2d\u5305\u542b\u4e86\u5206\u6563\u7684\u8bc1\u636e\uff0c\u9700\u8981\u6574\u5408\u624d\u80fd\u56de\u7b54\u539f\u59cb\u95ee\u9898\u3002</li>\n    <li>\u6211\u4eec\u63d0\u51fa\u4e86\u201c\u667a\u80fd\u4f53\u4e0a\u4e0b\u6587\u7f16\u8bd1\u201d\uff08ACC\uff09\uff0c\u5c06\u8fd9\u4e9b\u8f68\u8ff9\u8f6c\u6362\u4e3a\u957f\u4e0a\u4e0b\u6587\u95ee\u7b54\u5bf9\uff0c\u8bad\u7ec3\u6a21\u578b\u76f4\u63a5\u56de\u7b54\u95ee\u9898\uff0c\u800c\u65e0\u9700\u4f7f\u7528\u5de5\u5177\u3002</li>\n    <li>ACC\u5728\u957f\u8303\u56f4\u4f9d\u8d56\u5efa\u6a21\u4efb\u52a1\u4e2d\u8868\u73b0\u826f\u597d\uff0c\u7ed3\u679c\u4e0e\u66f4\u5927\u6a21\u578b\u76f8\u5f53\uff0c\u540c\u65f6\u4fdd\u6301\u4e86\u5728\u5176\u4ed6\u4efb\u52a1\u4e0a\u7684\u80fd\u529b\u3002</li>\n</ul>", "summary_simple": "<ul>\n    <li>There is a growing need for long-context reasoning in large language models (LLMs) due to the development of agents that solve problems in multiple steps.</li>\n    <li>Training LLMs for long-context reasoning is expensive and usually requires complex document preparation.</li>\n    <li>Agents generate extensive data (trajectories) when they work on problems, but traditional training methods overlook important information from these processes.</li>\n    <li>The proposed method, Agent Context Compilation (ACC), creates training data from the agents' problem-solving steps, linking questions to relevant tool responses and observations.</li>\n    <li>ACC improves LLM performance on tasks requiring understanding across long contexts and allows for effective training without needing extra annotations.</li>\n</ul>"}, "publishedAt": "2026-05-20T20:00:00.000Z", "title": "ACC: Compiling Agent Trajectories for Long-Context Training", "summary": "Recent development of agents has renewed demand for long-context reasoning capacity of LLMs. However, training LLMs for this capacity requires costly long-document curation or heuristic context synthesis. We observe that agents produce massive trajectories when solving problems, invoking tools and receiving environment observations across many turns. The evidence needed to answer the original question is thus scattered throughout these turns, requiring integration of distant context segments. Nevertheless, standard agent SFT masks tool responses and only trains turn-level tool selection, creating a supervision blind spot where these scattered signals go unused. We propose Agent Context Compilation (ACC), which converts trajectories from search, software engineering, and database querying agents into long-context QA pairs that combine the original question with tool responses and environment observations gathered across multiple turns, training the model to answer directly without tool use. This makes the dependencies between the question and the evidence explicit, enabling direct supervision of long-context reasoning over distant segments without additional annotation. ACC is a simple but effective approach that can be combined with any existing long-context extension or training method, providing scalable supervised fine-tuning data. We validate ACC on long-range dependency modeling tasks through MRCR and GraphWalks, challenging benchmarks requiring cross-turn coreference resolution and graph traversal over extended contexts. Training Qwen3-30B-A3B with ACC achieves 68.3 on MRCR (+18.1) and 77.5 on GraphWalks (+7.6), results comparable to Qwen3-235B-A22B, while preserving general capabilities on GPQA, MMLU-Pro, AIME, and IFEval. Further mechanism analysis reveals that the ACC-trained model exhibits task-adaptive attention restructuring and expert specialization.", "thumbnail": "https://cdn-thumbnails.huggingface.co/social-thumbnails/papers/2605.21850.png", "numComments": 1, "submittedBy": {"_id": "670a3bc3ada59c956f18cc17", "avatarUrl": "/avatars/1a853deca3ec206f47aec2c6abe3a146.svg", "fullname": "SII-sqs", "name": "groundhogLLM", "type": "user", "isPro": false, "isHf": false, "isHfAdmin": false, "isMod": false, "followerCount": 2, "isUserFollowing": false}, "organization": {"_id": "67ff908ff0f413c693b7cd0c", "name": "ustc-community", "fullname": "University of Science and Technology of China", "avatar": "https://cdn-avatars.huggingface.co/v1/production/uploads/660c2d134ba2fcc848b03e21/j_f3uYYIFPH_4WJH9fKel.png"}, "isAuthorParticipating": true}, {"paper": {"id": "2605.21572", "authors": [{"_id": "6a0fd47da53a61ce2e422d2d", "name": "Ziang Cao", "hidden": false}, {"_id": "6a0fd47da53a61ce2e422d2e", "name": "Yinghao Liu", "hidden": false}, {"_id": "6a0fd47da53a61ce2e422d2f", "name": "Haitian Li", "hidden": false}, {"_id": "6a0fd47da53a61ce2e422d30", "name": "Runmao Yao", "hidden": false}, {"_id": "6a0fd47da53a61ce2e422d31", "name": "Fangzhou Hong", "hidden": false}, {"_id": "6a0fd47da53a61ce2e422d32", "name": "Zhaoxi Chen", "hidden": false}, {"_id": "6a0fd47da53a61ce2e422d33", "name": "Liang Pan", "hidden": false}, {"_id": "6a0fd47da53a61ce2e422d34", "name": "Ziwei Liu", "hidden": false}], "mediaUrls": ["https://cdn-uploads.huggingface.co/production/uploads/60efe7fa0d920bc7805cada5/DHGaihMSL3qOlc14orpmf.mp4"], "publishedAt": "2026-05-20T00:00:00.000Z", "submittedOnDailyAt": "2026-05-22T00:00:00.000Z", "title": "PhysX-Omni: Unified Simulation-Ready Physical 3D Generation for Rigid, Deformable, and Articulated Objects", "submittedOnDailyBy": {"_id": "60efe7fa0d920bc7805cada5", "avatarUrl": "https://cdn-avatars.huggingface.co/v1/production/uploads/60efe7fa0d920bc7805cada5/2LBrJBjSCOP5ilZIpWLHl.png", "isPro": false, "fullname": "Ziqi Huang", "user": "Ziqi", "type": "user", "name": "Ziqi"}, "summary": "Simulation-ready physical 3D assets have emerged as a promising direction owing to their broad applicability in downstream tasks. However, most existing 3D generation methods either neglect physical properties or are limited to a single asset category, e.g., rigid, deformable, or articulated objects. To address these limitations, we introduce PhysX-Omni, a unified framework for simulation-ready physical 3D generation across diverse asset types. Specifically, we develop a novel and efficient geometry representation tailored for Vision-Language Models, which directly encodes high-resolution 3D structures without compression, significantly improving generation performance. In addition, we construct the first general simulation-ready 3D dataset, PhysXVerse, covering diverse indoor and outdoor categories. Furthermore, to comprehensively and flexibly evaluate both generative and understanding capabilities in the wild, we propose PhysX-Bench, which encompasses six key attributes: geometry, absolute scale, material, affordance, kinematics, and function description. Extensive experiments with conventional metrics and PhysX-Bench show that PhysX-Omni performs strongly in both generation and understanding. Moreover, additional studies further validate the potential of PhysX-Omni for applications in simulation-ready scene generation and robotic policy learning. We believe PhysX-Omni can significantly advance a wide range of downstream applications, particularly in embodied AI and physics-based simulation.", "upvotes": 42, "discussionId": "6a0fd47da53a61ce2e422d35", "projectPage": "https://physx-omni.github.io", "githubRepo": "https://github.com/physx-omni/PhysX-Omni", "githubRepoAddedBy": "user", "ai_summary": "PhysX-Omni presents a unified framework for generating simulation-ready 3D assets with physical properties across multiple categories using a novel geometry representation and evaluation benchmarks.", "ai_keywords": ["3D generation", "Vision-Language Models", "geometry representation", "PhysXVerse dataset", "PhysX-Bench", "embodied AI", "physics-based simulation"], "githubStars": 58, "summary_zh": "<ul>\n    <li>\u63a8\u51fa\u4e86\u4e00\u4e2a\u540d\u4e3aPhysX-Omni\u7684\u7edf\u4e00\u6846\u67b6\uff0c\u7528\u4e8e\u751f\u6210\u7b26\u5408\u7269\u7406\u7279\u6027\u76843D\u8d44\u4ea7\u3002</li>\n    <li>\u5f00\u53d1\u4e86\u4e00\u79cd\u65b0\u9896\u7684\u51e0\u4f55\u8868\u793a\uff0c\u80fd\u591f\u76f4\u63a5\u7f16\u7801\u9ad8\u5206\u8fa8\u7387\u76843D\u7ed3\u6784\uff0c\u63d0\u5347\u751f\u6210\u6027\u80fd\u3002</li>\n    <li>\u5efa\u7acb\u4e86\u7b2c\u4e00\u4e2a\u901a\u7528\u7684\u6a21\u62df\u51c6\u59073D\u6570\u636e\u96c6PhysXVerse\uff0c\u6db5\u76d6\u5404\u79cd\u5ba4\u5185\u548c\u5ba4\u5916\u7c7b\u522b\u3002</li>\n    <li>\u63d0\u51fa\u4e86PhysX-Bench\u6765\u8bc4\u4f30\u751f\u6210\u548c\u7406\u89e3\u80fd\u529b\uff0c\u5305\u542b\u51e0\u4f55\u3001\u7edd\u5bf9\u5c3a\u5ea6\u3001\u6750\u6599\u7b49\u516d\u4e2a\u5173\u952e\u5c5e\u6027\u3002</li>\n    <li>PhysX-Omni\u5728\u751f\u6210\u548c\u7406\u89e3\u65b9\u9762\u8868\u73b0\u51fa\u8272\uff0c\u5e76\u6709\u6f5c\u529b\u63a8\u52a8\u673a\u5668\u4eba\u653f\u7b56\u5b66\u4e60\u548c\u7269\u7406\u57fa\u7840\u6a21\u62df\u7b49\u5e94\u7528\u3002</li>\n</ul>", "summary_simple": "<ul>\n    <li>PhysX-Omni is a new framework for creating 3D models that are ready for simulations, covering various types of objects.</li>\n    <li>It uses a special way to represent 3D shapes, making it easier for AI models to understand and generate high-quality 3D structures.</li>\n    <li>The framework includes a new dataset called PhysXVerse, featuring a variety of indoor and outdoor 3D assets.</li>\n    <li>PhysX-Bench is introduced to evaluate the generated 3D models based on different characteristics like shape, size, and material.</li>\n    <li>Tests show that PhysX-Omni is effective in generating and understanding 3D models, with potential uses in AI and simulation technologies.</li>\n</ul>"}, "publishedAt": "2026-05-19T20:00:00.000Z", "title": "PhysX-Omni: Unified Simulation-Ready Physical 3D Generation for Rigid, Deformable, and Articulated Objects", "summary": "Simulation-ready physical 3D assets have emerged as a promising direction owing to their broad applicability in downstream tasks. However, most existing 3D generation methods either neglect physical properties or are limited to a single asset category, e.g., rigid, deformable, or articulated objects. To address these limitations, we introduce PhysX-Omni, a unified framework for simulation-ready physical 3D generation across diverse asset types. Specifically, we develop a novel and efficient geometry representation tailored for Vision-Language Models, which directly encodes high-resolution 3D structures without compression, significantly improving generation performance. In addition, we construct the first general simulation-ready 3D dataset, PhysXVerse, covering diverse indoor and outdoor categories. Furthermore, to comprehensively and flexibly evaluate both generative and understanding capabilities in the wild, we propose PhysX-Bench, which encompasses six key attributes: geometry, absolute scale, material, affordance, kinematics, and function description. Extensive experiments with conventional metrics and PhysX-Bench show that PhysX-Omni performs strongly in both generation and understanding. Moreover, additional studies further validate the potential of PhysX-Omni for applications in simulation-ready scene generation and robotic policy learning. We believe PhysX-Omni can significantly advance a wide range of downstream applications, particularly in embodied AI and physics-based simulation.", "mediaUrls": ["https://cdn-uploads.huggingface.co/production/uploads/60efe7fa0d920bc7805cada5/DHGaihMSL3qOlc14orpmf.mp4"], "thumbnail": "https://cdn-thumbnails.huggingface.co/social-thumbnails/papers/2605.21572.png", "numComments": 1, "submittedBy": {"_id": "60efe7fa0d920bc7805cada5", "avatarUrl": "https://cdn-avatars.huggingface.co/v1/production/uploads/60efe7fa0d920bc7805cada5/2LBrJBjSCOP5ilZIpWLHl.png", "fullname": "Ziqi Huang", "name": "Ziqi", "type": "user", "isPro": false, "isHf": false, "isHfAdmin": false, "isMod": false, "followerCount": 20, "isUserFollowing": false}, "isAuthorParticipating": false}, {"paper": {"id": "2605.22012", "authors": [{"_id": "6a0fe203a53a61ce2e422db3", "user": {"_id": "674e77fa59a127e4eacf5dba", "avatarUrl": "https://cdn-avatars.huggingface.co/v1/production/uploads/674e77fa59a127e4eacf5dba/W7qr94Buvvaio8zhKrEha.jpeg", "isPro": false, "fullname": "Yifan Dai", "user": "Moonwines", "type": "user", "name": "Moonwines"}, "name": "Yifan Dai", "status": "claimed_verified", "statusLastChangedAt": "2026-05-22T16:07:32.571Z", "hidden": false}, {"_id": "6a0fe203a53a61ce2e422db4", "name": "Zhenhua Wu", "hidden": false}, {"_id": "6a0fe203a53a61ce2e422db5", "name": "Bohan Zeng", "hidden": false}, {"_id": "6a0fe203a53a61ce2e422db6", "name": "Daili Hua", "hidden": false}, {"_id": "6a0fe203a53a61ce2e422db7", "name": "Jialing Liu", "hidden": false}, {"_id": "6a0fe203a53a61ce2e422db8", "name": "Bozhou Li", "hidden": false}, {"_id": "6a0fe203a53a61ce2e422db9", "user": {"_id": "65e71ef39cf349af2940b317", "avatarUrl": "/avatars/fc1cd8d3510946fc947d67b16b51834b.svg", "isPro": false, "fullname": "Yuran Wang", "user": "Ryann829", "type": "user", "name": "Ryann829"}, "name": "Yuran Wang", "status": "claimed_verified", "statusLastChangedAt": "2026-05-22T16:07:39.868Z", "hidden": false}, {"_id": "6a0fe203a53a61ce2e422dba", "name": "Chengzhuo Tong", "hidden": false}, {"_id": "6a0fe203a53a61ce2e422dbb", "name": "Hao Liang", "hidden": false}, {"_id": "6a0fe203a53a61ce2e422dbc", "name": "Xiaochen Ma", "hidden": false}, {"_id": "6a0fe203a53a61ce2e422dbd", "name": "Junbo Niu", "hidden": false}, {"_id": "6a0fe203a53a61ce2e422dbe", "name": "Tianyu Guo", "hidden": false}, {"_id": "6a0fe203a53a61ce2e422dbf", "user": {"_id": "673c7319d11b1c2e246ead9c", "avatarUrl": "https://cdn-avatars.huggingface.co/v1/production/uploads/673c7319d11b1c2e246ead9c/IjFIO--N7Hm_BOEafhEQv.jpeg", "isPro": false, "fullname": "Yang Shi", "user": "DogNeverSleep", "type": "user", "name": "DogNeverSleep"}, "name": "Yang Shi", "status": "claimed_verified", "statusLastChangedAt": "2026-05-22T16:07:36.713Z", "hidden": false}, {"_id": "6a0fe203a53a61ce2e422dc0", "name": "Yue Ding", "hidden": false}, {"_id": "6a0fe203a53a61ce2e422dc1", "name": "Yiyan Ji", "hidden": false}, {"_id": "6a0fe203a53a61ce2e422dc2", "name": "Bingyin Mei", "hidden": false}, {"_id": "6a0fe203a53a61ce2e422dc3", "name": "Yushuo Guan", "hidden": false}, {"_id": "6a0fe203a53a61ce2e422dc4", "name": "Yuanxing Zhang", "hidden": false}, {"_id": "6a0fe203a53a61ce2e422dc5", "name": "Pengfei Wan", "hidden": false}, {"_id": "6a0fe203a53a61ce2e422dc6", "name": "Fangcheng Fu", "hidden": false}, {"_id": "6a0fe203a53a61ce2e422dc7", "name": "Wentao Zhang", "hidden": false}], "publishedAt": "2026-05-21T00:00:00.000Z", "submittedOnDailyAt": "2026-05-22T00:00:00.000Z", "title": "LatentOmni: Rethinking Omni-Modal Understanding via Unified Audio-Visual Latent Reasoning", "submittedOnDailyBy": {"_id": "6671214c92412fd4640714eb", "avatarUrl": "/avatars/48fa84e7bc3bb92ad0192aa26b32de10.svg", "isPro": false, "fullname": "bohan zeng", "user": "zbhpku", "type": "user", "name": "zbhpku"}, "summary": "Joint audio-visual reasoning is essential for omnimodal understanding, yet current multimodal large language models (MLLMs) still struggle when reasoning requires fine-grained evidence from both modalities. A central limitation is that explicit text-based chain-of-thought (CoT) compresses continuous audio-visual signals into discrete tokens, weakening temporal grounding and shifting intermediate reasoning toward language priors. We argue that a unified latent space is a better medium for such reasoning because it preserves dense sensory information while remaining compatible with autoregressive generation. Based on this insight, we propose LatentOmni, a cross-modal reasoning framework that interleaves textual reasoning with audio-visual latent states. LatentOmni introduces feature-level supervision to align latent reasoning states with task-relevant sensory features and uses Omni-Sync Position Embedding (OSPE) to maintain temporal consistency between latent audio and visual states. We further construct LatentOmni-Instruct-35K, a dataset of audio-visual interleaved reasoning trajectories for supervising latent-space reasoning. Comprehensive evaluation across multiple audio-visual reasoning benchmarks demonstrates that LatentOmni achieves the best performance among the evaluated open-source models and consistently outperforms the Explicit Text CoT baseline, supporting latent-space joint reasoning as a promising path toward stronger omnimodal understanding.", "upvotes": 35, "discussionId": "6a0fe204a53a61ce2e422dc8", "githubRepo": "https://github.com/yfanDai/LatentOmni", "githubRepoAddedBy": "user", "ai_summary": "LatentOmni is a cross-modal reasoning framework that interleaves textual reasoning with audio-visual latent states using feature-level supervision and temporal consistency embedding, outperforming explicit text-based chain-of-thought approaches in audio-visual reasoning tasks.", "ai_keywords": ["multimodal large language models", "chain-of-thought", "latent space", "cross-modal reasoning", "feature-level supervision", "Omni-Sync Position Embedding", "audio-visual reasoning", "autoregressive generation", "sensory information", "temporal consistency"], "githubStars": 7, "organization": {"_id": "662c559b322afcbae51b3c8b", "name": "KlingTeam", "fullname": "Kling Team", "avatar": "https://cdn-avatars.huggingface.co/v1/production/uploads/60e272ca6c78a8c122b12127/ZQV1aKLUDPf2rUcxxAqj6.jpeg"}, "summary_zh": "<ul>\n    <li>\u8054\u5408\u97f3\u9891-\u89c6\u89c9\u63a8\u7406\u5bf9\u4e8e\u5168\u9762\u7406\u89e3\u975e\u5e38\u91cd\u8981\uff0c\u4f46\u73b0\u6709\u7684\u591a\u6a21\u6001\u5927\u8bed\u8a00\u6a21\u578b\u5728\u9700\u8981\u7ec6\u81f4\u8bc1\u636e\u65f6\u4ecd\u8868\u73b0\u4e0d\u4f73\u3002</li>\n    <li>\u5f53\u524d\u6a21\u578b\u7684\u4e00\u4e2a\u4e3b\u8981\u9650\u5236\u662f\u5c06\u8fde\u7eed\u7684\u97f3\u9891-\u89c6\u89c9\u4fe1\u53f7\u538b\u7f29\u4e3a\u79bb\u6563\u7684\u6587\u672c\uff0c\u524a\u5f31\u4e86\u65f6\u95f4\u4e0a\u7684\u5173\u8054\u3002</li>\n    <li>\u6211\u4eec\u63d0\u51fa\u4e86LatentOmni\uff0c\u4e00\u4e2a\u4ea4\u53c9\u6a21\u6001\u63a8\u7406\u6846\u67b6\uff0c\u5b83\u7ed3\u5408\u4e86\u6587\u672c\u63a8\u7406\u4e0e\u97f3\u9891-\u89c6\u89c9\u7684\u6f5c\u5728\u72b6\u6001\u3002</li>\n    <li>LatentOmni\u5f15\u5165\u7279\u5f81\u7ea7\u76d1\u7763\uff0c\u4f7f\u6f5c\u5728\u63a8\u7406\u72b6\u6001\u4e0e\u4efb\u52a1\u76f8\u5173\u7684\u611f\u5b98\u7279\u5f81\u5bf9\u9f50\uff0c\u5e76\u4fdd\u6301\u65f6\u95f4\u4e00\u81f4\u6027\u3002</li>\n    <li>\u5728\u591a\u4e2a\u97f3\u9891-\u89c6\u89c9\u63a8\u7406\u57fa\u51c6\u6d4b\u8bd5\u4e2d\uff0cLatentOmni\u7684\u8868\u73b0\u4f18\u4e8e\u8bc4\u4f30\u7684\u6240\u6709\u5f00\u6e90\u6a21\u578b\uff0c\u8bc1\u660e\u6f5c\u5728\u7a7a\u95f4\u8054\u5408\u63a8\u7406\u662f\u4e00\u6761\u66f4\u5f3a\u7684\u7406\u89e3\u8def\u5f84\u3002</li>\n</ul>", "summary_simple": "<ul>\n    <li>Current multimodal language models have trouble reasoning with both audio and visual information together.</li>\n    <li>These models often rely on text-based reasoning, which can lose important details from audio and visuals.</li>\n    <li>LatentOmni is a new framework that combines reasoning with both text and sensory information in a unified way.</li>\n    <li>It includes methods to keep audio and visual information aligned and consistent over time.</li>\n    <li>LatentOmni shows better performance than existing models, proving that this approach can enhance understanding across different types of information.</li>\n</ul>"}, "publishedAt": "2026-05-20T20:00:00.000Z", "title": "LatentOmni: Rethinking Omni-Modal Understanding via Unified Audio-Visual Latent Reasoning", "summary": "Joint audio-visual reasoning is essential for omnimodal understanding, yet current multimodal large language models (MLLMs) still struggle when reasoning requires fine-grained evidence from both modalities. A central limitation is that explicit text-based chain-of-thought (CoT) compresses continuous audio-visual signals into discrete tokens, weakening temporal grounding and shifting intermediate reasoning toward language priors. We argue that a unified latent space is a better medium for such reasoning because it preserves dense sensory information while remaining compatible with autoregressive generation. Based on this insight, we propose LatentOmni, a cross-modal reasoning framework that interleaves textual reasoning with audio-visual latent states. LatentOmni introduces feature-level supervision to align latent reasoning states with task-relevant sensory features and uses Omni-Sync Position Embedding (OSPE) to maintain temporal consistency between latent audio and visual states. We further construct LatentOmni-Instruct-35K, a dataset of audio-visual interleaved reasoning trajectories for supervising latent-space reasoning. Comprehensive evaluation across multiple audio-visual reasoning benchmarks demonstrates that LatentOmni achieves the best performance among the evaluated open-source models and consistently outperforms the Explicit Text CoT baseline, supporting latent-space joint reasoning as a promising path toward stronger omnimodal understanding.", "thumbnail": "https://cdn-thumbnails.huggingface.co/social-thumbnails/papers/2605.22012.png", "numComments": 1, "submittedBy": {"_id": "6671214c92412fd4640714eb", "avatarUrl": "/avatars/48fa84e7bc3bb92ad0192aa26b32de10.svg", "fullname": "bohan zeng", "name": "zbhpku", "type": "user", "isPro": false, "isHf": false, "isHfAdmin": false, "isMod": false, "followerCount": 11, "isUserFollowing": false}, "organization": {"_id": "662c559b322afcbae51b3c8b", "name": "KlingTeam", "fullname": "Kling Team", "avatar": "https://cdn-avatars.huggingface.co/v1/production/uploads/60e272ca6c78a8c122b12127/ZQV1aKLUDPf2rUcxxAqj6.jpeg"}, "isAuthorParticipating": false}, {"paper": {"id": "2605.22718", "authors": [{"_id": "6a0fb610a53a61ce2e422bf6", "name": "Jung Yi", "hidden": false}, {"_id": "6a0fb610a53a61ce2e422bf7", "name": "Minjae Kim", "hidden": false}, {"_id": "6a0fb610a53a61ce2e422bf8", "name": "Paul Hyunbin Cho", "hidden": false}, {"_id": "6a0fb610a53a61ce2e422bf9", "name": "Wooseok Jang", "hidden": false}, {"_id": "6a0fb610a53a61ce2e422bfa", "name": "Sangdoo Yun", "hidden": false}, {"_id": "6a0fb610a53a61ce2e422bfb", "name": "Seungryong Kim", "hidden": false}], "publishedAt": "2026-05-21T00:00:00.000Z", "submittedOnDailyAt": "2026-05-22T00:00:00.000Z", "title": "WorldKV: Efficient World Memory with World Retrieval and Compression", "submittedOnDailyBy": {"_id": "63ca8e060609f1def7e6548a", "avatarUrl": "/avatars/1da7947840cb87d5f77c0af9ee11f9c2.svg", "isPro": true, "fullname": "Yi Jung", "user": "YJ-142150", "type": "user", "name": "YJ-142150"}, "summary": "Autoregressive video diffusion models have enabled real-time, action-conditioned world generation. However, sustaining a persistent world, where revisiting a previously seen viewpoint yields consistent content, remains an open problem. Full KV-cache attention preserves this consistency but breaks real-time constraints: memory footprint and attention cost grow linearly with rollout length. Sliding window inference restores throughput but discards long-term consistency. We propose WorldKV, a training-free framework with two components: World Retrieval and World Compression. World Retrieval stores evicted KV-cache chunks in GPU/CPU memory and selectively retrieves scene-relevant chunks via camera/ action correspondence, inserting them back into the native attention window without re-encoding. World Compression prunes redundant tokens within each chunk via key-key similarity to an anchor frame, halving per-chunk storage to fit 2x more history under a fixed budget. On Matrix-Game-2.0 and LingBot- World-Fast, WorldKV matches or exceeds full-KV memory fidelity at roughly 2x the throughput, and is competitive with memory-trained baselines without any fine-tuning. Project Page: https://cvlab-kaist.github.io/WorldKV/", "upvotes": 29, "discussionId": "6a0fb610a53a61ce2e422bfc", "projectPage": "https://cvlab-kaist.github.io/WorldKV/", "ai_summary": "WorldKV enables persistent world generation in video diffusion models by retrieving and compressing key-value cache chunks to maintain consistency while improving throughput.", "ai_keywords": ["autoregressive video diffusion models", "KV-cache attention", "sliding window inference", "world retrieval", "world compression", "key-key similarity", "attention window", "token pruning", "camera/action correspondence"], "organization": {"_id": "6475760c33192631bad2bb38", "name": "kaist-ai", "fullname": "KAIST AI", "avatar": "https://cdn-avatars.huggingface.co/v1/production/uploads/6469949654873f0043b09c22/aaZFiyXe1qR-Dmy_xq67m.png"}, "summary_zh": "<ul>\n    <li>\u81ea\u56de\u5f52\u89c6\u9891\u6269\u6563\u6a21\u578b\u53ef\u4ee5\u5b9e\u65f6\u751f\u6210\u57fa\u4e8e\u52a8\u4f5c\u7684\u4e16\u754c\uff0c\u4f46\u4fdd\u6301\u4e00\u81f4\u7684\u6301\u7eed\u4e16\u754c\u4ecd\u662f\u4e00\u4e2a\u6311\u6218\u3002</li>\n    <li>\u5b8c\u6574\u7684KV\u7f13\u5b58\u6ce8\u610f\u529b\u65b9\u6cd5\u4fdd\u6301\u4e00\u81f4\u6027\uff0c\u4f46\u4f1a\u589e\u52a0\u5185\u5b58\u548c\u8ba1\u7b97\u6210\u672c\u3002</li>\n    <li>\u6ed1\u52a8\u7a97\u53e3\u63a8\u7406\u867d\u7136\u63d0\u9ad8\u4e86\u901f\u5ea6\uff0c\u4f46\u727a\u7272\u4e86\u957f\u671f\u4e00\u81f4\u6027\u3002</li>\n    <li>\u6211\u4eec\u63d0\u51fa\u4e86WorldKV\u6846\u67b6\uff0c\u5305\u62ec\u201c\u4e16\u754c\u68c0\u7d22\u201d\u548c\u201c\u4e16\u754c\u538b\u7f29\u201d\u4e24\u4e2a\u90e8\u5206\uff0c\u6539\u5584\u4e86\u6027\u80fd\u3002</li>\n    <li>\u5728Matrix-Game-2.0\u548cLingBot-World-Fast\u4e0a\uff0cWorldKV\u5728\u901f\u5ea6\u4e0a\u8fbe\u5230\u6216\u8d85\u8fc7\u5b8c\u6574KV\u7f13\u5b58\u7684\u8868\u73b0\uff0c\u5e76\u4e14\u65e0\u9700\u5fae\u8c03\u3002</li>\n</ul>", "summary_simple": "<ul>\n    <li>Autoregressive video diffusion models can generate worlds in real-time based on actions.</li>\n    <li>Keeping a consistent world when revisiting places is a challenge due to memory and speed issues.</li>\n    <li>WorldKV is a new framework that improves consistency without needing extra training.</li>\n    <li>It has two parts: one retrieves relevant memory chunks efficiently, and the other reduces unnecessary data storage.</li>\n    <li>WorldKV performs as well as traditional methods but is faster and does not require fine-tuning.</li>\n</ul>"}, "publishedAt": "2026-05-20T20:00:00.000Z", "title": "WorldKV: Efficient World Memory with World Retrieval and Compression", "summary": "Autoregressive video diffusion models have enabled real-time, action-conditioned world generation. However, sustaining a persistent world, where revisiting a previously seen viewpoint yields consistent content, remains an open problem. Full KV-cache attention preserves this consistency but breaks real-time constraints: memory footprint and attention cost grow linearly with rollout length. Sliding window inference restores throughput but discards long-term consistency. We propose WorldKV, a training-free framework with two components: World Retrieval and World Compression. World Retrieval stores evicted KV-cache chunks in GPU/CPU memory and selectively retrieves scene-relevant chunks via camera/ action correspondence, inserting them back into the native attention window without re-encoding. World Compression prunes redundant tokens within each chunk via key-key similarity to an anchor frame, halving per-chunk storage to fit 2x more history under a fixed budget. On Matrix-Game-2.0 and LingBot- World-Fast, WorldKV matches or exceeds full-KV memory fidelity at roughly 2x the throughput, and is competitive with memory-trained baselines without any fine-tuning. Project Page: https://cvlab-kaist.github.io/WorldKV/", "thumbnail": "https://cdn-thumbnails.huggingface.co/social-thumbnails/papers/2605.22718.png", "numComments": 1, "submittedBy": {"_id": "63ca8e060609f1def7e6548a", "avatarUrl": "/avatars/1da7947840cb87d5f77c0af9ee11f9c2.svg", "fullname": "Yi Jung", "name": "YJ-142150", "type": "user", "isPro": true, "isHf": false, "isHfAdmin": false, "isMod": false, "isUserFollowing": false}, "organization": {"_id": "6475760c33192631bad2bb38", "name": "kaist-ai", "fullname": "KAIST AI", "avatar": "https://cdn-avatars.huggingface.co/v1/production/uploads/6469949654873f0043b09c22/aaZFiyXe1qR-Dmy_xq67m.png"}, "isAuthorParticipating": false}, {"paper": {"id": "2605.22642", "authors": [{"_id": "6a0fb81aa53a61ce2e422c07", "user": {"_id": "641c5662c3983aa949110c76", "avatarUrl": "https://cdn-avatars.huggingface.co/v1/production/uploads/641c5662c3983aa949110c76/VhnS7jffwfyRMfuL-qU_e.jpeg", "isPro": false, "fullname": "Banghao Chi", "user": "BiboyQG", "type": "user", "name": "BiboyQG"}, "name": "Banghao Chi", "status": "claimed_verified", "statusLastChangedAt": "2026-05-22T16:08:56.542Z", "hidden": false}, {"_id": "6a0fb81aa53a61ce2e422c08", "name": "Yining Xie", "hidden": false}, {"_id": "6a0fb81aa53a61ce2e422c09", "user": {"_id": "65d3b7ec8f6b98b34ee6bbe3", "avatarUrl": "/avatars/53c2d4e4746147fc2559435d252e8951.svg", "isPro": true, "fullname": "Mingyuan Wu", "user": "Mingyuan1997", "type": "user", "name": "Mingyuan1997"}, "name": "Mingyuan Wu", "status": "claimed_verified", "statusLastChangedAt": "2026-05-22T16:08:58.179Z", "hidden": false}, {"_id": "6a0fb81aa53a61ce2e422c0a", "name": "Jingcheng Yang", "hidden": false}, {"_id": "6a0fb81aa53a61ce2e422c0b", "user": {"_id": "65614a38b29be3f5b69f296f", "avatarUrl": "/avatars/9f000f695714e7bf0252648dbe2cfec7.svg", "isPro": false, "fullname": "Jize Jiang", "user": "jizej", "type": "user", "name": "jizej"}, "name": "Jize Jiang", "status": "claimed_verified", "statusLastChangedAt": "2026-05-22T16:08:59.968Z", "hidden": false}, {"_id": "6a0fb81aa53a61ce2e422c0c", "name": "Zhaoheng Li", "hidden": false}, {"_id": "6a0fb81aa53a61ce2e422c0d", "name": "Shengyi Qian", "hidden": false}, {"_id": "6a0fb81aa53a61ce2e422c0e", "name": "Minjia Zhang", "hidden": false}, {"_id": "6a0fb81aa53a61ce2e422c0f", "name": "Klara Nahrstedt", "hidden": false}, {"_id": "6a0fb81aa53a61ce2e422c10", "name": "Rui Hou", "hidden": false}, {"_id": "6a0fb81aa53a61ce2e422c11", "name": "Xiangjun Fan", "hidden": false}, {"_id": "6a0fb81aa53a61ce2e422c12", "name": "Hanchao Yu", "hidden": false}], "publishedAt": "2026-05-21T00:00:00.000Z", "submittedOnDailyAt": "2026-05-22T00:00:00.000Z", "title": "Spreadsheet-RL: Advancing Large Language Model Agents on Realistic Spreadsheet Tasks via Reinforcement Learning", "submittedOnDailyBy": {"_id": "6039478ab3ecf716b1a5fd4d", "avatarUrl": "https://cdn-avatars.huggingface.co/v1/production/uploads/6039478ab3ecf716b1a5fd4d/_Thy4E7taiSYBLKxEKJbT.jpeg", "isPro": true, "fullname": "taesiri", "user": "taesiri", "type": "user", "name": "taesiri"}, "summary": "Spreadsheet systems (e.g., Microsoft Excel, Google Sheets) play a central role in modern data-centric workflows. As AI agents grow increasingly capable of automating complex tasks, such as controlling computers and generating presentations, building an AI-driven spreadsheet agent has emerged as a promising research direction. Most existing spreadsheet agents rely on specialized prompting over general-purpose LLMs; while this design has potentials on simple spreadsheet operations, it struggles to manage the complex, multi-step workflows typical of real-world applications.\n  We introduce Spreadsheet-RL, a reinforcement learning (RL) fine-tuning framework designed to train specialized spreadsheet agents within a realistic Microsoft Excel environment. Spreadsheet-RL features an automated pipeline for scalable collection of paired start-goal spreadsheets from online forums, as well as domain-specific evaluation tasks in areas such as finance and supply chain management, which we compile into the new Domain-Spreadsheet benchmark dataset. It also includes a Spreadsheet Gym environment designed for multi-turn RL: Spreadsheet Gym exposes extensive Excel functionality through a Python sandbox, along with a refined harness that incorporates a comprehensive tool set and carefully designed tool-routing rules for spreadsheet tasks. Through comprehensive experiments, we show that Spreadsheet-RL substantially enhances AI agent's performance on both general and domain-specific spreadsheet tasks: it improves Qwen3-4B-Thinking-2507's Pass@1 on SpreadsheetBench from 12.0% to 23.4%, and raises Pass@1 from 8.4% to 17.2% on our curated Domain-Spreadsheet dataset. These results highlight Spreadsheet-RL's strong potential for generalization and real-world adoption in spreadsheet automation, and broadly, its promise for advancing LLM-based interactions with data interfaces in everyday work.", "upvotes": 29, "discussionId": "6a0fb81aa53a61ce2e422c13", "projectPage": "https://spreadsheet-rl.github.io/", "githubRepo": "https://github.com/Spreadsheet-RL/Spreadsheet-RL", "githubRepoAddedBy": "user", "ai_summary": "Spreadsheet-RL is a reinforcement learning framework that trains specialized spreadsheet agents in realistic Excel environments, improving AI agent performance on both general and domain-specific spreadsheet tasks through automated data collection and domain-specific benchmarks.", "ai_keywords": ["reinforcement learning", "fine-tuning", "spreadsheet agents", "Microsoft Excel", "automated pipeline", "domain-specific evaluation", "Domain-Spreadsheet benchmark", "Spreadsheet Gym", "multi-turn RL", "tool-routing rules", "Pass@1"], "githubStars": 6, "organization": {"_id": "65448bef5b5d9185ba3202b9", "name": "UIUC-CS", "fullname": "University of Illinois at Urbana-Champaign", "avatar": "https://cdn-avatars.huggingface.co/v1/production/uploads/65448b21fcb96b8b48733729/ycqcXFayMTTD_KpE37067.jpeg"}, "summary_zh": "<ul>\n    <li>\u7535\u5b50\u8868\u683c\u7cfb\u7edf\u5728\u73b0\u4ee3\u6570\u636e\u5de5\u4f5c\u6d41\u7a0b\u4e2d\u626e\u6f14\u91cd\u8981\u89d2\u8272\u3002</li>\n    <li>\u968f\u7740\u4eba\u5de5\u667a\u80fd\u4ee3\u7406\u7684\u80fd\u529b\u589e\u5f3a\uff0c\u5f00\u53d1\u57fa\u4e8eAI\u7684\u7535\u5b50\u8868\u683c\u4ee3\u7406\u6210\u4e3a\u7814\u7a76\u65b0\u65b9\u5411\u3002</li>\n    <li>\u73b0\u6709\u7684\u7535\u5b50\u8868\u683c\u4ee3\u7406\u4e3b\u8981\u4f9d\u8d56\u4e8e\u7279\u5b9a\u7684\u63d0\u793a\uff0c\u5904\u7406\u590d\u6742\u7684\u591a\u6b65\u9aa4\u5de5\u4f5c\u6d41\u5b58\u5728\u56f0\u96be\u3002</li>\n    <li>\u6211\u4eec\u63a8\u51fa\u4e86Spreadsheet-RL\uff0c\u8fd9\u662f\u4e00\u4e2a\u5728\u771f\u5b9eExcel\u73af\u5883\u4e2d\u8bad\u7ec3\u7535\u5b50\u8868\u683c\u4ee3\u7406\u7684\u5f3a\u5316\u5b66\u4e60\u6846\u67b6\u3002</li>\n    <li>\u5b9e\u9a8c\u8868\u660e\uff0cSpreadsheet-RL\u663e\u8457\u63d0\u9ad8\u4e86AI\u4ee3\u7406\u5728\u7535\u5b50\u8868\u683c\u4efb\u52a1\u4e0a\u7684\u8868\u73b0\uff0c\u5c55\u793a\u4e86\u5176\u5728\u81ea\u52a8\u5316\u4e2d\u7684\u6f5c\u529b\u3002</li>\n</ul>", "summary_simple": "<ul>\n    <li>Spreadsheet systems like Excel and Google Sheets are important for managing data today.</li>\n    <li>Building a smart AI agent for spreadsheets is a new area of research, but current methods struggle with complex tasks.</li>\n    <li>Spreadsheet-RL is a new framework that uses reinforcement learning to train these AI agents in Excel.</li>\n    <li>The framework includes a way to collect real spreadsheet tasks and a special environment for testing AI performance.</li>\n    <li>Tests show that Spreadsheet-RL greatly improves AI performance on various spreadsheet tasks, indicating its potential for real-world use.</li>\n</ul>"}, "publishedAt": "2026-05-20T20:00:00.000Z", "title": "Spreadsheet-RL: Advancing Large Language Model Agents on Realistic Spreadsheet Tasks via Reinforcement Learning", "summary": "Spreadsheet systems (e.g., Microsoft Excel, Google Sheets) play a central role in modern data-centric workflows. As AI agents grow increasingly capable of automating complex tasks, such as controlling computers and generating presentations, building an AI-driven spreadsheet agent has emerged as a promising research direction. Most existing spreadsheet agents rely on specialized prompting over general-purpose LLMs; while this design has potentials on simple spreadsheet operations, it struggles to manage the complex, multi-step workflows typical of real-world applications.\n  We introduce Spreadsheet-RL, a reinforcement learning (RL) fine-tuning framework designed to train specialized spreadsheet agents within a realistic Microsoft Excel environment. Spreadsheet-RL features an automated pipeline for scalable collection of paired start-goal spreadsheets from online forums, as well as domain-specific evaluation tasks in areas such as finance and supply chain management, which we compile into the new Domain-Spreadsheet benchmark dataset. It also includes a Spreadsheet Gym environment designed for multi-turn RL: Spreadsheet Gym exposes extensive Excel functionality through a Python sandbox, along with a refined harness that incorporates a comprehensive tool set and carefully designed tool-routing rules for spreadsheet tasks. Through comprehensive experiments, we show that Spreadsheet-RL substantially enhances AI agent's performance on both general and domain-specific spreadsheet tasks: it improves Qwen3-4B-Thinking-2507's Pass@1 on SpreadsheetBench from 12.0% to 23.4%, and raises Pass@1 from 8.4% to 17.2% on our curated Domain-Spreadsheet dataset. These results highlight Spreadsheet-RL's strong potential for generalization and real-world adoption in spreadsheet automation, and broadly, its promise for advancing LLM-based interactions with data interfaces in everyday work.", "thumbnail": "https://cdn-thumbnails.huggingface.co/social-thumbnails/papers/2605.22642.png", "numComments": 3, "submittedBy": {"_id": "6039478ab3ecf716b1a5fd4d", "avatarUrl": "https://cdn-avatars.huggingface.co/v1/production/uploads/6039478ab3ecf716b1a5fd4d/_Thy4E7taiSYBLKxEKJbT.jpeg", "fullname": "taesiri", "name": "taesiri", "type": "user", "isPro": true, "isHf": false, "isHfAdmin": false, "isMod": false, "followerCount": 304, "isUserFollowing": false}, "organization": {"_id": "65448bef5b5d9185ba3202b9", "name": "UIUC-CS", "fullname": "University of Illinois at Urbana-Champaign", "avatar": "https://cdn-avatars.huggingface.co/v1/production/uploads/65448b21fcb96b8b48733729/ycqcXFayMTTD_KpE37067.jpeg"}, "isAuthorParticipating": true}],
    "week": [{"paper": {"id": "2605.22355", "authors": [{"_id": "6a0fc10ea53a61ce2e422c9a", "user": {"_id": "6964ab352fb9f77cbe8c9854", "avatarUrl": "/avatars/2c4734b40bb98d162837fbe6b128f7d7.svg", "isPro": false, "fullname": "Hanyu Guo", "user": "MaoPaJia", "type": "user", "name": "MaoPaJia"}, "name": "Hanyu Guo", "status": "claimed_verified", "statusLastChangedAt": "2026-05-22T16:08:45.926Z", "hidden": false}, {"_id": "6a0fc10ea53a61ce2e422c9b", "name": "Jiedong Yang", "hidden": false}, {"_id": "6a0fc10ea53a61ce2e422c9c", "name": "Chao Chen", "hidden": false}, {"_id": "6a0fc10ea53a61ce2e422c9d", "user": {"_id": "682eeb11d28d9650c926abb0", "avatarUrl": "/avatars/3c8a34cc61aa2330ffcb52446a9afe70.svg", "isPro": false, "fullname": "LONGFEI XU", "user": "Xufew", "type": "user", "name": "Xufew"}, "name": "Longfei Xu", "status": "claimed_verified", "statusLastChangedAt": "2026-05-22T16:08:49.010Z", "hidden": false}, {"_id": "6a0fc10ea53a61ce2e422c9e", "name": "Kaikui Liu", "hidden": false}, {"_id": "6a0fc10ea53a61ce2e422c9f", "name": "Xiangxiang Chu", "hidden": false}], "publishedAt": "2026-05-21T00:00:00.000Z", "submittedOnDailyAt": "2026-05-22T00:00:00.000Z", "title": "TransitLM: A Large-Scale Dataset and Benchmark for Map-Free Transit Route Generation", "submittedOnDailyBy": {"_id": "66d255e3947594430c723ff6", "avatarUrl": "/avatars/c56e4792332a01bf34085a75ee64916e.svg", "isPro": false, "fullname": "xiaochonglinghu", "user": "xiaochonglinghu", "type": "user", "name": "xiaochonglinghu"}, "summary": "Public transit route planning traditionally depends on structured map infrastructure and complex routing engines, and no existing dataset supports training models to bypass this dependency. We present TransitLM, a large-scale dataset of over 13 million transit route planning records from four Chinese cities covering 120,845 stations and 13,666 lines, released as a continual pre-training corpus and benchmark data for three evaluation tasks with complementary metrics. Experiments show that an LLM trained on TransitLM produces structurally valid routes at high accuracy and implicitly grounds arbitrary GPS coordinates to appropriate stations without any explicit mapping. These results demonstrate that transit route planning can be learned entirely from data, enabling end-to-end, map-free route generation directly from origin-destination information. The dataset and benchmark are available at https://huggingface.co/datasets/GD-ML/TransitLM, with evaluation code at https://github.com/HotTricker/TransitLM.", "upvotes": 162, "discussionId": "6a0fc10ea53a61ce2e422ca0", "githubRepo": "https://github.com/HotTricker/TransitLM", "githubRepoAddedBy": "user", "ai_summary": "TransitLM dataset enables end-to-end transit route planning using large language models trained on structured transit data, eliminating the need for traditional map-based approaches.", "ai_keywords": ["large language models", "transit route planning", "structured map infrastructure", "routing engines", "continual pre-training", "evaluation tasks", "GPS coordinates", "origin-destination information"], "githubStars": 107, "organization": {"_id": "67d11771890254196d3174e5", "name": "GD-ML", "fullname": "AMAP-ML", "avatar": "https://cdn-avatars.huggingface.co/v1/production/uploads/67d116c47be76de1a40873ca/s5ukAx9E36ZZIKvbpBRi4.png"}, "summary_zh": "<ul>\n    <li>TransitLM\u662f\u4e00\u4e2a\u5927\u89c4\u6a21\u7684\u6570\u636e\u96c6\uff0c\u5305\u62ec\u6765\u81ea\u56db\u4e2a\u4e2d\u56fd\u57ce\u5e02\u76841300\u591a\u4e07\u6761\u516c\u5171\u4ea4\u901a\u8def\u7ebf\u89c4\u5212\u8bb0\u5f55\u3002</li>\n    <li>\u8be5\u6570\u636e\u96c6\u6db5\u76d6\u4e86120,845\u4e2a\u7ad9\u70b9\u548c13,666\u6761\u7ebf\u8def\uff0c\u65e8\u5728\u66ff\u4ee3\u4f20\u7edf\u7684\u5730\u56fe\u57fa\u7840\u8bbe\u65bd\u548c\u590d\u6742\u8def\u7531\u5f15\u64ce\u3002</li>\n    <li>\u5b9e\u9a8c\u8868\u660e\uff0c\u57fa\u4e8eTransitLM\u8bad\u7ec3\u7684\u5927\u578b\u8bed\u8a00\u6a21\u578b\u53ef\u4ee5\u63d0\u4f9b\u9ad8\u51c6\u786e\u7387\u7684\u6709\u6548\u8def\u7ebf\u89c4\u5212\u3002</li>\n    <li>\u8be5\u6a21\u578b\u53ef\u4ee5\u6839\u636e\u539f\u70b9\u548c\u76ee\u7684\u5730\u4fe1\u606f\u751f\u6210\u8def\u7ebf\uff0c\u800c\u65e0\u9700\u4f9d\u8d56\u4efb\u4f55\u660e\u786e\u7684\u5730\u56fe\u3002</li>\n    <li>\u6570\u636e\u96c6\u548c\u57fa\u51c6\u6d4b\u8bd5\u53ef\u5728\u6307\u5b9a\u7f51\u5740\u83b7\u53d6\uff0c\u4e3a\u7814\u7a76\u548c\u5f00\u53d1\u63d0\u4f9b\u652f\u6301\u3002</li>\n</ul>", "summary_simple": "<ul>\n    <li>TransitLM is a new dataset with over 13 million records for planning public transit routes in four Chinese cities.</li>\n    <li>It includes data from 120,845 stations and 13,666 transit lines.</li>\n    <li>The dataset allows for training models to generate transit routes without needing traditional maps.</li>\n    <li>Experiments show that a language model trained on this dataset can create accurate routes and link GPS coordinates to the right stations.</li>\n    <li>The dataset and related code are available online for use and evaluation.</li>\n</ul>"}, "publishedAt": "2026-05-20T20:00:00.000Z", "title": "TransitLM: A Large-Scale Dataset and Benchmark for Map-Free Transit Route Generation", "summary": "Public transit route planning traditionally depends on structured map infrastructure and complex routing engines, and no existing dataset supports training models to bypass this dependency. We present TransitLM, a large-scale dataset of over 13 million transit route planning records from four Chinese cities covering 120,845 stations and 13,666 lines, released as a continual pre-training corpus and benchmark data for three evaluation tasks with complementary metrics. Experiments show that an LLM trained on TransitLM produces structurally valid routes at high accuracy and implicitly grounds arbitrary GPS coordinates to appropriate stations without any explicit mapping. These results demonstrate that transit route planning can be learned entirely from data, enabling end-to-end, map-free route generation directly from origin-destination information. The dataset and benchmark are available at https://huggingface.co/datasets/GD-ML/TransitLM, with evaluation code at https://github.com/HotTricker/TransitLM.", "thumbnail": "https://cdn-thumbnails.huggingface.co/social-thumbnails/papers/2605.22355.png", "numComments": 2, "submittedBy": {"_id": "66d255e3947594430c723ff6", "avatarUrl": "/avatars/c56e4792332a01bf34085a75ee64916e.svg", "fullname": "xiaochonglinghu", "name": "xiaochonglinghu", "type": "user", "isPro": false, "isHf": false, "isHfAdmin": false, "isMod": false, "followerCount": 9, "isUserFollowing": false}, "organization": {"_id": "67d11771890254196d3174e5", "name": "GD-ML", "fullname": "AMAP-ML", "avatar": "https://cdn-avatars.huggingface.co/v1/production/uploads/67d116c47be76de1a40873ca/s5ukAx9E36ZZIKvbpBRi4.png"}, "isAuthorParticipating": false}, {"paper": {"id": "2605.22109", "authors": [{"_id": "6a0fb91ea53a61ce2e422c1c", "name": "Caixin Kang", "hidden": false}, {"_id": "6a0fb91ea53a61ce2e422c1d", "name": "Tianyu Yan", "hidden": false}, {"_id": "6a0fb91ea53a61ce2e422c1e", "name": "Sitong Gong", "hidden": false}, {"_id": "6a0fb91ea53a61ce2e422c1f", "name": "Mingfang Zhang", "hidden": false}, {"_id": "6a0fb91ea53a61ce2e422c20", "name": "Liangyang Ouyang", "hidden": false}, {"_id": "6a0fb91ea53a61ce2e422c21", "name": "Ruicong Liu", "hidden": false}, {"_id": "6a0fb91ea53a61ce2e422c22", "name": "Bo Zheng", "hidden": false}, {"_id": "6a0fb91ea53a61ce2e422c23", "name": "Huchuan Lu", "hidden": false}, {"_id": "6a0fb91ea53a61ce2e422c24", "name": "Kaipeng Zhang", "hidden": false}, {"_id": "6a0fb91ea53a61ce2e422c25", "name": "Yoichi Sato", "hidden": false}, {"_id": "6a0fb91ea53a61ce2e422c26", "name": "Yifei Huang", "hidden": false}], "publishedAt": "2026-05-21T00:00:00.000Z", "submittedOnDailyAt": "2026-05-22T00:00:00.000Z", "title": "Perception or Prejudice: Can MLLMs Go Beyond First Impressions of Personality?", "submittedOnDailyBy": {"_id": "63a286c7f30c4642278ed11a", "avatarUrl": "/avatars/974fe4f3023791e97228c53330e9b4f3.svg", "isPro": false, "fullname": "Tim Kang", "user": "Ukpkmkkk", "type": "user", "name": "Ukpkmkkk"}, "summary": "Multimodal Large Language Models (MLLMs) are increasingly deployed in human-facing roles where personality perception is critical, yet existing benchmarks evaluate this capability solely on numerical Big Five score prediction, leaving open whether models truly perceive personality through behavioral understanding or merely prejudge through superficial pattern matching. We address this gap with three contributions. (i) A new task: we formalize Grounded Personality Reasoning (GPR), which requires MLLMs to anchor each Big Five rating in observable evidence through a chain of rating, reasoning, and grounding. (ii) A new dataset: we release MM-OCEAN (1,104 videos, 5,320 MCQs), produced by a multi-agent pipeline with human verification, with timestamped behavioral observations, evidence-grounded trait analyses, and seven categories of cue-grounding MCQs. (iii) Benchmark and analysis: we design a three-tier evaluation (rating, reasoning, grounding) plus four sample-level failure-mode metrics: Prejudice Rate (PR), Confabulation Rate (CR), Integration-failure Rate (IR), and Holistic-grounding Rate (HR), and benchmark 27 MLLMs (13 closed, 14 open). The analysis uncovers a striking Prejudice Gap: across the field, 51% of correct ratings are not grounded in retrieved cues, and the Holistic-Grounding Rate spans only 0-33.5%. These findings expose a disconnect between getting the right score and reasoning for the right reason, charting a roadmap for grounded social cognition in MLLMs.", "upvotes": 151, "discussionId": "6a0fb91fa53a61ce2e422c27", "githubRepo": "https://github.com/kkkcx/MM-OCEAN", "githubRepoAddedBy": "user", "ai_summary": "Researchers introduce a new task and dataset for evaluating personality reasoning in multimodal language models, revealing significant gaps between accurate predictions and grounded reasoning processes.", "ai_keywords": ["Multimodal Large Language Models", "Big Five score prediction", "Grounded Personality Reasoning", "MM-OCEAN dataset", "chain of rating", "reasoning", "and grounding", "multi-agent pipeline", "behavioral observations", "evidence-grounded trait analyses", "cue-grounding MCQs", "three-tier evaluation", "Prejudice Rate", "Confabulation Rate", "Integration-failure Rate", "Holistic-grounding Rate"], "githubStars": 5, "organization": {"_id": "6a0fbe68162dc5d32a0057a0", "name": "utokyo-ai", "fullname": "The University of Tokyo", "avatar": "https://cdn-avatars.huggingface.co/v1/production/uploads/63a286c7f30c4642278ed11a/jNLYa73JGG4k3ywpoD_9k.png"}, "summary_zh": "<ul>\n    <li>\u591a\u6a21\u6001\u5927\u8bed\u8a00\u6a21\u578b\uff08MLLMs\uff09\u5728\u9700\u8981\u7406\u89e3\u4e2a\u6027\u7684\u91cd\u8981\u89d2\u8272\u4e2d\u8d8a\u6765\u8d8a\u591a\u5730\u88ab\u5e94\u7528\u3002</li>\n    <li>\u63d0\u51fa\u4e86\u4e00\u79cd\u65b0\u4efb\u52a1\uff1a\u57fa\u4e8e\u53ef\u89c2\u5bdf\u8bc1\u636e\u5bf9\u4e94\u5927\u6027\u683c\u7279\u5f81\u8fdb\u884c\u63a8\u7406\uff08GPR\uff09\u3002</li>\n    <li>\u53d1\u5e03\u4e86\u4e00\u4e2a\u65b0\u6570\u636e\u96c6MM-OCEAN\uff0c\u5305\u62ec1104\u4e2a\u89c6\u9891\u548c5320\u4e2a\u591a\u9879\u9009\u62e9\u9898\uff0c\u6db5\u76d6\u884c\u4e3a\u89c2\u5bdf\u548c\u4e2a\u6027\u5206\u6790\u3002</li>\n    <li>\u8bbe\u8ba1\u4e86\u4e09\u5c42\u6b21\u7684\u8bc4\u4f30\u6807\u51c6\uff0c\u5e76\u5206\u6790\u4e8627\u4e2aMLLMs\u7684\u8868\u73b0\uff0c\u53d1\u73b0\u4e86\u660e\u663e\u7684\u504f\u89c1\u5dee\u8ddd\u3002</li>\n    <li>\u7ed3\u679c\u663e\u793a\uff0c\u867d\u7136\u8bc4\u5206\u6b63\u786e\uff0c\u4f46\u7f3a\u4e4f\u57fa\u4e8e\u8bc1\u636e\u7684\u63a8\u7406\uff0c\u63d0\u793aMLLMs\u5728\u793e\u4f1a\u8ba4\u77e5\u65b9\u9762\u7684\u4e0d\u8db3\u3002</li>\n</ul>", "summary_simple": "<ul>\n    <li>Multimodal Large Language Models (MLLMs) are used in roles where understanding personality is important, but current tests only measure their ability to predict personality scores.</li>\n    <li>The authors introduce a new task called Grounded Personality Reasoning (GPR) that requires MLLMs to support personality ratings with clear evidence.</li>\n    <li>They created a new dataset named MM-OCEAN, which includes over 1,100 videos and multiple-choice questions, with detailed behavioral observations and analyses.</li>\n    <li>The study includes a three-part evaluation system and various metrics to assess how well MLLMs understand personality, revealing a significant gap in their grounding of personality ratings.</li>\n    <li>Findings show that many correct ratings do not rely on actual behavioral cues, highlighting a need for better reasoning in MLLMs' social understanding.</li>\n</ul>"}, "publishedAt": "2026-05-20T20:00:00.000Z", "title": "Perception or Prejudice: Can MLLMs Go Beyond First Impressions of Personality?", "summary": "Multimodal Large Language Models (MLLMs) are increasingly deployed in human-facing roles where personality perception is critical, yet existing benchmarks evaluate this capability solely on numerical Big Five score prediction, leaving open whether models truly perceive personality through behavioral understanding or merely prejudge through superficial pattern matching. We address this gap with three contributions. (i) A new task: we formalize Grounded Personality Reasoning (GPR), which requires MLLMs to anchor each Big Five rating in observable evidence through a chain of rating, reasoning, and grounding. (ii) A new dataset: we release MM-OCEAN (1,104 videos, 5,320 MCQs), produced by a multi-agent pipeline with human verification, with timestamped behavioral observations, evidence-grounded trait analyses, and seven categories of cue-grounding MCQs. (iii) Benchmark and analysis: we design a three-tier evaluation (rating, reasoning, grounding) plus four sample-level failure-mode metrics: Prejudice Rate (PR), Confabulation Rate (CR), Integration-failure Rate (IR), and Holistic-grounding Rate (HR), and benchmark 27 MLLMs (13 closed, 14 open). The analysis uncovers a striking Prejudice Gap: across the field, 51% of correct ratings are not grounded in retrieved cues, and the Holistic-Grounding Rate spans only 0-33.5%. These findings expose a disconnect between getting the right score and reasoning for the right reason, charting a roadmap for grounded social cognition in MLLMs.", "thumbnail": "https://cdn-thumbnails.huggingface.co/social-thumbnails/papers/2605.22109.png", "numComments": 1, "submittedBy": {"_id": "63a286c7f30c4642278ed11a", "avatarUrl": "/avatars/974fe4f3023791e97228c53330e9b4f3.svg", "fullname": "Tim Kang", "name": "Ukpkmkkk", "type": "user", "isPro": false, "isHf": false, "isHfAdmin": false, "isMod": false, "isUserFollowing": false}, "organization": {"_id": "6a0fbe68162dc5d32a0057a0", "name": "utokyo-ai", "fullname": "The University of Tokyo", "avatar": "https://cdn-avatars.huggingface.co/v1/production/uploads/63a286c7f30c4642278ed11a/jNLYa73JGG4k3ywpoD_9k.png"}, "isAuthorParticipating": false}, {"paper": {"id": "2605.18747", "authors": [{"_id": "6a0bd45c8ca2d0b2563803fe", "name": "Xuying Ning", "hidden": false}, {"_id": "6a0bd45c8ca2d0b2563803ff", "name": "Katherine Tieu", "hidden": false}, {"_id": "6a0bd45c8ca2d0b256380400", "name": "Dongqi Fu", "hidden": false}, {"_id": "6a0bd45c8ca2d0b256380401", "name": "Tianxin Wei", "hidden": false}, {"_id": "6a0bd45c8ca2d0b256380402", "name": "Zihao Li", "hidden": false}, {"_id": "6a0bd45c8ca2d0b256380403", "name": "Yuanchen Bei", "hidden": false}, {"_id": "6a0bd45c8ca2d0b256380404", "name": "Jiaru Zou", "hidden": false}, {"_id": "6a0bd45c8ca2d0b256380405", "name": "Mengting Ai", "hidden": false}, {"_id": "6a0bd45c8ca2d0b256380406", "name": "Zhining Liu", "hidden": false}, {"_id": "6a0bd45c8ca2d0b256380407", "name": "Ting-Wei Li", "hidden": false}, {"_id": "6a0bd45c8ca2d0b256380408", "name": "Lingjie Chen", "hidden": false}, {"_id": "6a0bd45c8ca2d0b256380409", "name": "Yanjun Zhao", "hidden": false}, {"_id": "6a0bd45c8ca2d0b25638040a", "name": "Ke Yang", "hidden": false}, {"_id": "6a0bd45c8ca2d0b25638040b", "name": "Bingxuan Li", "hidden": false}, {"_id": "6a0bd45c8ca2d0b25638040c", "name": "Cheng Qian", "hidden": false}, {"_id": "6a0bd45c8ca2d0b25638040d", "name": "Gaotang Li", "hidden": false}, {"_id": "6a0bd45c8ca2d0b25638040e", "name": "Xiao Lin", "hidden": false}, {"_id": "6a0bd45c8ca2d0b25638040f", "name": "Zhichen Zeng", "hidden": false}, {"_id": "6a0bd45c8ca2d0b256380410", "name": "Ruizhong Qiu", "hidden": false}, {"_id": "6a0bd45c8ca2d0b256380411", "name": "Sirui Chen", "hidden": false}, {"_id": "6a0bd45c8ca2d0b256380412", "name": "Yifan Sun", "hidden": false}, {"_id": "6a0bd45c8ca2d0b256380413", "name": "Xiyuan Yang", "hidden": false}, {"_id": "6a0bd45c8ca2d0b256380414", "name": "Ruida Wang", "hidden": false}, {"_id": "6a0bd45c8ca2d0b256380415", "name": "Rui Pan", "hidden": false}, {"_id": "6a0bd45c8ca2d0b256380416", "name": "Chenyuan Yang", "hidden": false}, {"_id": "6a0bd45c8ca2d0b256380417", "name": "Dylan Zhang", "hidden": false}, {"_id": "6a0bd45c8ca2d0b256380418", "name": "Liri Fang", "hidden": false}, {"_id": "6a0bd45c8ca2d0b256380419", "name": "Zikun Cui", "hidden": false}, {"_id": "6a0bd45c8ca2d0b25638041a", "name": "Yang Cao", "hidden": false}, {"_id": "6a0bd45c8ca2d0b25638041b", "name": "Pan Chen", "hidden": false}, {"_id": "6a0bd45c8ca2d0b25638041c", "name": "Dorothy Sun", "hidden": false}, {"_id": "6a0bd45c8ca2d0b25638041d", "name": "Ren Chen", "hidden": false}, {"_id": "6a0bd45c8ca2d0b25638041e", "name": "Mahesh Srinivasan", "hidden": false}, {"_id": "6a0bd45c8ca2d0b25638041f", "name": "Nipun Mathur", "hidden": false}, {"_id": "6a0bd45c8ca2d0b256380420", "name": "Yinglong Xia", "hidden": false}, {"_id": "6a0bd45c8ca2d0b256380421", "name": "Hong Li", "hidden": false}, {"_id": "6a0bd45c8ca2d0b256380422", "name": "Hong Yan", "hidden": false}, {"_id": "6a0bd45c8ca2d0b256380423", "name": "Pan Lu", "hidden": false}, {"_id": "6a0bd45c8ca2d0b256380424", "name": "Lingming Zhang", "hidden": false}, {"_id": "6a0bd45c8ca2d0b256380425", "name": "Tong Zhang", "hidden": false}, {"_id": "6a0bd45c8ca2d0b256380426", "name": "Hanghang Tong", "hidden": false}, {"_id": "6a0bd45c8ca2d0b256380427", "name": "Jingrui He", "hidden": false}], "publishedAt": "2026-05-18T00:00:00.000Z", "submittedOnDailyAt": "2026-05-19T00:00:00.000Z", "title": "Code as Agent Harness", "submittedOnDailyBy": {"_id": "6039478ab3ecf716b1a5fd4d", "avatarUrl": "https://cdn-avatars.huggingface.co/v1/production/uploads/6039478ab3ecf716b1a5fd4d/_Thy4E7taiSYBLKxEKJbT.jpeg", "isPro": true, "fullname": "taesiri", "user": "taesiri", "type": "user", "name": "taesiri"}, "summary": "Recent large language models (LLMs) have demonstrated strong capabilities in understanding and generating code, from competitive programming to repository-level software engineering. In emerging agentic systems, code is no longer only a target output. It increasingly serves as an operational substrate for agent reasoning, acting, environment modeling, and execution-based verification. We frame this shift through the lens of agent harnesses and introduce code as agent harness: a unified view that centers code as the basis for agent infrastructure. To systematically study this perspective, we organize the survey around three connected layers. First, we study the harness interface, where code connects agents to reasoning, action, and environment modeling. Second, we examine harness mechanisms: planning, memory, and tool use for long-horizon execution, together with feedback-driven control and optimization that make harness reliable and adaptive. Third, we discuss scaling the harness from single-agent systems to multi-agent settings, where shared code artifacts support multi-agent coordination, review, and verification. Across these layers, we summarize representative methods and practical applications of code as agent harness, spanning coding assistants, GUI/OS automation, embodied agents, scientific discovery, personalization and recommendation, DevOps, and enterprise workflows. We further outline open challenges for harness engineering, including evaluation beyond final task success, verification under incomplete feedback, regression-free harness improvement, consistent shared state across multiple agents, human oversight for safety-critical actions, and extensions to multimodal environments. By centering code as the harness of agentic AI, this survey provides a unified roadmap toward executable, verifiable, and stateful AI agent systems.", "upvotes": 137, "discussionId": "6a0bd45c8ca2d0b256380428", "githubRepo": "https://github.com/YennNing/Awesome-Code-as-Agent-Harness-Papers", "githubRepoAddedBy": "user", "ai_summary": "Large language models are increasingly used as operational substrates for agent reasoning and execution in agentic systems, with code serving as a unified infrastructure layer across multiple domains and applications.", "ai_keywords": ["large language models", "agentic systems", "agent harness", "code as agent harness", "agent infrastructure", "reasoning", "action", "environment modeling", "planning", "memory", "tool use", "feedback-driven control", "optimization", "multi-agent coordination", "DevOps", "enterprise workflows"], "githubStars": 24, "summary_zh": "<ul>\n    <li>\u6700\u8fd1\u7684\u5927\u578b\u8bed\u8a00\u6a21\u578b\u5728\u7406\u89e3\u548c\u751f\u6210\u4ee3\u7801\u65b9\u9762\u8868\u73b0\u51fa\u5f3a\u5927\u7684\u80fd\u529b\uff0c\u9002\u7528\u4e8e\u7ade\u4e89\u7f16\u7a0b\u548c\u8f6f\u4ef6\u5de5\u7a0b\u3002</li>\n    <li>\u4ee3\u7801\u4e0d\u4ec5\u662f\u8f93\u51fa\u7ed3\u679c\uff0c\u8fd8\u6210\u4e3a\u4ee3\u7406\u63a8\u7406\u3001\u884c\u52a8\u3001\u73af\u5883\u5efa\u6a21\u548c\u6267\u884c\u9a8c\u8bc1\u7684\u57fa\u7840\u3002</li>\n    <li>\u672c\u6587\u5c06\u4ee3\u7801\u89c6\u4e3a\u201c\u4ee3\u7406\u5de5\u5177\u201d\uff0c\u5e76\u4ece\u4e09\u4e2a\u5c42\u9762\u8fdb\u884c\u7814\u7a76\uff1a\u63a5\u53e3\u3001\u673a\u5236\u548c\u591a\u4ee3\u7406\u6269\u5c55\u3002</li>\n    <li>\u7814\u7a76\u5185\u5bb9\u5305\u62ec\u7f16\u7801\u52a9\u624b\u3001GUI/\u64cd\u4f5c\u7cfb\u7edf\u81ea\u52a8\u5316\u3001\u79d1\u5b66\u53d1\u73b0\u7b49\u5b9e\u9645\u5e94\u7528\uff0c\u4ee5\u53ca\u5de5\u7a0b\u4e2d\u7684\u5f00\u653e\u6311\u6218\u3002</li>\n    <li>\u901a\u8fc7\u5c06\u4ee3\u7801\u4f5c\u4e3a\u4ee3\u7406AI\u7684\u57fa\u7840\uff0c\u63d0\u4f9b\u4e86\u53ef\u6267\u884c\u3001\u53ef\u9a8c\u8bc1\u548c\u72b6\u6001\u4fdd\u6301\u7684AI\u4ee3\u7406\u7cfb\u7edf\u7684\u7edf\u4e00\u8def\u7ebf\u56fe\u3002</li>\n</ul>", "summary_simple": "<ul>\n    <li>Recent language models can understand and generate code, making it useful for software engineering and problem-solving.</li>\n    <li>Code is becoming essential for AI agents, helping them think, act, and model their environments.</li>\n    <li>The survey explores three main areas: how code connects agents to their tasks, the mechanisms that help agents execute plans, and how to scale these systems for multiple agents working together.</li>\n    <li>It covers practical uses of code in various fields like coding assistance, automation, and scientific research.</li>\n    <li>The survey also identifies challenges in harnessing code for AI, such as improving reliability, ensuring safety, and managing multiple agents effectively.</li>\n</ul>"}, "publishedAt": "2026-05-17T20:00:00.000Z", "title": "Code as Agent Harness", "summary": "Recent large language models (LLMs) have demonstrated strong capabilities in understanding and generating code, from competitive programming to repository-level software engineering. In emerging agentic systems, code is no longer only a target output. It increasingly serves as an operational substrate for agent reasoning, acting, environment modeling, and execution-based verification. We frame this shift through the lens of agent harnesses and introduce code as agent harness: a unified view that centers code as the basis for agent infrastructure. To systematically study this perspective, we organize the survey around three connected layers. First, we study the harness interface, where code connects agents to reasoning, action, and environment modeling. Second, we examine harness mechanisms: planning, memory, and tool use for long-horizon execution, together with feedback-driven control and optimization that make harness reliable and adaptive. Third, we discuss scaling the harness from single-agent systems to multi-agent settings, where shared code artifacts support multi-agent coordination, review, and verification. Across these layers, we summarize representative methods and practical applications of code as agent harness, spanning coding assistants, GUI/OS automation, embodied agents, scientific discovery, personalization and recommendation, DevOps, and enterprise workflows. We further outline open challenges for harness engineering, including evaluation beyond final task success, verification under incomplete feedback, regression-free harness improvement, consistent shared state across multiple agents, human oversight for safety-critical actions, and extensions to multimodal environments. By centering code as the harness of agentic AI, this survey provides a unified roadmap toward executable, verifiable, and stateful AI agent systems.", "thumbnail": "https://cdn-thumbnails.huggingface.co/social-thumbnails/papers/2605.18747.png", "numComments": 3, "submittedBy": {"_id": "6039478ab3ecf716b1a5fd4d", "avatarUrl": "https://cdn-avatars.huggingface.co/v1/production/uploads/6039478ab3ecf716b1a5fd4d/_Thy4E7taiSYBLKxEKJbT.jpeg", "fullname": "taesiri", "name": "taesiri", "type": "user", "isPro": true, "isHf": false, "isHfAdmin": false, "isMod": false, "followerCount": 300, "isUserFollowing": false}, "isAuthorParticipating": false}, {"paper": {"id": "2605.21467", "authors": [{"_id": "6a0e89f1164dbbc68a26c5de", "user": {"_id": "6523afa7389ef6864de004a1", "avatarUrl": "/avatars/cdf04857038a7c8abadd2e2306835ebe.svg", "isPro": false, "fullname": "KaiyiZhang", "user": "Cardlnal", "type": "user", "name": "Cardlnal"}, "name": "Kaiyi Zhang", "status": "claimed_verified", "statusLastChangedAt": "2026-05-21T19:21:52.826Z", "hidden": false}, {"_id": "6a0e89f1164dbbc68a26c5df", "name": "Wei Wu", "hidden": false}, {"_id": "6a0e89f1164dbbc68a26c5e0", "name": "Yankai Lin", "hidden": false}], "publishedAt": "2026-05-20T00:00:00.000Z", "submittedOnDailyAt": "2026-05-22T00:00:00.000Z", "title": "DelTA: Discriminative Token Credit Assignment for Reinforcement Learning from Verifiable Rewards", "submittedOnDailyBy": {"_id": "6523afa7389ef6864de004a1", "avatarUrl": "/avatars/cdf04857038a7c8abadd2e2306835ebe.svg", "isPro": false, "fullname": "KaiyiZhang", "user": "Cardlnal", "type": "user", "name": "Cardlnal"}, "summary": "Reinforcement learning from verifiable rewards (RLVR) has emerged as a central technique for improving the reasoning capabilities of large language models. Despite its effectiveness, how response-level rewards translate into token-level probability changes remains poorly understood. We introduce a discriminator view of RLVR updates, showing that the policy-gradient update direction implicitly acts as a linear discriminator over token-gradient vectors and thereby determines which token probabilities are increased or decreased during learning. Under standard sequence-level RLVR, this discriminator is constructed from positive- and negative-side centroids formed by advantage-weighted averaging of token-gradient vectors. However, such centroid construction can be dominated by shared high-frequency patterns, such as formatting tokens, diluting sparse yet discriminative directions that better distinguish high-reward responses from low-reward ones. To address this limitation, we propose DelTA, a discriminative token credit assignment method that estimates token coefficients to amplify side-specific token-gradient directions and downweight shared or weakly discriminative ones. These coefficients reweight a self-normalized RLVR surrogate, making the effective side-wise centroids more contrastive and thereby reshaping the RLVR update direction. On seven mathematical benchmarks, DelTA outperforms the strongest same-scale baselines by 3.26 and 2.62 average points on Qwen3-8B-Base and Qwen3-14B-Base, respectively. Additional results on code generation, a different backbone, and out-of-domain evaluations further demonstrate the generalization ability of DelTA.", "upvotes": 124, "discussionId": "6a0e89f2164dbbc68a26c5e1", "githubRepo": "https://github.com/RUCBM/DelTA", "githubRepoAddedBy": "user", "ai_summary": "Reinforcement learning from verifiable rewards is enhanced through a discriminative token credit assignment method that improves reward-based training by amplifying distinctive token-gradient directions and reducing noise from shared patterns.", "ai_keywords": ["reinforcement learning from verifiable rewards", "policy-gradient update", "token-gradient vectors", "advantage-weighted averaging", "discriminative token credit assignment", "self-normalized RLVR surrogate", "side-wise centroids"], "githubStars": 4, "summary_zh": "<ul>\n    <li>\u589e\u5f3a\u5b66\u4e60\u901a\u8fc7\u53ef\u9a8c\u8bc1\u5956\u52b1\uff08RLVR\uff09\u662f\u63d0\u9ad8\u5927\u8bed\u8a00\u6a21\u578b\u63a8\u7406\u80fd\u529b\u7684\u91cd\u8981\u6280\u672f\u3002</li>\n    <li>\u76ee\u524d\u5c1a\u4e0d\u6e05\u695a\u54cd\u5e94\u7ea7\u5956\u52b1\u5982\u4f55\u8f6c\u5316\u4e3a\u6807\u8bb0\u7ea7\u6982\u7387\u53d8\u5316\u3002</li>\n    <li>\u6211\u4eec\u63d0\u51fa\u4e86\u4e00\u79cd\u5224\u522b\u5668\u89c6\u89d2\u6765\u770b\u5f85RLVR\u66f4\u65b0\uff0c\u8868\u660e\u7b56\u7565\u68af\u5ea6\u66f4\u65b0\u65b9\u5411\u4f5c\u4e3a\u7ebf\u6027\u5224\u522b\u5668\u5f71\u54cd\u6807\u8bb0\u6982\u7387\u7684\u6539\u53d8\u3002</li>\n    <li>\u901a\u8fc7\u4f20\u7edf\u7684RLVR\uff0c\u6784\u5efa\u7684\u5224\u522b\u5668\u53ef\u80fd\u53d7\u5230\u9ad8\u9891\u6a21\u5f0f\u7684\u5f71\u54cd\uff0c\u5bfc\u81f4\u533a\u5206\u9ad8\u5956\u52b1\u548c\u4f4e\u5956\u52b1\u54cd\u5e94\u7684\u80fd\u529b\u964d\u4f4e\u3002</li>\n    <li>\u6211\u4eec\u63d0\u51fa\u4e86DelTA\u65b9\u6cd5\uff0c\u901a\u8fc7\u91cd\u65b0\u52a0\u6743\u6807\u8bb0\u68af\u5ea6\u65b9\u5411\uff0c\u6539\u5584\u4e86RLVR\u7684\u66f4\u65b0\u65b9\u5411\uff0c\u5e76\u5728\u591a\u4e2a\u57fa\u51c6\u6d4b\u8bd5\u4e2d\u663e\u793a\u51fa\u4f18\u8d8a\u6027\u80fd\u3002</li>\n</ul>", "summary_simple": "<ul>\n    <li>Reinforcement learning from verifiable rewards (RLVR) helps improve how large language models understand and reason.</li>\n    <li>The way rewards at the response level affect individual tokens is not well understood.</li>\n    <li>A new method called DelTA has been introduced to improve how token probabilities are adjusted during learning.</li>\n    <li>DelTA focuses on amplifying important token directions and reducing the influence of common patterns that don't help distinguish between good and bad responses.</li>\n    <li>Tests show that DelTA performs better than existing methods on various tasks, including math problems and code generation.</li>\n</ul>"}, "publishedAt": "2026-05-19T20:00:00.000Z", "title": "DelTA: Discriminative Token Credit Assignment for Reinforcement Learning from Verifiable Rewards", "summary": "Reinforcement learning from verifiable rewards (RLVR) has emerged as a central technique for improving the reasoning capabilities of large language models. Despite its effectiveness, how response-level rewards translate into token-level probability changes remains poorly understood. We introduce a discriminator view of RLVR updates, showing that the policy-gradient update direction implicitly acts as a linear discriminator over token-gradient vectors and thereby determines which token probabilities are increased or decreased during learning. Under standard sequence-level RLVR, this discriminator is constructed from positive- and negative-side centroids formed by advantage-weighted averaging of token-gradient vectors. However, such centroid construction can be dominated by shared high-frequency patterns, such as formatting tokens, diluting sparse yet discriminative directions that better distinguish high-reward responses from low-reward ones. To address this limitation, we propose DelTA, a discriminative token credit assignment method that estimates token coefficients to amplify side-specific token-gradient directions and downweight shared or weakly discriminative ones. These coefficients reweight a self-normalized RLVR surrogate, making the effective side-wise centroids more contrastive and thereby reshaping the RLVR update direction. On seven mathematical benchmarks, DelTA outperforms the strongest same-scale baselines by 3.26 and 2.62 average points on Qwen3-8B-Base and Qwen3-14B-Base, respectively. Additional results on code generation, a different backbone, and out-of-domain evaluations further demonstrate the generalization ability of DelTA.", "thumbnail": "https://cdn-thumbnails.huggingface.co/social-thumbnails/papers/2605.21467.png", "numComments": 1, "submittedBy": {"_id": "6523afa7389ef6864de004a1", "avatarUrl": "/avatars/cdf04857038a7c8abadd2e2306835ebe.svg", "fullname": "KaiyiZhang", "name": "Cardlnal", "type": "user", "isPro": false, "isHf": false, "isHfAdmin": false, "isMod": false, "followerCount": 4, "isUserFollowing": false}, "isAuthorParticipating": true}, {"paper": {"id": "2605.18401", "authors": [{"_id": "6a0bffbf8ca2d0b256380589", "user": {"_id": "66d12f904cc92b9866c7f837", "avatarUrl": "/avatars/5c3ce46c1f953a7081e344cd91a8d17b.svg", "isPro": false, "fullname": "Hongyi Liu", "user": "hongyi-liu", "type": "user", "name": "hongyi-liu"}, "name": "Hongyi Liu", "status": "claimed_verified", "statusLastChangedAt": "2026-05-19T08:30:53.912Z", "hidden": false}, {"_id": "6a0bffbf8ca2d0b25638058a", "user": {"_id": "678e34a809dc6d3a3125a8ca", "avatarUrl": "/avatars/02c5c4ec23a408d9762bf4dff0176da9.svg", "isPro": false, "fullname": "Yanghaoyan", "user": "Ch1ldKing", "type": "user", "name": "Ch1ldKing"}, "name": "Haoyan Yang", "status": "claimed_verified", "statusLastChangedAt": "2026-05-19T08:30:51.850Z", "hidden": false}, {"_id": "6a0bffbf8ca2d0b25638058b", "name": "Tao Jiang", "hidden": false}, {"_id": "6a0bffbf8ca2d0b25638058c", "name": "Bo Tang", "hidden": false}, {"_id": "6a0bffbf8ca2d0b25638058d", "name": "Feiyu Xiong", "hidden": false}, {"_id": "6a0bffbf8ca2d0b25638058e", "name": "Zhiyu Li", "hidden": false}], "publishedAt": "2026-05-18T00:00:00.000Z", "submittedOnDailyAt": "2026-05-19T00:00:00.000Z", "title": "SkillsVote: Lifecycle Governance of Agent Skills from Collection, Recommendation to Evolution", "submittedOnDailyBy": {"_id": "66d12f904cc92b9866c7f837", "avatarUrl": "/avatars/5c3ce46c1f953a7081e344cd91a8d17b.svg", "isPro": false, "fullname": "Hongyi Liu", "user": "hongyi-liu", "type": "user", "name": "hongyi-liu"}, "summary": "Long-horizon LLM agents leave traces that could become reusable experience, but raw trajectories are noisy and hard to govern. We treat Agent Skills as an experience schema that couples executable scripts, with non-executable guidance on procedures. Yet open skill ecosystems contain redundant, uneven, environment-sensitive artifacts, and indiscriminate updates can pollute future context. We present SkillsVote, a lifecycle-governance framework for Agent Skills from collection and recommendation to evolution. SkillsVote profiles a million-scale open-source corpus for environment requirements, quality, and verifiability, then synthesizes tasks for verifiable skills. Before execution, SkillsVote performs agentic library search over structured skill library to expose instructional skill context. After execution, it decomposes trajectories into skill-linked subtasks, attributes outcomes to skill use, agent exploration, environment, and result signals, and admits only successful reusable discoveries to evidence-gated updates. In our evaluation, offline evolution improves GPT-5.2 on Terminal-Bench 2.0 by up to 7.9 pp, while online evolution improves SWE-Bench Pro by up to 2.6 pp. Overall, governed external skill libraries can improve frozen agents without model updates when systems control exposure, credit, and preservation.", "upvotes": 111, "discussionId": "6a0bffbf8ca2d0b25638058f", "projectPage": "https://skills.vote", "githubRepo": "https://github.com/MemTensor/skills-vote", "githubRepoAddedBy": "user", "ai_summary": "SkillsVote is a governance framework for long-horizon LLM agents that manages reusable skills through structured collection, recommendation, and evolution processes.", "ai_keywords": ["Agent Skills", "experience schema", "executable scripts", "skill ecosystems", "lifecycle-governance framework", "environment requirements", "verifiability", "agentic library search", "trajectory decomposition", "evidence-gated updates", "Terminal-Bench 2.0", "SWE-Bench Pro"], "githubStars": 219, "organization": {"_id": "658bf18c135580745c529d53", "name": "IAAR-Shanghai", "fullname": "Memtensor Research Group", "avatar": "https://cdn-avatars.huggingface.co/v1/production/uploads/62a155e615eeab266b2f2243/ONfcDR9Ox8AVtXtrAR4FG.png"}, "summary_zh": "<ul>\n    <li>\u957f\u65f6\u95f4\u8fd0\u884c\u7684LLM\u4ee3\u7406\u4f1a\u7559\u4e0b\u53ef\u91cd\u7528\u7684\u7ecf\u9a8c\uff0c\u4f46\u539f\u59cb\u8f68\u8ff9\u5608\u6742\u4e14\u96be\u4ee5\u7ba1\u7406\u3002</li>\n    <li>\u6211\u4eec\u5c06\u4ee3\u7406\u6280\u80fd\u89c6\u4e3a\u4e00\u79cd\u7ecf\u9a8c\u6a21\u5f0f\uff0c\u7ed3\u5408\u53ef\u6267\u884c\u811a\u672c\u548c\u4e0d\u53ef\u6267\u884c\u7684\u7a0b\u5e8f\u6307\u5bfc\u3002</li>\n    <li>\u6280\u80fd\u751f\u6001\u7cfb\u7edf\u4e2d\u5b58\u5728\u5197\u4f59\u548c\u4e0d\u5747\u5300\u7684\u73af\u5883\u654f\u611f\u6027\uff0c\u968f\u610f\u66f4\u65b0\u53ef\u80fd\u4f1a\u6c61\u67d3\u672a\u6765\u7684\u4e0a\u4e0b\u6587\u3002</li>\n    <li>\u6211\u4eec\u63d0\u51fa\u4e86SkillsVote\uff0c\u5b83\u662f\u4e00\u4e2a\u751f\u547d\u5468\u671f\u7ba1\u7406\u6846\u67b6\uff0c\u7528\u4e8e\u4ee3\u7406\u6280\u80fd\u7684\u6536\u96c6\u3001\u63a8\u8350\u548c\u6f14\u53d8\u3002</li>\n    <li>\u8bc4\u4f30\u7ed3\u679c\u663e\u793a\uff0c\u7ecf\u8fc7\u7ba1\u7406\u7684\u5916\u90e8\u6280\u80fd\u5e93\u53ef\u4ee5\u5728\u4e0d\u66f4\u65b0\u6a21\u578b\u7684\u60c5\u51b5\u4e0b\u6539\u5584\u51bb\u7ed3\u7684\u4ee3\u7406\u8868\u73b0\u3002</li>\n</ul>", "summary_simple": "<ul>\n    <li>Long-horizon LLM agents leave useful traces, but the data can be messy and hard to manage.</li>\n    <li>We introduce SkillsVote, a framework that helps manage these traces by organizing skills and their usage.</li>\n    <li>SkillsVote analyzes a large collection of skills for quality and relevance, ensuring only useful skills are recommended and evolved.</li>\n    <li>It breaks down agent actions into smaller tasks and tracks outcomes to improve future skill use.</li>\n    <li>Our tests show that using SkillsVote can significantly enhance the performance of agents without needing to update the underlying models.</li>\n</ul>"}, "publishedAt": "2026-05-17T20:00:00.000Z", "title": "SkillsVote: Lifecycle Governance of Agent Skills from Collection, Recommendation to Evolution", "summary": "Long-horizon LLM agents leave traces that could become reusable experience, but raw trajectories are noisy and hard to govern. We treat Agent Skills as an experience schema that couples executable scripts, with non-executable guidance on procedures. Yet open skill ecosystems contain redundant, uneven, environment-sensitive artifacts, and indiscriminate updates can pollute future context. We present SkillsVote, a lifecycle-governance framework for Agent Skills from collection and recommendation to evolution. SkillsVote profiles a million-scale open-source corpus for environment requirements, quality, and verifiability, then synthesizes tasks for verifiable skills. Before execution, SkillsVote performs agentic library search over structured skill library to expose instructional skill context. After execution, it decomposes trajectories into skill-linked subtasks, attributes outcomes to skill use, agent exploration, environment, and result signals, and admits only successful reusable discoveries to evidence-gated updates. In our evaluation, offline evolution improves GPT-5.2 on Terminal-Bench 2.0 by up to 7.9 pp, while online evolution improves SWE-Bench Pro by up to 2.6 pp. Overall, governed external skill libraries can improve frozen agents without model updates when systems control exposure, credit, and preservation.", "thumbnail": "https://cdn-thumbnails.huggingface.co/social-thumbnails/papers/2605.18401.png", "numComments": 1, "submittedBy": {"_id": "66d12f904cc92b9866c7f837", "avatarUrl": "/avatars/5c3ce46c1f953a7081e344cd91a8d17b.svg", "fullname": "Hongyi Liu", "name": "hongyi-liu", "type": "user", "isPro": false, "isHf": false, "isHfAdmin": false, "isMod": false, "isUserFollowing": false}, "organization": {"_id": "658bf18c135580745c529d53", "name": "IAAR-Shanghai", "fullname": "Memtensor Research Group", "avatar": "https://cdn-avatars.huggingface.co/v1/production/uploads/62a155e615eeab266b2f2243/ONfcDR9Ox8AVtXtrAR4FG.png"}, "isAuthorParticipating": true}, {"paper": {"id": "2605.19833", "authors": [{"_id": "6a0df8e4d1ef9ecdf71c0e9d", "user": {"_id": "678f850bec882f210c1b59f2", "avatarUrl": "/avatars/f25bab4afb86de92f75bf9a90e02f59f.svg", "isPro": false, "fullname": "XIE ZHIFEI", "user": "zhifeixie", "type": "user", "name": "zhifeixie"}, "name": "Zhifei Xie", "status": "admin_assigned", "statusLastChangedAt": "2026-05-21T13:39:13.670Z", "hidden": false}, {"_id": "6a0df8e4d1ef9ecdf71c0e9e", "name": "Kaiyu Pang", "hidden": false}, {"_id": "6a0df8e4d1ef9ecdf71c0e9f", "name": "Haobin Zhang", "hidden": false}, {"_id": "6a0df8e4d1ef9ecdf71c0ea0", "name": "Deheng Ye", "hidden": false}, {"_id": "6a0df8e4d1ef9ecdf71c0ea1", "name": "Xiaobin Hu", "hidden": false}, {"_id": "6a0df8e4d1ef9ecdf71c0ea2", "name": "Shuicheng Yan", "hidden": false}, {"_id": "6a0df8e4d1ef9ecdf71c0ea3", "name": "Chunyan Miao", "hidden": false}], "mediaUrls": ["https://cdn-uploads.huggingface.co/production/uploads/66c5d81a4061fd5907443787/z0m7qDFg_25I0H1Ttgo16.jpeg"], "publishedAt": "2026-05-19T00:00:00.000Z", "submittedOnDailyAt": "2026-05-21T00:00:00.000Z", "title": "Mega-ASR: Towards In-the-wild^2 Speech Recognition via Scaling up Real-world Acoustic Simulation", "submittedOnDailyBy": {"_id": "66c5d81a4061fd5907443787", "avatarUrl": "/avatars/2e107195b1ff7d06bbc6c9bd4e5620cf.svg", "isPro": false, "fullname": "zhifei", "user": "filicos", "type": "user", "name": "filicos"}, "summary": "Despite rapid advances in automatic speech recognition (ASR) and large audio-language models, robust recognition in real-world environments remains limited by an \"acoustic robustness bottleneck\": models often lose acoustic grounding and produce omissions or hallucinations under severe, compositional distortions. We propose Mega-ASR, a unified ASR-in-the-wild framework that combines scalable compound-data construction with progressive acoustic-to-semantic optimization. We introduce Voices-in-the-Wild-2M, covering 7 classic acoustic phenomena and 54 physically plausible compound scenarios, and train Mega-ASR with Acoustic-to-Semantic Progressive Supervised Fine-Tuning and Dual-Granularity WER-Gated Policy Optimization. Extensive experiments demonstrate that Mega-ASR achieves significant advantages over prior state-of-the-art systems on adverse-condition ASR benchmarks (45.69% vs. 54.01% on VOiCES R4-B-F, and 21.49% vs. 29.34% on NOIZEUS Sta-0). On complex compositional acoustic scenarios, Mega-ASR further delivers over 30% relative WER reduction against strong open- and closed-source baselines, establishing a scalable paradigm for robust ASR in-the-wild.", "upvotes": 111, "discussionId": "6a0df8e4d1ef9ecdf71c0ea4", "projectPage": "https://xzf-thu.github.io/Mega-ASR/", "githubRepo": "https://github.com/xzf-thu/Mega-ASR", "githubRepoAddedBy": "user", "ai_summary": "Mega-ASR framework improves robustness in real-world speech recognition through compound-data construction and progressive acoustic-to-semantic optimization techniques.", "ai_keywords": ["automatic speech recognition", "acoustic robustness bottleneck", "compound-data construction", "progressive acoustic-to-semantic optimization", "Acoustic-to-Semantic Progressive Supervised Fine-Tuning", "Dual-Granularity WER-Gated Policy Optimization", "VOiCES R4-B-F", "NOIZEUS Sta-0", "WER reduction"], "githubStars": 100, "organization": {"_id": "6508ab2b349930913196378b", "name": "NationalUniversityofSingapore", "fullname": "National University of Singapore", "avatar": "https://cdn-avatars.huggingface.co/v1/production/uploads/630ca0817dacb93b33506ce7/ZYUmpSMsa5Whihw3me2Bw.png"}, "summary_zh": "<ul>\n    <li>\u5c3d\u7ba1\u81ea\u52a8\u8bed\u97f3\u8bc6\u522b\uff08ASR\uff09\u548c\u5927\u578b\u97f3\u9891\u8bed\u8a00\u6a21\u578b\u5df2\u6709\u5feb\u901f\u8fdb\u5c55\uff0c\u4f46\u5728\u590d\u6742\u771f\u5b9e\u73af\u5883\u4e2d\u7684\u8bc6\u522b\u4ecd\u7136\u5b58\u5728\u56f0\u96be\u3002</li>\n    <li>\u63d0\u51fa\u4e86Mega-ASR\u6846\u67b6\uff0c\u7ed3\u5408\u53ef\u6269\u5c55\u7684\u6570\u636e\u6784\u5efa\u548c\u6e10\u8fdb\u7684\u58f0\u5b66\u5230\u8bed\u4e49\u4f18\u5316\u3002</li>\n    <li>\u5f15\u5165\u4e86Voices-in-the-Wild-2M\u6570\u636e\u96c6\uff0c\u6db5\u76d67\u79cd\u7ecf\u5178\u58f0\u5b66\u73b0\u8c61\u548c54\u79cd\u7269\u7406\u4e0a\u5408\u7406\u7684\u590d\u5408\u573a\u666f\u3002</li>\n    <li>Mega-ASR\u5728\u6076\u52a3\u6761\u4ef6\u4e0b\u7684ASR\u57fa\u51c6\u6d4b\u8bd5\u4e2d\u8868\u73b0\u4f18\u5f02\uff0c\u663e\u8457\u8d85\u8fc7\u4e86\u4e4b\u524d\u7684\u6700\u5148\u8fdb\u7cfb\u7edf\u3002</li>\n    <li>\u5728\u590d\u6742\u7684\u58f0\u5b66\u573a\u666f\u4e2d\uff0cMega-ASR\u5b9e\u73b0\u4e86\u8d85\u8fc730%\u7684\u5b57\u9519\u8bef\u7387\uff08WER\uff09\u76f8\u5bf9\u51cf\u5c11\uff0c\u5efa\u7acb\u4e86\u5f3a\u5927\u7684ASR\u65b0\u8303\u5f0f\u3002</li>\n</ul>", "summary_simple": "<ul>\n    <li>Current speech recognition technology struggles in tough, real-world conditions due to limitations in understanding sound correctly.</li>\n    <li>Mega-ASR is a new system designed to improve speech recognition by using a large dataset and advanced training methods.</li>\n    <li>The system is trained with a unique dataset called Voices-in-the-Wild-2M, which includes various sound challenges and realistic scenarios.</li>\n    <li>Tests show Mega-ASR performs better than existing systems, achieving higher accuracy in difficult acoustic situations.</li>\n    <li>It reduces errors significantly in complex sound environments, providing a more reliable solution for speech recognition in real-world settings.</li>\n</ul>"}, "publishedAt": "2026-05-18T20:00:00.000Z", "title": "Mega-ASR: Towards In-the-wild^2 Speech Recognition via Scaling up Real-world Acoustic Simulation", "summary": "Despite rapid advances in automatic speech recognition (ASR) and large audio-language models, robust recognition in real-world environments remains limited by an \"acoustic robustness bottleneck\": models often lose acoustic grounding and produce omissions or hallucinations under severe, compositional distortions. We propose Mega-ASR, a unified ASR-in-the-wild framework that combines scalable compound-data construction with progressive acoustic-to-semantic optimization. We introduce Voices-in-the-Wild-2M, covering 7 classic acoustic phenomena and 54 physically plausible compound scenarios, and train Mega-ASR with Acoustic-to-Semantic Progressive Supervised Fine-Tuning and Dual-Granularity WER-Gated Policy Optimization. Extensive experiments demonstrate that Mega-ASR achieves significant advantages over prior state-of-the-art systems on adverse-condition ASR benchmarks (45.69% vs. 54.01% on VOiCES R4-B-F, and 21.49% vs. 29.34% on NOIZEUS Sta-0). On complex compositional acoustic scenarios, Mega-ASR further delivers over 30% relative WER reduction against strong open- and closed-source baselines, establishing a scalable paradigm for robust ASR in-the-wild.", "mediaUrls": ["https://cdn-uploads.huggingface.co/production/uploads/66c5d81a4061fd5907443787/z0m7qDFg_25I0H1Ttgo16.jpeg"], "thumbnail": "https://cdn-thumbnails.huggingface.co/social-thumbnails/papers/2605.19833.png", "numComments": 2, "submittedBy": {"_id": "66c5d81a4061fd5907443787", "avatarUrl": "/avatars/2e107195b1ff7d06bbc6c9bd4e5620cf.svg", "fullname": "zhifei", "name": "filicos", "type": "user", "isPro": false, "isHf": false, "isHfAdmin": false, "isMod": false, "followerCount": 2, "isUserFollowing": false}, "organization": {"_id": "6508ab2b349930913196378b", "name": "NationalUniversityofSingapore", "fullname": "National University of Singapore", "avatar": "https://cdn-avatars.huggingface.co/v1/production/uploads/630ca0817dacb93b33506ce7/ZYUmpSMsa5Whihw3me2Bw.png"}, "isAuthorParticipating": false}, {"paper": {"id": "2605.18739", "authors": [{"_id": "6a0bccfd8ca2d0b25638035f", "name": "Yukang Chen", "hidden": false}, {"_id": "6a0bccfd8ca2d0b256380360", "name": "Luozhou Wang", "hidden": false}, {"_id": "6a0bccfd8ca2d0b256380361", "name": "Wei Huang", "hidden": false}, {"_id": "6a0bccfd8ca2d0b256380362", "name": "Shuai Yang", "hidden": false}, {"_id": "6a0bccfd8ca2d0b256380363", "name": "Bohan Zhang", "hidden": false}, {"_id": "6a0bccfd8ca2d0b256380364", "name": "Yicheng Xiao", "hidden": false}, {"_id": "6a0bccfd8ca2d0b256380365", "user": {"_id": "642e3bcb958faf258a40e89c", "avatarUrl": "/avatars/dad142df2217f8eed1f45c9e7287d3ea.svg", "isPro": false, "fullname": "Ruihang Chu", "user": "Ruihang", "type": "user", "name": "Ruihang"}, "name": "Ruihang Chu", "status": "claimed_verified", "statusLastChangedAt": "2026-05-19T08:32:09.924Z", "hidden": false}, {"_id": "6a0bccfd8ca2d0b256380366", "name": "Weian Mao", "hidden": false}, {"_id": "6a0bccfd8ca2d0b256380367", "name": "Qixin Hu", "hidden": false}, {"_id": "6a0bccfd8ca2d0b256380368", "name": "Shaoteng Liu", "hidden": false}, {"_id": "6a0bccfd8ca2d0b256380369", "name": "Yuyang Zhao", "hidden": false}, {"_id": "6a0bccfd8ca2d0b25638036a", "name": "Huizi Mao", "hidden": false}, {"_id": "6a0bccfd8ca2d0b25638036b", "name": "Ying-Cong Chen", "hidden": false}, {"_id": "6a0bccfd8ca2d0b25638036c", "name": "Enze Xie", "hidden": false}, {"_id": "6a0bccfd8ca2d0b25638036d", "name": "Xiaojuan Qi", "hidden": false}, {"_id": "6a0bccfd8ca2d0b25638036e", "name": "Song Han", "hidden": false}], "mediaUrls": ["https://cdn-uploads.huggingface.co/production/uploads/656db3f53dc1d277e5a64410/OzJh3crGlolLQVniGo4zz.qt"], "publishedAt": "2026-05-18T00:00:00.000Z", "submittedOnDailyAt": "2026-05-19T00:00:00.000Z", "title": "LongLive-2.0: An NVFP4 Parallel Infrastructure for Long Video Generation", "submittedOnDailyBy": {"_id": "656db3f53dc1d277e5a64410", "avatarUrl": "https://cdn-avatars.huggingface.co/v1/production/uploads/656db3f53dc1d277e5a64410/9kiY2K3MCRcBDk7MrkTBK.png", "isPro": false, "fullname": "Wei Huang", "user": "AaronHuangWei", "type": "user", "name": "AaronHuangWei"}, "summary": "We present LongLive-2.0, an NVFP4-based parallel infrastructure throughout the full training and inference workflow of long video generation, addressing speed and memory bottlenecks. For training, we introduce sequence-parallel autoregressive (AR) training, instantiated as Balanced SP, which co-designs the efficient teacher-forcing layout with SP execution by pairing clean-history and noisy-target temporal chunks on each rank, enabling a natural teacher-forcing mask with SP-aware chunked VAE encoding. Combined with NVFP4 precision, it reduces GPU memory cost and accelerates GEMM computation during training, the proportion of which increases as video length grows. Moreover, we show that a high-quality infrastructure and dataset enable a remarkably clean training pipeline. Unlike existing Self-Forcing series methods that rely on ODE initialization and subsequent distribution matching distillation (DMD), LongLive-2.0 directly tunes a diffusion model into a long, multi-shot, interactive auto-regressive (AR) diffusion model. It can be further converted to real-time generation (4 to 2 denoising steps) with standalone LoRA weights. For inference on Blackwell GPUs, we enable W4A4 NVFP4 inference, quantize KV cache into NVFP4 for memory savings, and boost end-to-end throughput with asynchronous streaming VAE decoding. On non-Blackwell GPU architectures, we deploy SP inference to match the speed on Blackwell GPUs, while the quantized KV cache can lower inter-GPU communication of SP. Experiments show up to 2.15x speedup in training, and 1.84x in inference. LongLive-2.0-5B achieves 45.7 FPS inference while attaining strong performance on benchmarks. To our knowledge, LongLive-2.0 is the first NVFP4 training and inference system for long video generation.", "upvotes": 90, "discussionId": "6a0bccfd8ca2d0b25638036f", "projectPage": "https://nvlabs.github.io/LongLive/LongLive2/", "githubRepo": "https://github.com/NVlabs/LongLive", "githubRepoAddedBy": "user", "ai_summary": "LongLive-2.0 presents an NVFP4-based parallel infrastructure for long video generation that addresses training and inference bottlenecks through sequence-parallel autoregressive training and diffusion model tuning.", "ai_keywords": ["NVFP4", "sequence-parallel autoregressive training", "Balanced SP", "teacher-forcing layout", "VAE encoding", "diffusion model", "auto-regressive diffusion model", "LoRA weights", "W4A4", "KV cache quantization", "asynchronous streaming VAE decoding", "Blackwell GPUs", "inter-GPU communication"], "githubStars": 1294, "organization": {"_id": "60262b67268c201cdc8b7d43", "name": "nvidia", "fullname": "NVIDIA", "avatar": "https://cdn-avatars.huggingface.co/v1/production/uploads/65df9200dc3292a8983e5017/Vs5FPVCH-VZBipV3qKTuy.png"}, "summary_zh": "<ul>\n    <li>LongLive-2.0 \u662f\u4e00\u4e2a\u57fa\u4e8e NVFP4 \u7684\u5e76\u884c\u57fa\u7840\u8bbe\u65bd\uff0c\u7528\u4e8e\u957f\u89c6\u9891\u751f\u6210\u7684\u8bad\u7ec3\u548c\u63a8\u7406\uff0c\u89e3\u51b3\u4e86\u901f\u5ea6\u548c\u5185\u5b58\u74f6\u9888\u3002</li>\n    <li>\u5f15\u5165\u4e86\u5e73\u8861\u5e8f\u5217\u5e76\u884c\u81ea\u56de\u5f52\u8bad\u7ec3\uff0c\u4f18\u5316\u4e86\u6559\u5e08\u5f3a\u5236\u5e03\u5c40\u548c\u6267\u884c\uff0c\u63d0\u9ad8\u4e86\u8bad\u7ec3\u7684\u6548\u7387\uff0c\u51cf\u5c11\u4e86 GPU \u5185\u5b58\u6d88\u8017\u3002</li>\n    <li>LongLive-2.0 \u76f4\u63a5\u5c06\u6269\u6563\u6a21\u578b\u8c03\u6574\u4e3a\u957f\u65f6\u95f4\u3001\u591a\u955c\u5934\u7684\u81ea\u56de\u5f52\u6269\u6563\u6a21\u578b\uff0c\u652f\u6301\u5b9e\u65f6\u751f\u6210\u3002</li>\n    <li>\u5728 Blackwell GPU \u4e0a\u5b9e\u73b0\u4e86\u9ad8\u6548\u63a8\u7406\uff0c\u91c7\u7528\u4e86\u91cf\u5316 KV \u7f13\u5b58\u548c\u5f02\u6b65\u6d41\u5f0f VAE \u89e3\u7801\uff0c\u63d0\u5347\u4e86\u541e\u5410\u91cf\u3002</li>\n    <li>\u5b9e\u9a8c\u663e\u793a\u8bad\u7ec3\u901f\u5ea6\u63d0\u5347\u4e86 2.15 \u500d\uff0c\u63a8\u7406\u901f\u5ea6\u63d0\u5347\u4e86 1.84 \u500d\uff0cLongLive-2.0-5B \u5728\u57fa\u51c6\u6d4b\u8bd5\u4e2d\u8868\u73b0\u4f18\u5f02\uff0c\u8fbe\u5230 45.7 FPS \u7684\u63a8\u7406\u901f\u5ea6\u3002</li>\n</ul>", "summary_simple": "<ul>\n    <li>LongLive-2.0 is a new system designed to improve the speed and memory usage in generating long videos.</li>\n    <li>It uses a special training method called sequence-parallel autoregressive training to make the process more efficient.</li>\n    <li>The system reduces memory costs and speeds up calculations during training, especially for longer videos.</li>\n    <li>For inference, it features optimizations for different GPU architectures to enhance performance and save memory.</li>\n    <li>Experiments show significant speed improvements in both training (up to 2.15x faster) and inference (up to 1.84x faster), achieving 45.7 frames per second during inference.</li>\n</ul>"}, "publishedAt": "2026-05-17T20:00:00.000Z", "title": "LongLive-2.0: An NVFP4 Parallel Infrastructure for Long Video Generation", "summary": "We present LongLive-2.0, an NVFP4-based parallel infrastructure throughout the full training and inference workflow of long video generation, addressing speed and memory bottlenecks. For training, we introduce sequence-parallel autoregressive (AR) training, instantiated as Balanced SP, which co-designs the efficient teacher-forcing layout with SP execution by pairing clean-history and noisy-target temporal chunks on each rank, enabling a natural teacher-forcing mask with SP-aware chunked VAE encoding. Combined with NVFP4 precision, it reduces GPU memory cost and accelerates GEMM computation during training, the proportion of which increases as video length grows. Moreover, we show that a high-quality infrastructure and dataset enable a remarkably clean training pipeline. Unlike existing Self-Forcing series methods that rely on ODE initialization and subsequent distribution matching distillation (DMD), LongLive-2.0 directly tunes a diffusion model into a long, multi-shot, interactive auto-regressive (AR) diffusion model. It can be further converted to real-time generation (4 to 2 denoising steps) with standalone LoRA weights. For inference on Blackwell GPUs, we enable W4A4 NVFP4 inference, quantize KV cache into NVFP4 for memory savings, and boost end-to-end throughput with asynchronous streaming VAE decoding. On non-Blackwell GPU architectures, we deploy SP inference to match the speed on Blackwell GPUs, while the quantized KV cache can lower inter-GPU communication of SP. Experiments show up to 2.15x speedup in training, and 1.84x in inference. LongLive-2.0-5B achieves 45.7 FPS inference while attaining strong performance on benchmarks. To our knowledge, LongLive-2.0 is the first NVFP4 training and inference system for long video generation.", "mediaUrls": ["https://cdn-uploads.huggingface.co/production/uploads/656db3f53dc1d277e5a64410/OzJh3crGlolLQVniGo4zz.qt"], "thumbnail": "https://cdn-thumbnails.huggingface.co/social-thumbnails/papers/2605.18739.png", "numComments": 1, "submittedBy": {"_id": "656db3f53dc1d277e5a64410", "avatarUrl": "https://cdn-avatars.huggingface.co/v1/production/uploads/656db3f53dc1d277e5a64410/9kiY2K3MCRcBDk7MrkTBK.png", "fullname": "Wei Huang", "name": "AaronHuangWei", "type": "user", "isPro": false, "isHf": false, "isHfAdmin": false, "isMod": false, "followerCount": 15, "isUserFollowing": false}, "organization": {"_id": "60262b67268c201cdc8b7d43", "name": "nvidia", "fullname": "NVIDIA", "avatar": "https://cdn-avatars.huggingface.co/v1/production/uploads/65df9200dc3292a8983e5017/Vs5FPVCH-VZBipV3qKTuy.png"}, "isAuthorParticipating": false}, {"paper": {"id": "2605.18233", "authors": [{"_id": "6a0ed65533b630fff3b43c15", "name": "X. Feng", "hidden": false}, {"_id": "6a0ed65533b630fff3b43c16", "name": "J. Zhu", "hidden": false}, {"_id": "6a0ed65533b630fff3b43c17", "name": "M. Wu", "hidden": false}, {"_id": "6a0ed65533b630fff3b43c18", "name": "C. Chen", "hidden": false}, {"_id": "6a0ed65533b630fff3b43c19", "name": "F. Mao", "hidden": false}, {"_id": "6a0ed65533b630fff3b43c1a", "name": "H. Guo", "hidden": false}, {"_id": "6a0ed65533b630fff3b43c1b", "name": "J. Wu", "hidden": false}, {"_id": "6a0ed65533b630fff3b43c1c", "name": "X. Chu", "hidden": false}, {"_id": "6a0ed65533b630fff3b43c1d", "name": "K. Huang", "hidden": false}], "mediaUrls": ["https://cdn-uploads.huggingface.co/production/uploads/66d255e3947594430c723ff6/bSIgHEPP94mwhttRdMKpf.mp4"], "publishedAt": "2026-05-18T00:00:00.000Z", "submittedOnDailyAt": "2026-05-21T00:00:00.000Z", "title": "Enhancing Train-Free Infinite-Frame Generation for Consistent Long Videos", "submittedOnDailyBy": {"_id": "66d255e3947594430c723ff6", "avatarUrl": "/avatars/c56e4792332a01bf34085a75ee64916e.svg", "isPro": false, "fullname": "xiaochonglinghu", "user": "xiaochonglinghu", "type": "user", "name": "xiaochonglinghu"}, "summary": "Without incurring significant computational overhead, train-free long video generation aims to enable foundation video generation models to produce longer videos. Frame-level autoregressive frameworks, e.g., FIFO-diffusion, offer the advantage of generating infinitely long videos with constant memory consumption. However, the mismatch between training and inference, coupled with the challenge of maintaining long-term consistency, limits the effective utilization of foundation models. To mitigate these concerns, we propose MIGA, a novel infinite-frame long video generation method. Firstly, we propose an effective two-stage alignment mechanism that mitigates the training-inference gap by reducing the excessive noise span fed to the model. We then introduce an innovative dual consistency enhancement mechanism, where the self-reflection approach corrects early high-noise frames and the long-range frame guidance approach leverages later low-noise frames with broad coverage to steer generation, jointly improving temporal consistency. Extensive experiments on VBench and NarrLV demonstrate the state-of-the-art performance of MIGA. Our project page is available at https://xiaokunfeng.github.io/miga_homepage/.", "upvotes": 81, "discussionId": "6a0ed65633b630fff3b43c1e", "projectPage": "https://xiaokunfeng.github.io/miga_homepage/", "ai_summary": "MIGA addresses long video generation challenges by reducing training-inference gaps and enhancing temporal consistency through dual consistency mechanisms.", "ai_keywords": ["frame-level autoregressive frameworks", "FIFO-diffusion", "training-inference gap", "noise span", "self-reflection approach", "long-range frame guidance", "temporal consistency"], "organization": {"_id": "64488b334988ee01f2a8d856", "name": "alibaba-inc", "fullname": "alibaba-inc", "avatar": "https://cdn-avatars.huggingface.co/v1/production/uploads/61ac8f8a00d01045fca0ad2f/MX4wxQVaFm1A1wqnrL2WU.jpeg"}, "summary_zh": "<ul>\n    <li>\u63d0\u51fa\u4e86\u4e00\u79cd\u65b0\u7684\u65e0\u9650\u5e27\u957f\u89c6\u9891\u751f\u6210\u65b9\u6cd5MIGA\uff0c\u65e8\u5728\u751f\u6210\u66f4\u957f\u7684\u89c6\u9891\u3002</li>\n    <li>MIGA\u91c7\u7528\u4e86\u4e24\u9636\u6bb5\u5bf9\u9f50\u673a\u5236\uff0c\u51cf\u5c11\u4e86\u8bad\u7ec3\u548c\u63a8\u7406\u4e4b\u95f4\u7684\u5dee\u8ddd\u3002</li>\n    <li>\u5f15\u5165\u4e86\u53cc\u91cd\u4e00\u81f4\u6027\u589e\u5f3a\u673a\u5236\uff0c\u6539\u5584\u4e86\u65f6\u95f4\u4e00\u81f4\u6027\u3002</li>\n    <li>\u901a\u8fc7\u5b9e\u9a8c\u8bc1\u660e\uff0cMIGA\u5728VBench\u548cNarrLV\u4e0a\u8868\u73b0\u4f18\u5f02\u3002</li>\n    <li>\u9879\u76ee\u4e3b\u9875\u53ef\u8bbf\u95ee\uff1ahttps://xiaokunfeng.github.io/miga_homepage/\u3002</li>\n</ul>", "summary_simple": "<ul>\n    <li>The goal is to generate long videos without needing extra computational power.</li>\n    <li>MIGA is a new method that improves long video generation using a two-stage process.</li>\n    <li>This method reduces noise during video generation, making the output clearer.</li>\n    <li>MIGA also enhances consistency in videos by correcting noisy frames and using low-noise frames for guidance.</li>\n    <li>Tests show that MIGA performs better than previous methods in video generation.</li>\n</ul>"}, "publishedAt": "2026-05-17T20:00:00.000Z", "title": "Enhancing Train-Free Infinite-Frame Generation for Consistent Long Videos", "summary": "Without incurring significant computational overhead, train-free long video generation aims to enable foundation video generation models to produce longer videos. Frame-level autoregressive frameworks, e.g., FIFO-diffusion, offer the advantage of generating infinitely long videos with constant memory consumption. However, the mismatch between training and inference, coupled with the challenge of maintaining long-term consistency, limits the effective utilization of foundation models. To mitigate these concerns, we propose MIGA, a novel infinite-frame long video generation method. Firstly, we propose an effective two-stage alignment mechanism that mitigates the training-inference gap by reducing the excessive noise span fed to the model. We then introduce an innovative dual consistency enhancement mechanism, where the self-reflection approach corrects early high-noise frames and the long-range frame guidance approach leverages later low-noise frames with broad coverage to steer generation, jointly improving temporal consistency. Extensive experiments on VBench and NarrLV demonstrate the state-of-the-art performance of MIGA. Our project page is available at https://xiaokunfeng.github.io/miga_homepage/.", "mediaUrls": ["https://cdn-uploads.huggingface.co/production/uploads/66d255e3947594430c723ff6/bSIgHEPP94mwhttRdMKpf.mp4"], "thumbnail": "https://cdn-thumbnails.huggingface.co/social-thumbnails/papers/2605.18233.png", "numComments": 1, "submittedBy": {"_id": "66d255e3947594430c723ff6", "avatarUrl": "/avatars/c56e4792332a01bf34085a75ee64916e.svg", "fullname": "xiaochonglinghu", "name": "xiaochonglinghu", "type": "user", "isPro": false, "isHf": false, "isHfAdmin": false, "isMod": false, "followerCount": 9, "isUserFollowing": false}, "organization": {"_id": "64488b334988ee01f2a8d856", "name": "alibaba-inc", "fullname": "alibaba-inc", "avatar": "https://cdn-avatars.huggingface.co/v1/production/uploads/61ac8f8a00d01045fca0ad2f/MX4wxQVaFm1A1wqnrL2WU.jpeg"}, "isAuthorParticipating": false}, {"paper": {"id": "2605.14678", "authors": [{"_id": "6a0e7c1a164dbbc68a26c56f", "user": {"_id": "689ec537196ab997b13dc977", "avatarUrl": "https://cdn-avatars.huggingface.co/v1/production/uploads/689ec537196ab997b13dc977/yXA_pd8ndjBIIg1Hx59QJ.png", "isPro": false, "fullname": "Haoran Zhang", "user": "zzzhr97", "type": "user", "name": "zzzhr97"}, "name": "Haoran Zhang", "status": "claimed_verified", "statusLastChangedAt": "2026-05-21T19:22:15.982Z", "hidden": false}, {"_id": "6a0e7c1a164dbbc68a26c570", "name": "Luxin Xu", "hidden": false}, {"_id": "6a0e7c1a164dbbc68a26c571", "name": "Zhilin Wang", "hidden": false}, {"_id": "6a0e7c1a164dbbc68a26c572", "name": "Runquan Gui", "hidden": false}, {"_id": "6a0e7c1a164dbbc68a26c573", "name": "Shunkai Zhang", "hidden": false}, {"_id": "6a0e7c1a164dbbc68a26c574", "name": "Haodi Lei", "hidden": false}, {"_id": "6a0e7c1a164dbbc68a26c575", "name": "Zihao He", "hidden": false}, {"_id": "6a0e7c1a164dbbc68a26c576", "name": "Bingsu He", "hidden": false}, {"_id": "6a0e7c1a164dbbc68a26c577", "name": "Chicheng Qin", "hidden": false}, {"_id": "6a0e7c1a164dbbc68a26c578", "name": "Tong Zhu", "hidden": false}, {"_id": "6a0e7c1a164dbbc68a26c579", "name": "Xiaoye Qu", "hidden": false}, {"_id": "6a0e7c1a164dbbc68a26c57a", "name": "Yang Yang", "hidden": false}, {"_id": "6a0e7c1a164dbbc68a26c57b", "name": "Yu Cheng", "hidden": false}, {"_id": "6a0e7c1a164dbbc68a26c57c", "name": "Yafu Li", "hidden": false}], "publishedAt": "2026-05-19T00:00:00.000Z", "submittedOnDailyAt": "2026-05-22T00:00:00.000Z", "title": "\u03c0-Bench: Evaluating Proactive Personal Assistant Agents in Long-Horizon Workflows", "submittedOnDailyBy": {"_id": "689ec537196ab997b13dc977", "avatarUrl": "https://cdn-avatars.huggingface.co/v1/production/uploads/689ec537196ab997b13dc977/yXA_pd8ndjBIIg1Hx59QJ.png", "isPro": false, "fullname": "Haoran Zhang", "user": "zzzhr97", "type": "user", "name": "zzzhr97"}, "summary": "The rise of personal assistant agents, e.g., OpenClaw, highlights the growing potential of large language models to support users across everyday life and work. A core challenge in these settings is proactive assistance, since users often begin with underspecified requests and leave important needs, constraints, or preferences unstated. However, existing benchmarks rarely evaluate whether agents can identify and act on such hidden intents before they are explicitly stated, especially in sustained multi-turn interactions where user needs emerge gradually. To address this gap, we introduce \u03c0-Bench, a benchmark for proactive assistance comprising 100 multi-turn tasks across 5 domain-specific user personas. By incorporating hidden user intents, inter-task dependencies, and cross-session continuity, \u03c0-Bench evaluates agents' ability to anticipate and address user needs over extended interactions, jointly measuring proactivity and task completion in long-horizon trajectories that better reflect real-world use. Experiments show (1) proactive assistance remains challenging, (2) a clear distinction between task completion and proactivity, and (3) the value of prior interaction for proactive intent resolution in later tasks.", "upvotes": 79, "discussionId": "6a0e7c1a164dbbc68a26c57d", "projectPage": "https://simplified-reasoning.github.io/Pi-Bench", "githubRepo": "https://github.com/Simplified-Reasoning/Pi-Bench", "githubRepoAddedBy": "user", "ai_summary": "Proactive assistance in personal agent systems requires identifying hidden user intents through sustained multi-turn interactions, which current benchmarks fail to adequately evaluate.", "ai_keywords": ["personal assistant agents", "large language models", "proactive assistance", "user intents", "multi-turn interactions", "domain-specific user personas", "long-horizon trajectories", "task completion", "proactivity"], "githubStars": 31, "organization": {"_id": "6a03a74a34f1cffc0570e62d", "name": "Simplified-Reasoning", "fullname": "Simplified Reasoning", "avatar": "https://cdn-avatars.huggingface.co/v1/production/uploads/62495cb96ee7ee6b646db130/S-AqbmitJFm2PxXyZrX7H.jpeg"}, "summary_zh": "<ul>\n    <li>\u4e2a\u4eba\u52a9\u7406\u4ee3\u7406\u7684\u5174\u8d77\u5c55\u793a\u4e86\u5927\u578b\u8bed\u8a00\u6a21\u578b\u5728\u65e5\u5e38\u751f\u6d3b\u548c\u5de5\u4f5c\u4e2d\u7684\u6f5c\u529b\u3002</li>\n    <li>\u73b0\u6709\u7684\u8bc4\u4f30\u6807\u51c6\u5f88\u5c11\u6d4b\u8bd5\u4ee3\u7406\u5728\u7528\u6237\u672a\u660e\u786e\u8868\u8fbe\u9700\u6c42\u65f6\u7684\u4e3b\u52a8\u5e2e\u52a9\u80fd\u529b\u3002</li>\n    <li>\u6211\u4eec\u63d0\u51fa\u4e86\u03c0-Bench\u57fa\u51c6\uff0c\u7528\u4e8e\u8bc4\u4f30\u4e3b\u52a8\u5e2e\u52a9\uff0c\u5305\u542b100\u4e2a\u591a\u8f6e\u5bf9\u8bdd\u4efb\u52a1\u3002</li>\n    <li>\u03c0-Bench\u8003\u8651\u4e86\u9690\u85cf\u7528\u6237\u610f\u56fe\u548c\u4efb\u52a1\u95f4\u7684\u4f9d\u8d56\u6027\uff0c\u8bc4\u4f30\u4ee3\u7406\u5728\u957f\u671f\u4e92\u52a8\u4e2d\u7684\u9884\u89c1\u80fd\u529b\u3002</li>\n    <li>\u5b9e\u9a8c\u8868\u660e\uff0c\u4e3b\u52a8\u5e2e\u52a9\u4ecd\u5177\u6311\u6218\u6027\uff0c\u5e76\u5f3a\u8c03\u4e86\u4efb\u52a1\u5b8c\u6210\u548c\u4e3b\u52a8\u6027\u4e4b\u95f4\u7684\u533a\u522b\u3002</li>\n</ul>", "summary_simple": "<ul>\n    <li>Personal assistant agents like OpenClaw show potential for helping users in daily life and work.</li>\n    <li>Many user requests are vague, making it hard for agents to understand hidden needs.</li>\n    <li>Current tests don't measure how well agents can identify these hidden needs in ongoing conversations.</li>\n    <li>\u03c0-Bench is a new benchmark with 100 tasks designed to evaluate proactive support in various user scenarios.</li>\n    <li>Experiments reveal that proactive assistance is difficult, and prior interactions help agents understand user needs better.</li>\n</ul>"}, "publishedAt": "2026-05-18T20:00:00.000Z", "title": "\u03c0-Bench: Evaluating Proactive Personal Assistant Agents in Long-Horizon Workflows", "summary": "The rise of personal assistant agents, e.g., OpenClaw, highlights the growing potential of large language models to support users across everyday life and work. A core challenge in these settings is proactive assistance, since users often begin with underspecified requests and leave important needs, constraints, or preferences unstated. However, existing benchmarks rarely evaluate whether agents can identify and act on such hidden intents before they are explicitly stated, especially in sustained multi-turn interactions where user needs emerge gradually. To address this gap, we introduce \u03c0-Bench, a benchmark for proactive assistance comprising 100 multi-turn tasks across 5 domain-specific user personas. By incorporating hidden user intents, inter-task dependencies, and cross-session continuity, \u03c0-Bench evaluates agents' ability to anticipate and address user needs over extended interactions, jointly measuring proactivity and task completion in long-horizon trajectories that better reflect real-world use. Experiments show (1) proactive assistance remains challenging, (2) a clear distinction between task completion and proactivity, and (3) the value of prior interaction for proactive intent resolution in later tasks.", "thumbnail": "https://cdn-thumbnails.huggingface.co/social-thumbnails/papers/2605.14678.png", "numComments": 2, "submittedBy": {"_id": "689ec537196ab997b13dc977", "avatarUrl": "https://cdn-avatars.huggingface.co/v1/production/uploads/689ec537196ab997b13dc977/yXA_pd8ndjBIIg1Hx59QJ.png", "fullname": "Haoran Zhang", "name": "zzzhr97", "type": "user", "isPro": false, "isHf": false, "isHfAdmin": false, "isMod": false, "followerCount": 3, "isUserFollowing": false}, "organization": {"_id": "6a03a74a34f1cffc0570e62d", "name": "Simplified-Reasoning", "fullname": "Simplified Reasoning", "avatar": "https://cdn-avatars.huggingface.co/v1/production/uploads/62495cb96ee7ee6b646db130/S-AqbmitJFm2PxXyZrX7H.jpeg"}, "isAuthorParticipating": true}, {"paper": {"id": "2605.18678", "authors": [{"_id": "6a0bd58b8ca2d0b25638042b", "user": {"_id": "66f155d025991d4ac9d4490d", "avatarUrl": "/avatars/ceebf154e9fd20dd6c59b22325c984fd.svg", "isPro": false, "fullname": "Fengyi", "user": "ffy2000", "type": "user", "name": "ffy2000"}, "name": "Fengyi Fu", "status": "claimed_verified", "statusLastChangedAt": "2026-05-19T08:31:25.962Z", "hidden": false}, {"_id": "6a0bd58b8ca2d0b25638042c", "name": "Mengqi Huang", "hidden": false}, {"_id": "6a0bd58b8ca2d0b25638042d", "user": {"_id": "660114b38ae190912a61be5d", "avatarUrl": "/avatars/abc4ab10d6f9769d2b5e697ccbf3fb70.svg", "isPro": false, "fullname": "ShaojinWu", "user": "fenfan", "type": "user", "name": "fenfan"}, "name": "Shaojin Wu", "status": "claimed_verified", "statusLastChangedAt": "2026-05-19T08:31:29.658Z", "hidden": false}, {"_id": "6a0bd58b8ca2d0b25638042e", "name": "Yunsheng Jiang", "hidden": false}, {"_id": "6a0bd58b8ca2d0b25638042f", "name": "Yufei Huo", "hidden": false}, {"_id": "6a0bd58b8ca2d0b256380430", "name": "Hao Li", "hidden": false}, {"_id": "6a0bd58b8ca2d0b256380431", "name": "Yinghang Song", "hidden": false}, {"_id": "6a0bd58b8ca2d0b256380432", "name": "Fei Ding", "hidden": false}, {"_id": "6a0bd58b8ca2d0b256380433", "user": {"_id": "642953ce145a9d7d11f117d0", "avatarUrl": "https://cdn-avatars.huggingface.co/v1/production/uploads/642953ce145a9d7d11f117d0/mwvqCZzvqSCaHKDgsaweP.jpeg", "isPro": false, "fullname": "Jianzhu Guo", "user": "cleardusk", "type": "user", "name": "cleardusk"}, "name": "Jianzhu Guo", "status": "claimed_verified", "statusLastChangedAt": "2026-05-19T08:31:31.595Z", "hidden": false}, {"_id": "6a0bd58b8ca2d0b256380434", "name": "Qian He", "hidden": false}, {"_id": "6a0bd58b8ca2d0b256380435", "name": "Zheren Fu", "hidden": false}, {"_id": "6a0bd58b8ca2d0b256380436", "name": "Zhendong Mao", "hidden": false}, {"_id": "6a0bd58b8ca2d0b256380437", "name": "Yongdong Zhang", "hidden": false}], "publishedAt": "2026-05-18T00:00:00.000Z", "submittedOnDailyAt": "2026-05-19T00:00:00.000Z", "title": "Lance: Unified Multimodal Modeling by Multi-Task Synergy", "submittedOnDailyBy": {"_id": "630636bcd37ce67e0e4d1d42", "avatarUrl": "/avatars/c3ba695d339eaaf9e810bfa0d9a7689a.svg", "isPro": false, "fullname": "Mengqi Huang", "user": "CoreloneH", "type": "user", "name": "CoreloneH"}, "summary": "We present Lance, a lightweight native unified model supporting multimodal understanding, generation, and editing for both images and videos. Rather than relying on model capacity scaling or text-image-dominant designs, Lance explores a practical paradigm for unified multimodal modeling via collaborative multi-task training. It is grounded in two core principles: unified context modeling and decoupled capability pathways. Specifically, Lance is trained from scratch and employs a dual-stream mixture-of-experts architecture on shared interleaved multimodal sequences, enabling joint context learning while decoupling the pathways for understanding and generation. We further introduce modality-aware rotary positional encoding to mitigate interference among heterogeneous visual tokens and boost cross-task alignment. During training, Lance adopts a staged multi-task training paradigm with capability-oriented objectives and adaptive data scheduling to strengthen both semantic comprehension and visual generation performance. Experimental results demonstrate that Lance substantially outperforms existing open-source unified models in image and video generation, while retaining strong multimodal understanding capabilities. The homepage is available at https://lance-project.github.io.", "upvotes": 61, "discussionId": "6a0bd58b8ca2d0b256380438", "projectPage": "https://lance-project.github.io/", "githubRepo": "https://github.com/bytedance/Lance", "githubRepoAddedBy": "user", "ai_summary": "Lance is a unified multimodal model that combines understanding, generation, and editing capabilities for images and videos through collaborative multi-task training and a dual-stream architecture.", "ai_keywords": ["mixture-of-experts architecture", "multimodal understanding", "multimodal generation", "multimodal editing", "collaborative multi-task training", "unified context modeling", "decoupled capability pathways", "modality-aware rotary positional encoding", "staged multi-task training", "adaptive data scheduling"], "githubStars": 259, "organization": {"_id": "66bc9cc55b64185087601c60", "name": "bytedance-research", "fullname": "bytedance-research", "avatar": "https://cdn-avatars.huggingface.co/v1/production/uploads/6535c9e88bde2fae19b6fb25/7a1zq0juEwFJVCIShnLI-.png"}, "summary_zh": "<ul>\n    <li>Lance \u662f\u4e00\u4e2a\u8f7b\u91cf\u7ea7\u7684\u7edf\u4e00\u6a21\u578b\uff0c\u652f\u6301\u56fe\u50cf\u548c\u89c6\u9891\u7684\u591a\u6a21\u6001\u7406\u89e3\u3001\u751f\u6210\u548c\u7f16\u8f91\u3002</li>\n    <li>\u8be5\u6a21\u578b\u901a\u8fc7\u534f\u4f5c\u591a\u4efb\u52a1\u8bad\u7ec3\uff0c\u800c\u4e0d\u662f\u7b80\u5355\u6269\u5927\u6a21\u578b\u5bb9\u91cf\uff0c\u6765\u5b9e\u73b0\u7edf\u4e00\u7684\u591a\u6a21\u6001\u5efa\u6a21\u3002</li>\n    <li>Lance \u91c7\u7528\u53cc\u6d41\u4e13\u5bb6\u67b6\u6784\uff0c\u80fd\u591f\u540c\u65f6\u5b66\u4e60\u4e0a\u4e0b\u6587\uff0c\u5e76\u5c06\u7406\u89e3\u548c\u751f\u6210\u80fd\u529b\u5206\u5f00\u3002</li>\n    <li>\u5f15\u5165\u4e86\u6a21\u6001\u611f\u77e5\u7684\u65cb\u8f6c\u4f4d\u7f6e\u7f16\u7801\uff0c\u4ee5\u51cf\u5c11\u4e0d\u540c\u89c6\u89c9\u6807\u8bb0\u4e4b\u95f4\u7684\u5e72\u6270\u3002</li>\n    <li>\u5b9e\u9a8c\u7ed3\u679c\u8868\u660e\uff0cLance \u5728\u56fe\u50cf\u548c\u89c6\u9891\u751f\u6210\u65b9\u9762\u663e\u8457\u4f18\u4e8e\u73b0\u6709\u7684\u5f00\u6e90\u7edf\u4e00\u6a21\u578b\uff0c\u540c\u65f6\u4fdd\u6301\u5f3a\u5927\u7684\u591a\u6a21\u6001\u7406\u89e3\u80fd\u529b\u3002</li>\n</ul>", "summary_simple": "<ul>\n    <li>Lance is a lightweight model that can understand, generate, and edit both images and videos.</li>\n    <li>It uses a new approach called collaborative multi-task training instead of just making the model bigger.</li>\n    <li>The model is built on two main ideas: unified context modeling and separate pathways for different tasks.</li>\n    <li>Lance includes special techniques to help it better understand and generate visual content without confusion.</li>\n    <li>It has shown to perform much better than other similar models in producing images and videos while still understanding them well.</li>\n</ul>"}, "publishedAt": "2026-05-17T20:00:00.000Z", "title": "Lance: Unified Multimodal Modeling by Multi-Task Synergy", "summary": "We present Lance, a lightweight native unified model supporting multimodal understanding, generation, and editing for both images and videos. Rather than relying on model capacity scaling or text-image-dominant designs, Lance explores a practical paradigm for unified multimodal modeling via collaborative multi-task training. It is grounded in two core principles: unified context modeling and decoupled capability pathways. Specifically, Lance is trained from scratch and employs a dual-stream mixture-of-experts architecture on shared interleaved multimodal sequences, enabling joint context learning while decoupling the pathways for understanding and generation. We further introduce modality-aware rotary positional encoding to mitigate interference among heterogeneous visual tokens and boost cross-task alignment. During training, Lance adopts a staged multi-task training paradigm with capability-oriented objectives and adaptive data scheduling to strengthen both semantic comprehension and visual generation performance. Experimental results demonstrate that Lance substantially outperforms existing open-source unified models in image and video generation, while retaining strong multimodal understanding capabilities. The homepage is available at https://lance-project.github.io.", "thumbnail": "https://cdn-thumbnails.huggingface.co/social-thumbnails/papers/2605.18678.png", "numComments": 2, "submittedBy": {"_id": "630636bcd37ce67e0e4d1d42", "avatarUrl": "/avatars/c3ba695d339eaaf9e810bfa0d9a7689a.svg", "fullname": "Mengqi Huang", "name": "CoreloneH", "type": "user", "isPro": false, "isHf": false, "isHfAdmin": false, "isMod": false, "followerCount": 9, "isUserFollowing": false}, "organization": {"_id": "66bc9cc55b64185087601c60", "name": "bytedance-research", "fullname": "bytedance-research", "avatar": "https://cdn-avatars.huggingface.co/v1/production/uploads/6535c9e88bde2fae19b6fb25/7a1zq0juEwFJVCIShnLI-.png"}, "isAuthorParticipating": false}],
    "month": [{"paper": {"id": "2604.27351", "authors": [{"_id": "69f406b0ab6004e666b006e1", "name": "Zihao Li", "hidden": false}, {"_id": "69f406b0ab6004e666b006e2", "name": "Jiaru Zou", "hidden": false}, {"_id": "69f406b0ab6004e666b006e3", "name": "Feihao Fang", "hidden": false}, {"_id": "69f406b0ab6004e666b006e4", "name": "Xuying Ning", "hidden": false}, {"_id": "69f406b0ab6004e666b006e5", "name": "Mengting Ai", "hidden": false}, {"_id": "69f406b0ab6004e666b006e6", "name": "Tianxin Wei", "hidden": false}, {"_id": "69f406b0ab6004e666b006e7", "name": "Sirui Chen", "hidden": false}, {"_id": "69f406b0ab6004e666b006e8", "name": "Xiyuan Yang", "hidden": false}, {"_id": "69f406b0ab6004e666b006e9", "name": "Jingrui He", "hidden": false}], "mediaUrls": ["https://cdn-uploads.huggingface.co/production/uploads/65d41143406bdae630826d87/XzC_QtmxoQ2Gf7PsluCMm.png"], "publishedAt": "2026-04-30T00:00:00.000Z", "submittedOnDailyAt": "2026-05-01T00:30:02.362Z", "title": "Heterogeneous Scientific Foundation Model Collaboration", "submittedOnDailyBy": {"_id": "65d41143406bdae630826d87", "avatarUrl": "/avatars/ed8259ed64a13b1ed43c004b741e1401.svg", "isPro": false, "fullname": "Zihao Li", "user": "Violet24K", "type": "user", "name": "Violet24K"}, "summary": "Agentic large language model systems have demonstrated strong capabilities. However, their reliance on language as the universal interface fundamentally limits their applicability to many real-world problems, especially in scientific domains where domain-specific foundation models have been developed to address specialized tasks beyond natural language. In this work, we introduce Eywa, a heterogeneous agentic framework designed to extend language-centric systems to a broader class of scientific foundation models. The key idea of Eywa is to augment domain-specific foundation models with a language-model-based reasoning interface, enabling language models to guide inference over non-linguistic data modalities. This design allows predictive foundation models, which are typically optimized for specialized data and tasks, to participate in higher-level reasoning and decision-making processes within agentic systems. Eywa can serve as a drop-in replacement for a single-agent pipeline (EywaAgent) or be integrated into existing multi-agent systems by replacing traditional agents with specialized agents (EywaMAS). We further investigate a planning-based orchestration framework in which a planner dynamically coordinates traditional agents and Eywa agents to solve complex tasks across heterogeneous data modalities (EywaOrchestra). We evaluate Eywa across a diverse set of scientific domains spanning physical, life, and social sciences. Experimental results demonstrate that Eywa improves performance on tasks involving structured and domain-specific data, while reducing reliance on language-based reasoning through effective collaboration with specialized foundation models.", "upvotes": 176, "discussionId": "69f406b0ab6004e666b006ea", "projectPage": "https://www.zihao.website/eywa.github.io/", "githubRepo": "https://github.com/Violet24K/Eywa", "githubRepoAddedBy": "user", "ai_summary": "Eywa is a heterogeneous agentic framework that extends language-centric systems to scientific foundation models by integrating domain-specific models with language-based reasoning interfaces for improved performance across diverse scientific domains.", "ai_keywords": ["agentic framework", "domain-specific foundation models", "language-model-based reasoning", "non-linguistic data modalities", "predictive foundation models", "multi-agent systems", "planning-based orchestration", "heterogeneous data modalities"], "githubStars": 10, "organization": {"_id": "60212a089f64108326fac7c2", "name": "illinois", "fullname": "University of Illinois at Urbana-Champaign", "avatar": "https://cdn-avatars.huggingface.co/v1/production/uploads/1612786274096-6021121cfb1b47827d667074.png"}, "summary_zh": "<ul>\n    <li>Eywa\u662f\u4e00\u4e2a\u5f02\u6784\u4ee3\u7406\u6846\u67b6\uff0c\u65e8\u5728\u6269\u5c55\u8bed\u8a00\u4e2d\u5fc3\u7cfb\u7edf\u5230\u66f4\u5e7f\u6cdb\u7684\u79d1\u5b66\u57fa\u7840\u6a21\u578b\u3002</li>\n    <li>\u5b83\u901a\u8fc7\u8bed\u8a00\u6a21\u578b\u7684\u63a8\u7406\u63a5\u53e3\u589e\u5f3a\u9886\u57df\u7279\u5b9a\u7684\u57fa\u7840\u6a21\u578b\uff0c\u4f7f\u8bed\u8a00\u6a21\u578b\u80fd\u591f\u6307\u5bfc\u975e\u8bed\u8a00\u6570\u636e\u7684\u63a8\u7406\u3002</li>\n    <li>Eywa\u53ef\u4ee5\u66ff\u4ee3\u5355\u4e00\u4ee3\u7406\u7ba1\u9053\uff08EywaAgent\uff09\u6216\u4e0e\u73b0\u6709\u591a\u4ee3\u7406\u7cfb\u7edf\u96c6\u6210\uff08EywaMAS\uff09\u3002</li>\n    <li>\u5b83\u8fd8\u63a2\u7d22\u4e86\u4e00\u79cd\u89c4\u5212\u57fa\u7840\u7684\u534f\u8c03\u6846\u67b6\uff08EywaOrchestra\uff09\uff0c\u52a8\u6001\u534f\u8c03\u4f20\u7edf\u4ee3\u7406\u548cEywa\u4ee3\u7406\u89e3\u51b3\u590d\u6742\u4efb\u52a1\u3002</li>\n    <li>\u5b9e\u9a8c\u7ed3\u679c\u663e\u793a\uff0cEywa\u5728\u6d89\u53ca\u7ed3\u6784\u5316\u548c\u9886\u57df\u7279\u5b9a\u6570\u636e\u7684\u4efb\u52a1\u4e2d\u63d0\u5347\u4e86\u6027\u80fd\uff0c\u5e76\u51cf\u5c11\u4e86\u5bf9\u57fa\u4e8e\u8bed\u8a00\u63a8\u7406\u7684\u4f9d\u8d56\u3002</li>\n</ul>", "summary_simple": "<ul>\n    <li>Eywa is a new system that combines language models with specialized scientific models to solve complex problems.</li>\n    <li>It enhances the ability of language models to work with different types of data beyond just text.</li>\n    <li>Eywa can be used as a standalone system or integrated into existing multi-agent systems.</li>\n    <li>The system improves performance on tasks that involve specific scientific data while reducing the need for language-based reasoning.</li>\n    <li>Tests show that Eywa works well across various scientific fields, including physical, life, and social sciences.</li>\n</ul>"}, "publishedAt": "2026-04-29T20:00:00.000Z", "title": "Heterogeneous Scientific Foundation Model Collaboration", "summary": "Agentic large language model systems have demonstrated strong capabilities. However, their reliance on language as the universal interface fundamentally limits their applicability to many real-world problems, especially in scientific domains where domain-specific foundation models have been developed to address specialized tasks beyond natural language. In this work, we introduce Eywa, a heterogeneous agentic framework designed to extend language-centric systems to a broader class of scientific foundation models. The key idea of Eywa is to augment domain-specific foundation models with a language-model-based reasoning interface, enabling language models to guide inference over non-linguistic data modalities. This design allows predictive foundation models, which are typically optimized for specialized data and tasks, to participate in higher-level reasoning and decision-making processes within agentic systems. Eywa can serve as a drop-in replacement for a single-agent pipeline (EywaAgent) or be integrated into existing multi-agent systems by replacing traditional agents with specialized agents (EywaMAS). We further investigate a planning-based orchestration framework in which a planner dynamically coordinates traditional agents and Eywa agents to solve complex tasks across heterogeneous data modalities (EywaOrchestra). We evaluate Eywa across a diverse set of scientific domains spanning physical, life, and social sciences. Experimental results demonstrate that Eywa improves performance on tasks involving structured and domain-specific data, while reducing reliance on language-based reasoning through effective collaboration with specialized foundation models.", "mediaUrls": ["https://cdn-uploads.huggingface.co/production/uploads/65d41143406bdae630826d87/XzC_QtmxoQ2Gf7PsluCMm.png"], "thumbnail": "https://cdn-thumbnails.huggingface.co/social-thumbnails/papers/2604.27351.png", "numComments": 1, "submittedBy": {"_id": "65d41143406bdae630826d87", "avatarUrl": "/avatars/ed8259ed64a13b1ed43c004b741e1401.svg", "fullname": "Zihao Li", "name": "Violet24K", "type": "user", "isPro": false, "isHf": false, "isHfAdmin": false, "isMod": false, "followerCount": 1, "isUserFollowing": false}, "organization": {"_id": "60212a089f64108326fac7c2", "name": "illinois", "fullname": "University of Illinois at Urbana-Champaign", "avatar": "https://cdn-avatars.huggingface.co/v1/production/uploads/1612786274096-6021121cfb1b47827d667074.png"}, "isAuthorParticipating": false}, {"paper": {"id": "2605.02881", "authors": [{"_id": "69f95d7b888fc8ecf44e5771", "user": {"_id": "6402a262cad36eb2b0fdd14b", "avatarUrl": "https://cdn-avatars.huggingface.co/v1/production/uploads/6402a262cad36eb2b0fdd14b/fIug0NLdw5zxrv0PUXmMY.jpeg", "isPro": false, "fullname": "Haoquan Fang", "user": "hqfang", "type": "user", "name": "hqfang"}, "name": "Haoquan Fang", "status": "claimed_verified", "statusLastChangedAt": "2026-05-05T17:27:04.052Z", "hidden": false}, {"_id": "69f95d7b888fc8ecf44e5772", "name": "Jiafei Duan", "hidden": false}, {"_id": "69f95d7b888fc8ecf44e5773", "name": "Donovan Clay", "hidden": false}, {"_id": "69f95d7b888fc8ecf44e5774", "user": {"_id": "66c34b6f85c8bcb5f2338467", "avatarUrl": "/avatars/c004e7c8f3604c3e5fca465d59f051e2.svg", "isPro": false, "fullname": "Sam Wang", "user": "swang23", "type": "user", "name": "swang23"}, "name": "Sam Wang", "status": "claimed_verified", "statusLastChangedAt": "2026-05-05T17:27:02.383Z", "hidden": false}, {"_id": "69f95d7b888fc8ecf44e5775", "name": "Shuo Liu", "hidden": false}, {"_id": "69f95d7b888fc8ecf44e5776", "name": "Weikai Huang", "hidden": false}, {"_id": "69f95d7b888fc8ecf44e5777", "name": "Xiang Fan", "hidden": false}, {"_id": "69f95d7b888fc8ecf44e5778", "name": "Wei-Chuan Tsai", "hidden": false}, {"_id": "69f95d7b888fc8ecf44e5779", "name": "Shirui Chen", "hidden": false}, {"_id": "69f95d7b888fc8ecf44e577a", "name": "Yi Ru Wang", "hidden": false}, {"_id": "69f95d7b888fc8ecf44e577b", "name": "Shanli Xing", "hidden": false}, {"_id": "69f95d7b888fc8ecf44e577c", "name": "Jaemin Cho", "hidden": false}, {"_id": "69f95d7b888fc8ecf44e577d", "name": "Jae Sung Park", "hidden": false}, {"_id": "69f95d7b888fc8ecf44e577e", "name": "Ainaz Eftekhar", "hidden": false}, {"_id": "69f95d7b888fc8ecf44e577f", "name": "Peter Sushko", "hidden": false}, {"_id": "69f95d7b888fc8ecf44e5780", "name": "Karen Farley", "hidden": false}, {"_id": "69f95d7b888fc8ecf44e5781", "name": "Angad Wadhwa", "hidden": false}, {"_id": "69f95d7b888fc8ecf44e5782", "name": "Cole Harrison", "hidden": false}, {"_id": "69f95d7b888fc8ecf44e5783", "name": "Winson Han", "hidden": false}, {"_id": "69f95d7b888fc8ecf44e5784", "name": "Ying-Chun Lee", "hidden": false}, {"_id": "69f95d7b888fc8ecf44e5785", "name": "Eli VanderBilt", "hidden": false}, {"_id": "69f95d7b888fc8ecf44e5786", "name": "Rose Hendrix", "hidden": false}, {"_id": "69f95d7b888fc8ecf44e5787", "name": "Suveen Ellawela", "hidden": false}, {"_id": "69f95d7b888fc8ecf44e5788", "name": "Lucas Ngoo", "hidden": false}, {"_id": "69f95d7b888fc8ecf44e5789", "name": "Joyce Chai", "hidden": false}, {"_id": "69f95d7b888fc8ecf44e578a", "name": "Zhongzheng Ren", "hidden": false}, {"_id": "69f95d7b888fc8ecf44e578b", "name": "Ali Farhadi", "hidden": false}, {"_id": "69f95d7b888fc8ecf44e578c", "name": "Dieter Fox", "hidden": false}, {"_id": "69f95d7b888fc8ecf44e578d", "name": "Ranjay Krishna", "hidden": false}], "mediaUrls": ["https://cdn-uploads.huggingface.co/production/uploads/632b42626110e37dba3d5bcb/J4g90Or8f9R1Qs_9uxOsT.mp4"], "publishedAt": "2026-05-04T00:00:00.000Z", "submittedOnDailyAt": "2026-05-05T02:01:40.321Z", "title": "MolmoAct2: Action Reasoning Models for Real-world Deployment", "submittedOnDailyBy": {"_id": "632b42626110e37dba3d5bcb", "avatarUrl": "/avatars/ca70a15def71ee84f4f149db5e954843.svg", "isPro": false, "fullname": "Duan", "user": "Jiafei1224", "type": "user", "name": "Jiafei1224"}, "summary": "Vision-Language-Action (VLA) models aim to provide a single generalist controller for robots, but today's systems fall short on the criteria that matter for real-world deployment. Frontier models are closed, open-weight alternatives are tied to expensive hardware, reasoning-augmented policies pay prohibitive latency for their grounding, and fine-tuned success rates remain below the threshold for dependable use. We present MolmoAct2, a fully open action reasoning model built for practical deployment, advancing its predecessor along five axes. We introduce MolmoER, a VLM backbone specialized for spatial and embodied reasoning, trained on a 3.3M-sample corpus with a specialize-then-rehearse recipe. We release three new datasets spanning low-to-medium cost platforms, including MolmoAct2-BimanualYAM, 720 hours of teleoperated bimanual trajectories that constitute the largest open bimanual dataset to date, together with quality-filtered Franka (DROID) and SO100/101 subsets. We provide OpenFAST, an open-weight, open-data action tokenizer trained on millions of trajectories across five embodiments. We redesign the architecture to graft a flow-matching continuous-action expert onto a discrete-token VLM via per-layer KV-cache conditioning. Finally, we propose MolmoThink, an adaptive-depth reasoning variant that re-predicts depth tokens only for scene regions that change between timesteps, retaining geometric grounding at a fraction of prior latency. In the most extensive empirical study of any open VLA to date, spanning 7 simulation and real-world benchmarks, MolmoAct2 outperforms strong baselines including Pi-05, while MolmoER surpasses GPT-5 and Gemini Robotics ER-1.5 across 13 embodied-reasoning benchmarks. We release model weights, training code, and complete training data. Project page: https://allenai.org/blog/molmoact2", "upvotes": 162, "discussionId": "69f95d7b888fc8ecf44e578e", "projectPage": "https://allenai.org/blog/molmoact2", "githubRepo": "https://github.com/allenai/molmoact2", "githubRepoAddedBy": "user", "ai_summary": "MolmoAct2 presents an open-action reasoning model for robotics that improves upon previous systems through specialized vision-language-model backbones, new datasets, open-weight action tokenizers, architectural redesign for continuous-action prediction, and adaptive reasoning for reduced latency.", "ai_keywords": ["Vision-Language-Action models", "VLM backbone", "spatial reasoning", "embodied reasoning", "action tokenizer", "flow-matching", "continuous-action expert", "discrete-token VLM", "KV-cache conditioning", "adaptive-depth reasoning", "geometric grounding"], "githubStars": 12, "organization": {"_id": "5e70f3648ce3c604d78fe132", "name": "allenai", "fullname": "Ai2", "avatar": "https://cdn-avatars.huggingface.co/v1/production/uploads/652db071b62cf1f8463221e2/CxxwFiaomTa1MCX_B7-pT.png"}, "summary_zh": "<ul>\n    <li>MolmoAct2 \u662f\u4e00\u4e2a\u5f00\u653e\u7684\u884c\u52a8\u63a8\u7406\u6a21\u578b\uff0c\u65e8\u5728\u4e3a\u673a\u5668\u4eba\u63d0\u4f9b\u901a\u7528\u63a7\u5236\u80fd\u529b\u3002</li>\n    <li>\u8be5\u6a21\u578b\u5728\u7a7a\u95f4\u548c\u5177\u8eab\u63a8\u7406\u65b9\u9762\u8fdb\u884c\u4e86\u4e13\u95e8\u8bad\u7ec3\uff0c\u4f7f\u7528\u4e86330\u4e07\u4e2a\u6837\u672c\u7684\u6570\u636e\u96c6\u3002</li>\n    <li>\u6211\u4eec\u53d1\u5e03\u4e86\u4e09\u4e2a\u65b0\u6570\u636e\u96c6\uff0c\u5305\u62ec\u6700\u5927\u7684\u5f00\u653e\u53cc\u624b\u64cd\u4f5c\u6570\u636e\u96c6\uff0c\u5305\u542b720\u5c0f\u65f6\u7684\u9065\u63a7\u53cc\u624b\u8f68\u8ff9\u3002</li>\n    <li>MolmoAct2 \u91c7\u7528\u4e86\u6539\u8fdb\u7684\u67b6\u6784\uff0c\u4ee5\u63d0\u9ad8\u63a8\u7406\u6548\u7387\uff0c\u5e76\u51cf\u5c11\u5ef6\u8fdf\u3002</li>\n    <li>\u5728\u591a\u4e2a\u57fa\u51c6\u6d4b\u8bd5\u4e2d\uff0cMolmoAct2 \u8d85\u8d8a\u4e86\u8bb8\u591a\u5f3a\u5927\u7684\u57fa\u7ebf\u6a21\u578b\uff0c\u5e76\u4e14\u6211\u4eec\u63d0\u4f9b\u4e86\u6a21\u578b\u6743\u91cd\u548c\u8bad\u7ec3\u4ee3\u7801\u3002</li>\n</ul>", "summary_simple": "<ul>\n    <li>MolmoAct2 is a new model designed for robots that improves upon previous systems for better real-world use.</li>\n    <li>It features a special backbone called MolmoER, focused on understanding space and actions, trained on a large dataset.</li>\n    <li>Three new datasets are released, including the largest open dataset for bimanual robot tasks, with 720 hours of recorded actions.</li>\n    <li>The model includes OpenFAST, an open-action tokenizer trained on millions of robot actions across different setups.</li>\n    <li>In extensive tests, MolmoAct2 outperformed other models, showing significant improvements in robot reasoning and action capabilities.</li>\n</ul>"}, "publishedAt": "2026-05-03T20:00:00.000Z", "title": "MolmoAct2: Action Reasoning Models for Real-world Deployment", "summary": "Vision-Language-Action (VLA) models aim to provide a single generalist controller for robots, but today's systems fall short on the criteria that matter for real-world deployment. Frontier models are closed, open-weight alternatives are tied to expensive hardware, reasoning-augmented policies pay prohibitive latency for their grounding, and fine-tuned success rates remain below the threshold for dependable use. We present MolmoAct2, a fully open action reasoning model built for practical deployment, advancing its predecessor along five axes. We introduce MolmoER, a VLM backbone specialized for spatial and embodied reasoning, trained on a 3.3M-sample corpus with a specialize-then-rehearse recipe. We release three new datasets spanning low-to-medium cost platforms, including MolmoAct2-BimanualYAM, 720 hours of teleoperated bimanual trajectories that constitute the largest open bimanual dataset to date, together with quality-filtered Franka (DROID) and SO100/101 subsets. We provide OpenFAST, an open-weight, open-data action tokenizer trained on millions of trajectories across five embodiments. We redesign the architecture to graft a flow-matching continuous-action expert onto a discrete-token VLM via per-layer KV-cache conditioning. Finally, we propose MolmoThink, an adaptive-depth reasoning variant that re-predicts depth tokens only for scene regions that change between timesteps, retaining geometric grounding at a fraction of prior latency. In the most extensive empirical study of any open VLA to date, spanning 7 simulation and real-world benchmarks, MolmoAct2 outperforms strong baselines including Pi-05, while MolmoER surpasses GPT-5 and Gemini Robotics ER-1.5 across 13 embodied-reasoning benchmarks. We release model weights, training code, and complete training data. Project page: https://allenai.org/blog/molmoact2", "mediaUrls": ["https://cdn-uploads.huggingface.co/production/uploads/632b42626110e37dba3d5bcb/J4g90Or8f9R1Qs_9uxOsT.mp4"], "thumbnail": "https://cdn-thumbnails.huggingface.co/social-thumbnails/papers/2605.02881.png", "numComments": 5, "submittedBy": {"_id": "632b42626110e37dba3d5bcb", "avatarUrl": "/avatars/ca70a15def71ee84f4f149db5e954843.svg", "fullname": "Duan", "name": "Jiafei1224", "type": "user", "isPro": false, "isHf": false, "isHfAdmin": false, "isMod": false, "followerCount": 7, "isUserFollowing": false}, "organization": {"_id": "5e70f3648ce3c604d78fe132", "name": "allenai", "fullname": "Ai2", "avatar": "https://cdn-avatars.huggingface.co/v1/production/uploads/652db071b62cf1f8463221e2/CxxwFiaomTa1MCX_B7-pT.png"}, "isAuthorParticipating": false}, {"paper": {"id": "2605.22355", "authors": [{"_id": "6a0fc10ea53a61ce2e422c9a", "user": {"_id": "6964ab352fb9f77cbe8c9854", "avatarUrl": "/avatars/2c4734b40bb98d162837fbe6b128f7d7.svg", "isPro": false, "fullname": "Hanyu Guo", "user": "MaoPaJia", "type": "user", "name": "MaoPaJia"}, "name": "Hanyu Guo", "status": "claimed_verified", "statusLastChangedAt": "2026-05-22T16:08:45.926Z", "hidden": false}, {"_id": "6a0fc10ea53a61ce2e422c9b", "name": "Jiedong Yang", "hidden": false}, {"_id": "6a0fc10ea53a61ce2e422c9c", "name": "Chao Chen", "hidden": false}, {"_id": "6a0fc10ea53a61ce2e422c9d", "user": {"_id": "682eeb11d28d9650c926abb0", "avatarUrl": "/avatars/3c8a34cc61aa2330ffcb52446a9afe70.svg", "isPro": false, "fullname": "LONGFEI XU", "user": "Xufew", "type": "user", "name": "Xufew"}, "name": "Longfei Xu", "status": "claimed_verified", "statusLastChangedAt": "2026-05-22T16:08:49.010Z", "hidden": false}, {"_id": "6a0fc10ea53a61ce2e422c9e", "name": "Kaikui Liu", "hidden": false}, {"_id": "6a0fc10ea53a61ce2e422c9f", "name": "Xiangxiang Chu", "hidden": false}], "publishedAt": "2026-05-21T00:00:00.000Z", "submittedOnDailyAt": "2026-05-22T00:00:00.000Z", "title": "TransitLM: A Large-Scale Dataset and Benchmark for Map-Free Transit Route Generation", "submittedOnDailyBy": {"_id": "66d255e3947594430c723ff6", "avatarUrl": "/avatars/c56e4792332a01bf34085a75ee64916e.svg", "isPro": false, "fullname": "xiaochonglinghu", "user": "xiaochonglinghu", "type": "user", "name": "xiaochonglinghu"}, "summary": "Public transit route planning traditionally depends on structured map infrastructure and complex routing engines, and no existing dataset supports training models to bypass this dependency. We present TransitLM, a large-scale dataset of over 13 million transit route planning records from four Chinese cities covering 120,845 stations and 13,666 lines, released as a continual pre-training corpus and benchmark data for three evaluation tasks with complementary metrics. Experiments show that an LLM trained on TransitLM produces structurally valid routes at high accuracy and implicitly grounds arbitrary GPS coordinates to appropriate stations without any explicit mapping. These results demonstrate that transit route planning can be learned entirely from data, enabling end-to-end, map-free route generation directly from origin-destination information. The dataset and benchmark are available at https://huggingface.co/datasets/GD-ML/TransitLM, with evaluation code at https://github.com/HotTricker/TransitLM.", "upvotes": 162, "discussionId": "6a0fc10ea53a61ce2e422ca0", "githubRepo": "https://github.com/HotTricker/TransitLM", "githubRepoAddedBy": "user", "ai_summary": "TransitLM dataset enables end-to-end transit route planning using large language models trained on structured transit data, eliminating the need for traditional map-based approaches.", "ai_keywords": ["large language models", "transit route planning", "structured map infrastructure", "routing engines", "continual pre-training", "evaluation tasks", "GPS coordinates", "origin-destination information"], "githubStars": 107, "organization": {"_id": "67d11771890254196d3174e5", "name": "GD-ML", "fullname": "AMAP-ML", "avatar": "https://cdn-avatars.huggingface.co/v1/production/uploads/67d116c47be76de1a40873ca/s5ukAx9E36ZZIKvbpBRi4.png"}, "summary_zh": "<ul>\n    <li>TransitLM\u662f\u4e00\u4e2a\u5927\u89c4\u6a21\u7684\u6570\u636e\u96c6\uff0c\u5305\u62ec\u6765\u81ea\u56db\u4e2a\u4e2d\u56fd\u57ce\u5e02\u76841300\u591a\u4e07\u6761\u516c\u5171\u4ea4\u901a\u8def\u7ebf\u89c4\u5212\u8bb0\u5f55\u3002</li>\n    <li>\u8be5\u6570\u636e\u96c6\u6db5\u76d6\u4e86120,845\u4e2a\u7ad9\u70b9\u548c13,666\u6761\u7ebf\u8def\uff0c\u65e8\u5728\u66ff\u4ee3\u4f20\u7edf\u7684\u5730\u56fe\u57fa\u7840\u8bbe\u65bd\u548c\u590d\u6742\u8def\u7531\u5f15\u64ce\u3002</li>\n    <li>\u5b9e\u9a8c\u8868\u660e\uff0c\u57fa\u4e8eTransitLM\u8bad\u7ec3\u7684\u5927\u578b\u8bed\u8a00\u6a21\u578b\u53ef\u4ee5\u63d0\u4f9b\u9ad8\u51c6\u786e\u7387\u7684\u6709\u6548\u8def\u7ebf\u89c4\u5212\u3002</li>\n    <li>\u8be5\u6a21\u578b\u53ef\u4ee5\u6839\u636e\u539f\u70b9\u548c\u76ee\u7684\u5730\u4fe1\u606f\u751f\u6210\u8def\u7ebf\uff0c\u800c\u65e0\u9700\u4f9d\u8d56\u4efb\u4f55\u660e\u786e\u7684\u5730\u56fe\u3002</li>\n    <li>\u6570\u636e\u96c6\u548c\u57fa\u51c6\u6d4b\u8bd5\u53ef\u5728\u6307\u5b9a\u7f51\u5740\u83b7\u53d6\uff0c\u4e3a\u7814\u7a76\u548c\u5f00\u53d1\u63d0\u4f9b\u652f\u6301\u3002</li>\n</ul>", "summary_simple": "<ul>\n    <li>TransitLM is a new dataset with over 13 million records for planning public transit routes in four Chinese cities.</li>\n    <li>It includes data from 120,845 stations and 13,666 transit lines.</li>\n    <li>The dataset allows for training models to generate transit routes without needing traditional maps.</li>\n    <li>Experiments show that a language model trained on this dataset can create accurate routes and link GPS coordinates to the right stations.</li>\n    <li>The dataset and related code are available online for use and evaluation.</li>\n</ul>"}, "publishedAt": "2026-05-20T20:00:00.000Z", "title": "TransitLM: A Large-Scale Dataset and Benchmark for Map-Free Transit Route Generation", "summary": "Public transit route planning traditionally depends on structured map infrastructure and complex routing engines, and no existing dataset supports training models to bypass this dependency. We present TransitLM, a large-scale dataset of over 13 million transit route planning records from four Chinese cities covering 120,845 stations and 13,666 lines, released as a continual pre-training corpus and benchmark data for three evaluation tasks with complementary metrics. Experiments show that an LLM trained on TransitLM produces structurally valid routes at high accuracy and implicitly grounds arbitrary GPS coordinates to appropriate stations without any explicit mapping. These results demonstrate that transit route planning can be learned entirely from data, enabling end-to-end, map-free route generation directly from origin-destination information. The dataset and benchmark are available at https://huggingface.co/datasets/GD-ML/TransitLM, with evaluation code at https://github.com/HotTricker/TransitLM.", "thumbnail": "https://cdn-thumbnails.huggingface.co/social-thumbnails/papers/2605.22355.png", "numComments": 2, "submittedBy": {"_id": "66d255e3947594430c723ff6", "avatarUrl": "/avatars/c56e4792332a01bf34085a75ee64916e.svg", "fullname": "xiaochonglinghu", "name": "xiaochonglinghu", "type": "user", "isPro": false, "isHf": false, "isHfAdmin": false, "isMod": false, "followerCount": 9, "isUserFollowing": false}, "organization": {"_id": "67d11771890254196d3174e5", "name": "GD-ML", "fullname": "AMAP-ML", "avatar": "https://cdn-avatars.huggingface.co/v1/production/uploads/67d116c47be76de1a40873ca/s5ukAx9E36ZZIKvbpBRi4.png"}, "isAuthorParticipating": false}, {"paper": {"id": "2605.12882", "authors": [{"_id": "6a0540aeb1a8cbabc9f08804", "name": "Dongsheng Ma", "hidden": false}, {"_id": "6a0540aeb1a8cbabc9f08805", "name": "Jiayu Li", "hidden": false}, {"_id": "6a0540aeb1a8cbabc9f08806", "name": "Zhengren Wang", "hidden": false}, {"_id": "6a0540aeb1a8cbabc9f08807", "name": "Yijie Wang", "hidden": false}, {"_id": "6a0540aeb1a8cbabc9f08808", "name": "Jiahao Kong", "hidden": false}, {"_id": "6a0540aeb1a8cbabc9f08809", "name": "Weijun Zeng", "hidden": false}, {"_id": "6a0540aeb1a8cbabc9f0880a", "name": "Jutao Xiao", "hidden": false}, {"_id": "6a0540aeb1a8cbabc9f0880b", "name": "Jie Yang", "hidden": false}, {"_id": "6a0540aeb1a8cbabc9f0880c", "name": "Wentao Zhang", "hidden": false}, {"_id": "6a0540aeb1a8cbabc9f0880d", "name": "Bin Wang", "hidden": false}, {"_id": "6a0540aeb1a8cbabc9f0880e", "name": "Conghui He", "hidden": false}], "publishedAt": "2026-05-13T00:00:00.000Z", "submittedOnDailyAt": "2026-05-18T00:00:00.000Z", "title": "CiteVQA: Benchmarking Evidence Attribution for Trustworthy Document Intelligence", "submittedOnDailyBy": {"_id": "66431358af62c6c266b921ad", "avatarUrl": "https://cdn-avatars.huggingface.co/v1/production/uploads/66431358af62c6c266b921ad/36VacSxNJSPM9Ap_35HSZ.jpeg", "isPro": false, "fullname": "Wang", "user": "zr-wang", "type": "user", "name": "zr-wang"}, "summary": "Multimodal Large Language Models (MLLMs) have significantly advanced document understanding, yet current Doc-VQA evaluations score only the final answer and leave the supporting evidence unchecked. This answer-only approach masks a critical failure mode: a model can land on the correct answer while grounding it in the wrong passage -- a critical risk in high-stakes domains like law, finance, and medicine, where every conclusion must be traceable to a specific source region. To address this, we introduce CiteVQA, a benchmark that requires models to return element-level bounding-box citations alongside each answer, evaluating both jointly. CiteVQA comprises 1,897 questions across 711 PDFs spanning seven domains and two languages, averaging 40.6 pages per document. To ensure fidelity and scalability, the ground-truth citations are generated by an automated pipeline-which identifies crucial evidence via masking ablation-and are subsequently validated through expert review. At the core of our evaluation is Strict Attributed Accuracy (SAA), which credits a prediction only when the answer and the cited region are both correct. Auditing 20 MLLMs reveals a pervasive Attribution Hallucination: models frequently produce the right answer while citing the wrong region. The strongest system (Gemini-3.1-Pro-Preview) achieves an SAA of only 76.0, and the strongest open-source MLLM reaches just 22.5. Ultimately, towards trustworthy document intelligence, CiteVQA exposes a reliability gap that answer-only evaluations overlook, providing the instrumentation needed to close it. Our repository is available at https://github.com/opendatalab/CiteVQA.", "upvotes": 161, "discussionId": "6a0540afb1a8cbabc9f0880f", "projectPage": "https://huggingface.co/datasets/opendatalab/CiteVQA", "githubRepo": "https://github.com/opendatalab/CiteVQA", "githubRepoAddedBy": "user", "ai_summary": "CiteVQA introduces a benchmark for document vision-language models that evaluates both answer accuracy and correct citation of supporting evidence, revealing significant attribution hallucinations in current models.", "ai_keywords": ["Multimodal Large Language Models", "Doc-VQA", "document understanding", "bounding-box citations", "Strict Attributed Accuracy", "Attribution Hallucination", "masking ablation", "expert review", "PDF documents", "cross-domain evaluation"], "githubStars": 55, "organization": {"_id": "66ce9d1f5e180b9b9c8e6f31", "name": "opendatalab", "fullname": "OpenDataLab", "avatar": "https://cdn-avatars.huggingface.co/v1/production/uploads/639c3afa7432f2f5d16b7296/yqxxBknyeqkGnYsjoaR4M.png"}, "summary_zh": "<ul>\n    <li>\u591a\u6a21\u6001\u5927\u8bed\u8a00\u6a21\u578b\uff08MLLMs\uff09\u5728\u6587\u6863\u7406\u89e3\u65b9\u9762\u53d6\u5f97\u4e86\u663e\u8457\u8fdb\u5c55\uff0c\u4f46\u73b0\u6709\u7684Doc-VQA\u8bc4\u4f30\u53ea\u5173\u6ce8\u6700\u7ec8\u7b54\u6848\uff0c\u5ffd\u89c6\u4e86\u652f\u6301\u8bc1\u636e\u3002</li>\n    <li>\u8fd9\u79cd\u53ea\u770b\u7b54\u6848\u7684\u65b9\u6cd5\u5b58\u5728\u98ce\u9669\uff0c\u6a21\u578b\u53ef\u80fd\u7ed9\u51fa\u6b63\u786e\u7b54\u6848\u5374\u5f15\u7528\u4e86\u9519\u8bef\u7684\u6bb5\u843d\uff0c\u5728\u6cd5\u5f8b\u3001\u91d1\u878d\u548c\u533b\u5b66\u7b49\u9ad8\u98ce\u9669\u9886\u57df\u5c24\u5176\u91cd\u8981\u3002</li>\n    <li>\u6211\u4eec\u5f15\u5165\u4e86CiteVQA\u57fa\u51c6\uff0c\u8981\u6c42\u6a21\u578b\u5728\u6bcf\u4e2a\u7b54\u6848\u65c1\u8fb9\u63d0\u4f9b\u5143\u7d20\u7ea7\u7684\u5f15\u7528\uff0c\u8bc4\u4f30\u7b54\u6848\u548c\u5f15\u7528\u533a\u57df\u7684\u51c6\u786e\u6027\u3002</li>\n    <li>CiteVQA\u5305\u542b1,897\u4e2a\u95ee\u9898\uff0c\u8de8\u8d8a711\u4e2aPDF\u6587\u6863\uff0c\u6db5\u76d6\u4e03\u4e2a\u9886\u57df\u548c\u4e24\u79cd\u8bed\u8a00\uff0c\u6587\u6863\u5e73\u5747\u670940.6\u9875\u3002</li>\n    <li>\u6211\u4eec\u7684\u8bc4\u4f30\u6838\u5fc3\u662f\u4e25\u683c\u5f52\u5c5e\u51c6\u786e\u7387\uff08SAA\uff09\uff0c\u53d1\u73b0\u8bb8\u591a\u6a21\u578b\u5728\u5f15\u7528\u65f6\u51fa\u73b0\u4e86\u5f52\u5c5e\u5e7b\u89c9\uff0c\u8868\u73b0\u51fa\u7b54\u6848\u6b63\u786e\u4f46\u5f15\u7528\u9519\u8bef\u7684\u60c5\u51b5\u3002</li>\n</ul>", "summary_simple": "<ul>\n    <li>Current evaluations of document question answering (Doc-VQA) only check the final answer, ignoring the evidence used to support it.</li>\n    <li>This can lead to situations where a model gives the right answer but cites the wrong source, which is risky in important fields like law and medicine.</li>\n    <li>CiteVQA is a new benchmark that requires models to provide citations for their answers, evaluating both together.</li>\n    <li>It includes 1,897 questions from 711 PDFs in seven fields and two languages, with a focus on accurate evidence identification.</li>\n    <li>The study reveals that many models often cite incorrect sources, highlighting a gap in reliability that previous evaluations missed.</li>\n</ul>"}, "publishedAt": "2026-05-12T20:00:00.000Z", "title": "CiteVQA: Benchmarking Evidence Attribution for Trustworthy Document Intelligence", "summary": "Multimodal Large Language Models (MLLMs) have significantly advanced document understanding, yet current Doc-VQA evaluations score only the final answer and leave the supporting evidence unchecked. This answer-only approach masks a critical failure mode: a model can land on the correct answer while grounding it in the wrong passage -- a critical risk in high-stakes domains like law, finance, and medicine, where every conclusion must be traceable to a specific source region. To address this, we introduce CiteVQA, a benchmark that requires models to return element-level bounding-box citations alongside each answer, evaluating both jointly. CiteVQA comprises 1,897 questions across 711 PDFs spanning seven domains and two languages, averaging 40.6 pages per document. To ensure fidelity and scalability, the ground-truth citations are generated by an automated pipeline-which identifies crucial evidence via masking ablation-and are subsequently validated through expert review. At the core of our evaluation is Strict Attributed Accuracy (SAA), which credits a prediction only when the answer and the cited region are both correct. Auditing 20 MLLMs reveals a pervasive Attribution Hallucination: models frequently produce the right answer while citing the wrong region. The strongest system (Gemini-3.1-Pro-Preview) achieves an SAA of only 76.0, and the strongest open-source MLLM reaches just 22.5. Ultimately, towards trustworthy document intelligence, CiteVQA exposes a reliability gap that answer-only evaluations overlook, providing the instrumentation needed to close it. Our repository is available at https://github.com/opendatalab/CiteVQA.", "thumbnail": "https://cdn-thumbnails.huggingface.co/social-thumbnails/papers/2605.12882.png", "numComments": 1, "submittedBy": {"_id": "66431358af62c6c266b921ad", "avatarUrl": "https://cdn-avatars.huggingface.co/v1/production/uploads/66431358af62c6c266b921ad/36VacSxNJSPM9Ap_35HSZ.jpeg", "fullname": "Wang", "name": "zr-wang", "type": "user", "isPro": false, "isHf": false, "isHfAdmin": false, "isMod": false, "isUserFollowing": false}, "organization": {"_id": "66ce9d1f5e180b9b9c8e6f31", "name": "opendatalab", "fullname": "OpenDataLab", "avatar": "https://cdn-avatars.huggingface.co/v1/production/uploads/639c3afa7432f2f5d16b7296/yqxxBknyeqkGnYsjoaR4M.png"}, "isAuthorParticipating": false}, {"paper": {"id": "2604.22748", "authors": [{"_id": "69eebcee7bd3cb2932a35e06", "user": {"_id": "63f57aadb51da4d61daaff09", "avatarUrl": "/avatars/c558638d08dd4e564880979e5c90cf67.svg", "isPro": false, "fullname": "meng chu", "user": "TruemanV5", "type": "user", "name": "TruemanV5"}, "name": "Meng Chu", "status": "claimed_verified", "statusLastChangedAt": "2026-04-27T08:54:12.102Z", "hidden": false}, {"_id": "69eebcee7bd3cb2932a35e07", "user": {"_id": "617a46cdff689804c90eca30", "avatarUrl": "/avatars/8c8ec420d2e902e36cef55626e498594.svg", "isPro": false, "fullname": "Xuan \"Billy\" Zhang", "user": "magicgh", "type": "user", "name": "magicgh"}, "name": "Xuan Billy Zhang", "status": "claimed_verified", "statusLastChangedAt": "2026-04-27T08:54:15.002Z", "hidden": false}, {"_id": "69eebcee7bd3cb2932a35e08", "name": "Kevin Qinghong Lin", "hidden": false}, {"_id": "69eebcee7bd3cb2932a35e09", "user": {"_id": "62df78222d89ce551ce0f71d", "avatarUrl": "/avatars/89fba294cff2d2f941d121c1923e4c76.svg", "isPro": false, "fullname": "Lingdong Kong", "user": "ldkong", "type": "user", "name": "ldkong"}, "name": "Lingdong Kong", "status": "claimed_verified", "statusLastChangedAt": "2026-04-27T08:53:55.054Z", "hidden": false}, {"_id": "69eebcee7bd3cb2932a35e0a", "name": "Jize Zhang", "hidden": false}, {"_id": "69eebcee7bd3cb2932a35e0b", "user": {"_id": "6347a75bc849ba78f289eaf5", "avatarUrl": "/avatars/f66099e1479b78e24445e05f6af429ef.svg", "isPro": false, "fullname": "Teng Tu", "user": "tuteng0915", "type": "user", "name": "tuteng0915"}, "name": "Teng Tu", "status": "claimed_verified", "statusLastChangedAt": "2026-04-27T08:53:35.451Z", "hidden": false}, {"_id": "69eebcee7bd3cb2932a35e0c", "user": {"_id": "66a7359280778f0a3ed1fdf7", "avatarUrl": "/avatars/431270dbfc2ca06a8c05ec95319b34e3.svg", "isPro": false, "fullname": "Weijian Ma", "user": "WeijianMa", "type": "user", "name": "WeijianMa"}, "name": "Weijian Ma", "status": "claimed_verified", "statusLastChangedAt": "2026-04-27T08:54:05.417Z", "hidden": false}, {"_id": "69eebcee7bd3cb2932a35e0d", "name": "Ziqi Huang", "hidden": false}, {"_id": "69eebcee7bd3cb2932a35e0e", "name": "Senqiao Yang", "hidden": false}, {"_id": "69eebcee7bd3cb2932a35e0f", "name": "Wei Huang", "hidden": false}, {"_id": "69eebcee7bd3cb2932a35e10", "name": "Yeying Jin", "hidden": false}, {"_id": "69eebcee7bd3cb2932a35e11", "user": {"_id": "654a1b4fcaf723fbb247bc2c", "avatarUrl": "/avatars/1d30c9fc81f0b5baa3b865174a345a4e.svg", "isPro": true, "fullname": "Zhefan Rao", "user": "Glanty", "type": "user", "name": "Glanty"}, "name": "Zhefan Rao", "status": "claimed_verified", "statusLastChangedAt": "2026-04-27T08:53:53.120Z", "hidden": false}, {"_id": "69eebcee7bd3cb2932a35e12", "name": "Jinhui Ye", "hidden": false}, {"_id": "69eebcee7bd3cb2932a35e13", "name": "Xinyu Lin", "hidden": false}, {"_id": "69eebcee7bd3cb2932a35e14", "user": {"_id": "6617c1de028adf787611adf9", "avatarUrl": "/avatars/387ceeca152ae19ce574edffecf7f23c.svg", "isPro": false, "fullname": "Xichen Zhang", "user": "hkuzxc", "type": "user", "name": "hkuzxc"}, "name": "Xichen Zhang", "status": "claimed_verified", "statusLastChangedAt": "2026-04-27T08:54:07.461Z", "hidden": false}, {"_id": "69eebcee7bd3cb2932a35e15", "name": "Qisheng Hu", "hidden": false}, {"_id": "69eebcee7bd3cb2932a35e16", "name": "Shuai Yang", "hidden": false}, {"_id": "69eebcee7bd3cb2932a35e17", "name": "Leyang Shen", "hidden": false}, {"_id": "69eebcee7bd3cb2932a35e18", "name": "Wei Chow", "hidden": false}, {"_id": "69eebcee7bd3cb2932a35e19", "name": "Yifei Dong", "hidden": false}, {"_id": "69eebcee7bd3cb2932a35e1a", "name": "Fengyi Wu", "hidden": false}, {"_id": "69eebcee7bd3cb2932a35e1b", "name": "Quanyu Long", "hidden": false}, {"_id": "69eebcee7bd3cb2932a35e1c", "name": "Bin Xia", "hidden": false}, {"_id": "69eebcee7bd3cb2932a35e1d", "name": "Shaozuo Yu", "hidden": false}, {"_id": "69eebcee7bd3cb2932a35e1e", "user": {"_id": "66955e88490f463859b56ff2", "avatarUrl": "/avatars/e885fc50ffe500aeb61b60821d78f754.svg", "isPro": false, "fullname": "mk", "user": "mk1111", "type": "user", "name": "mk1111"}, "name": "Mingkang Zhu", "status": "claimed_verified", "statusLastChangedAt": "2026-04-27T08:54:03.194Z", "hidden": false}, {"_id": "69eebcee7bd3cb2932a35e1f", "name": "Wenhu Zhang", "hidden": false}, {"_id": "69eebcee7bd3cb2932a35e20", "name": "Jiehui Huang", "hidden": false}, {"_id": "69eebcee7bd3cb2932a35e21", "name": "Haokun Gui", "hidden": false}, {"_id": "69eebcee7bd3cb2932a35e22", "user": {"_id": "652403fe0b84de275c17c015", "avatarUrl": "/avatars/61e1588aecee193d10ced7a3c7fcca1c.svg", "isPro": false, "fullname": "Haoxuan Che", "user": "hche", "type": "user", "name": "hche"}, "name": "Haoxuan Che", "status": "claimed_verified", "statusLastChangedAt": "2026-04-27T08:54:09.920Z", "hidden": false}, {"_id": "69eebcee7bd3cb2932a35e23", "name": "Long Chen", "hidden": false}, {"_id": "69eebcee7bd3cb2932a35e24", "name": "Qifeng Chen", "hidden": false}, {"_id": "69eebcee7bd3cb2932a35e25", "name": "Wenxuan Zhang", "hidden": false}, {"_id": "69eebcee7bd3cb2932a35e26", "name": "Wenya Wang", "hidden": false}, {"_id": "69eebcee7bd3cb2932a35e27", "name": "Xiaojuan Qi", "hidden": false}, {"_id": "69eebcee7bd3cb2932a35e28", "name": "Yang Deng", "hidden": false}, {"_id": "69eebcee7bd3cb2932a35e29", "name": "Yanwei Li", "hidden": false}, {"_id": "69eebcee7bd3cb2932a35e2a", "name": "Mike Zheng Shou", "hidden": false}, {"_id": "69eebcee7bd3cb2932a35e2b", "name": "Zhi-Qi Cheng", "hidden": false}, {"_id": "69eebcee7bd3cb2932a35e2c", "name": "See-Kiong Ng", "hidden": false}, {"_id": "69eebcee7bd3cb2932a35e2d", "name": "Ziwei Liu", "hidden": false}, {"_id": "69eebcee7bd3cb2932a35e2e", "name": "Philip Torr", "hidden": false}, {"_id": "69eebcee7bd3cb2932a35e2f", "name": "Jiaya Jia", "hidden": false}], "publishedAt": "2026-04-24T00:00:00.000Z", "submittedOnDailyAt": "2026-04-27T00:04:03.088Z", "title": "Agentic World Modeling: Foundations, Capabilities, Laws, and Beyond", "submittedOnDailyBy": {"_id": "6039478ab3ecf716b1a5fd4d", "avatarUrl": "https://cdn-avatars.huggingface.co/v1/production/uploads/6039478ab3ecf716b1a5fd4d/_Thy4E7taiSYBLKxEKJbT.jpeg", "isPro": true, "fullname": "taesiri", "user": "taesiri", "type": "user", "name": "taesiri"}, "summary": "As AI systems move from generating text to accomplishing goals through sustained interaction, the ability to model environment dynamics becomes a central bottleneck. Agents that manipulate objects, navigate software, coordinate with others, or design experiments require predictive environment models, yet the term world model carries different meanings across research communities. We introduce a \"levels x laws\" taxonomy organized along two axes. The first defines three capability levels: L1 Predictor, which learns one-step local transition operators; L2 Simulator, which composes them into multi-step, action-conditioned rollouts that respect domain laws; and L3 Evolver, which autonomously revises its own model when predictions fail against new evidence. The second identifies four governing-law regimes: physical, digital, social, and scientific. These regimes determine what constraints a world model must satisfy and where it is most likely to fail. Using this framework, we synthesize over 400 works and summarize more than 100 representative systems spanning model-based reinforcement learning, video generation, web and GUI agents, multi-agent social simulation, and AI-driven scientific discovery. We analyze methods, failure modes, and evaluation practices across level-regime pairs, propose decision-centric evaluation principles and a minimal reproducible evaluation package, and outline architectural guidance, open problems, and governance challenges. The resulting roadmap connects previously isolated communities and charts a path from passive next-step prediction toward world models that can simulate, and ultimately reshape, the environments in which agents operate.", "upvotes": 152, "discussionId": "69eebcef7bd3cb2932a35e30", "projectPage": "https://agentic-world-modeling.xyz/", "githubRepo": "https://github.com/matrix-agent/awesome-agentic-world-modeling", "githubRepoAddedBy": "user", "ai_summary": "World models are categorized into three capability levels and four law regimes to better understand and develop predictive environment models for AI agents across diverse domains.", "ai_keywords": ["world model", "levels x laws taxonomy", "L1 Predictor", "L2 Simulator", "L3 Evolver", "predictive environment models", "model-based reinforcement learning", "video generation", "web agents", "GUI agents", "multi-agent social simulation", "AI-driven scientific discovery", "action-conditioned rollouts", "domain laws", "failure modes", "evaluation practices", "architectural guidance", "open problems", "governance challenges"], "githubStars": 69, "summary_zh": "<ul>\n    <li>AI\u7cfb\u7edf\u7684\u53d1\u5c55\u9700\u8981\u80fd\u591f\u5efa\u6a21\u73af\u5883\u52a8\u6001\uff0c\u4ee5\u5b9e\u73b0\u6301\u7eed\u7684\u4e92\u52a8\u548c\u76ee\u6807\u8fbe\u6210\u3002</li>\n    <li>\u6211\u4eec\u63d0\u51fa\u4e86\u4e00\u4e2a\u201c\u5c42\u6b21\u4e0e\u6cd5\u5219\u201d\u7684\u5206\u7c7b\u6cd5\uff0c\u5206\u4e3a\u4e09\u79cd\u80fd\u529b\u5c42\u7ea7\u548c\u56db\u79cd\u6cbb\u7406\u6cd5\u5219\u3002</li>\n    <li>\u80fd\u529b\u5c42\u7ea7\u5305\u62ec\uff1aL1\u9884\u6d4b\u5668\u3001L2\u6a21\u62df\u5668\u548cL3\u8fdb\u5316\u8005\uff0c\u5206\u522b\u5bf9\u5e94\u4e0d\u540c\u7684\u9884\u6d4b\u548c\u5efa\u6a21\u80fd\u529b\u3002</li>\n    <li>\u6cbb\u7406\u6cd5\u5219\u5305\u62ec\u7269\u7406\u3001\u6570\u5b57\u3001\u793e\u4f1a\u548c\u79d1\u5b66\uff0c\u8fd9\u4e9b\u6cd5\u5219\u51b3\u5b9a\u4e86\u4e16\u754c\u6a21\u578b\u7684\u7ea6\u675f\u548c\u5931\u8d25\u7684\u53ef\u80fd\u6027\u3002</li>\n    <li>\u8be5\u6846\u67b6\u6574\u5408\u4e86400\u591a\u9879\u7814\u7a76\uff0c\u63d0\u4f9b\u4e86\u8bc4\u4f30\u539f\u5219\u3001\u67b6\u6784\u6307\u5bfc\u4ee5\u53ca\u5f00\u653e\u95ee\u9898\u7684\u601d\u8003\u3002</li>\n</ul>", "summary_simple": "<ul>\n    <li>AI systems are evolving from just generating text to achieving goals through ongoing interactions, which requires better understanding of their environments.</li>\n    <li>The authors introduce a taxonomy that categorizes AI models based on their capabilities and the laws governing their environments.</li>\n    <li>There are three levels of capability: L1 Predictor (basic predictions), L2 Simulator (multi-step predictions), and L3 Evolver (self-improvement of the model).</li>\n    <li>Four law regimes are defined: physical, digital, social, and scientific, each with specific constraints and failure points for world models.</li>\n    <li>The framework integrates over 400 research works, suggests evaluation methods, and aims to connect different research communities to improve AI's interaction with its environments.</li>\n</ul>"}, "publishedAt": "2026-04-23T20:00:00.000Z", "title": "Agentic World Modeling: Foundations, Capabilities, Laws, and Beyond", "summary": "As AI systems move from generating text to accomplishing goals through sustained interaction, the ability to model environment dynamics becomes a central bottleneck. Agents that manipulate objects, navigate software, coordinate with others, or design experiments require predictive environment models, yet the term world model carries different meanings across research communities. We introduce a \"levels x laws\" taxonomy organized along two axes. The first defines three capability levels: L1 Predictor, which learns one-step local transition operators; L2 Simulator, which composes them into multi-step, action-conditioned rollouts that respect domain laws; and L3 Evolver, which autonomously revises its own model when predictions fail against new evidence. The second identifies four governing-law regimes: physical, digital, social, and scientific. These regimes determine what constraints a world model must satisfy and where it is most likely to fail. Using this framework, we synthesize over 400 works and summarize more than 100 representative systems spanning model-based reinforcement learning, video generation, web and GUI agents, multi-agent social simulation, and AI-driven scientific discovery. We analyze methods, failure modes, and evaluation practices across level-regime pairs, propose decision-centric evaluation principles and a minimal reproducible evaluation package, and outline architectural guidance, open problems, and governance challenges. The resulting roadmap connects previously isolated communities and charts a path from passive next-step prediction toward world models that can simulate, and ultimately reshape, the environments in which agents operate.", "thumbnail": "https://cdn-thumbnails.huggingface.co/social-thumbnails/papers/2604.22748.png", "numComments": 1, "submittedBy": {"_id": "6039478ab3ecf716b1a5fd4d", "avatarUrl": "https://cdn-avatars.huggingface.co/v1/production/uploads/6039478ab3ecf716b1a5fd4d/_Thy4E7taiSYBLKxEKJbT.jpeg", "fullname": "taesiri", "name": "taesiri", "type": "user", "isPro": true, "isHf": false, "isHfAdmin": false, "isMod": false, "followerCount": 282, "isUserFollowing": false}, "isAuthorParticipating": true}, {"paper": {"id": "2605.22109", "authors": [{"_id": "6a0fb91ea53a61ce2e422c1c", "name": "Caixin Kang", "hidden": false}, {"_id": "6a0fb91ea53a61ce2e422c1d", "name": "Tianyu Yan", "hidden": false}, {"_id": "6a0fb91ea53a61ce2e422c1e", "name": "Sitong Gong", "hidden": false}, {"_id": "6a0fb91ea53a61ce2e422c1f", "name": "Mingfang Zhang", "hidden": false}, {"_id": "6a0fb91ea53a61ce2e422c20", "name": "Liangyang Ouyang", "hidden": false}, {"_id": "6a0fb91ea53a61ce2e422c21", "name": "Ruicong Liu", "hidden": false}, {"_id": "6a0fb91ea53a61ce2e422c22", "name": "Bo Zheng", "hidden": false}, {"_id": "6a0fb91ea53a61ce2e422c23", "name": "Huchuan Lu", "hidden": false}, {"_id": "6a0fb91ea53a61ce2e422c24", "name": "Kaipeng Zhang", "hidden": false}, {"_id": "6a0fb91ea53a61ce2e422c25", "name": "Yoichi Sato", "hidden": false}, {"_id": "6a0fb91ea53a61ce2e422c26", "name": "Yifei Huang", "hidden": false}], "publishedAt": "2026-05-21T00:00:00.000Z", "submittedOnDailyAt": "2026-05-22T00:00:00.000Z", "title": "Perception or Prejudice: Can MLLMs Go Beyond First Impressions of Personality?", "submittedOnDailyBy": {"_id": "63a286c7f30c4642278ed11a", "avatarUrl": "/avatars/974fe4f3023791e97228c53330e9b4f3.svg", "isPro": false, "fullname": "Tim Kang", "user": "Ukpkmkkk", "type": "user", "name": "Ukpkmkkk"}, "summary": "Multimodal Large Language Models (MLLMs) are increasingly deployed in human-facing roles where personality perception is critical, yet existing benchmarks evaluate this capability solely on numerical Big Five score prediction, leaving open whether models truly perceive personality through behavioral understanding or merely prejudge through superficial pattern matching. We address this gap with three contributions. (i) A new task: we formalize Grounded Personality Reasoning (GPR), which requires MLLMs to anchor each Big Five rating in observable evidence through a chain of rating, reasoning, and grounding. (ii) A new dataset: we release MM-OCEAN (1,104 videos, 5,320 MCQs), produced by a multi-agent pipeline with human verification, with timestamped behavioral observations, evidence-grounded trait analyses, and seven categories of cue-grounding MCQs. (iii) Benchmark and analysis: we design a three-tier evaluation (rating, reasoning, grounding) plus four sample-level failure-mode metrics: Prejudice Rate (PR), Confabulation Rate (CR), Integration-failure Rate (IR), and Holistic-grounding Rate (HR), and benchmark 27 MLLMs (13 closed, 14 open). The analysis uncovers a striking Prejudice Gap: across the field, 51% of correct ratings are not grounded in retrieved cues, and the Holistic-Grounding Rate spans only 0-33.5%. These findings expose a disconnect between getting the right score and reasoning for the right reason, charting a roadmap for grounded social cognition in MLLMs.", "upvotes": 151, "discussionId": "6a0fb91fa53a61ce2e422c27", "githubRepo": "https://github.com/kkkcx/MM-OCEAN", "githubRepoAddedBy": "user", "ai_summary": "Researchers introduce a new task and dataset for evaluating personality reasoning in multimodal language models, revealing significant gaps between accurate predictions and grounded reasoning processes.", "ai_keywords": ["Multimodal Large Language Models", "Big Five score prediction", "Grounded Personality Reasoning", "MM-OCEAN dataset", "chain of rating", "reasoning", "and grounding", "multi-agent pipeline", "behavioral observations", "evidence-grounded trait analyses", "cue-grounding MCQs", "three-tier evaluation", "Prejudice Rate", "Confabulation Rate", "Integration-failure Rate", "Holistic-grounding Rate"], "githubStars": 5, "organization": {"_id": "6a0fbe68162dc5d32a0057a0", "name": "utokyo-ai", "fullname": "The University of Tokyo", "avatar": "https://cdn-avatars.huggingface.co/v1/production/uploads/63a286c7f30c4642278ed11a/jNLYa73JGG4k3ywpoD_9k.png"}, "summary_zh": "<ul>\n    <li>\u591a\u6a21\u6001\u5927\u8bed\u8a00\u6a21\u578b\uff08MLLMs\uff09\u5728\u9700\u8981\u7406\u89e3\u4e2a\u6027\u7684\u91cd\u8981\u89d2\u8272\u4e2d\u8d8a\u6765\u8d8a\u591a\u5730\u88ab\u5e94\u7528\u3002</li>\n    <li>\u63d0\u51fa\u4e86\u4e00\u79cd\u65b0\u4efb\u52a1\uff1a\u57fa\u4e8e\u53ef\u89c2\u5bdf\u8bc1\u636e\u5bf9\u4e94\u5927\u6027\u683c\u7279\u5f81\u8fdb\u884c\u63a8\u7406\uff08GPR\uff09\u3002</li>\n    <li>\u53d1\u5e03\u4e86\u4e00\u4e2a\u65b0\u6570\u636e\u96c6MM-OCEAN\uff0c\u5305\u62ec1104\u4e2a\u89c6\u9891\u548c5320\u4e2a\u591a\u9879\u9009\u62e9\u9898\uff0c\u6db5\u76d6\u884c\u4e3a\u89c2\u5bdf\u548c\u4e2a\u6027\u5206\u6790\u3002</li>\n    <li>\u8bbe\u8ba1\u4e86\u4e09\u5c42\u6b21\u7684\u8bc4\u4f30\u6807\u51c6\uff0c\u5e76\u5206\u6790\u4e8627\u4e2aMLLMs\u7684\u8868\u73b0\uff0c\u53d1\u73b0\u4e86\u660e\u663e\u7684\u504f\u89c1\u5dee\u8ddd\u3002</li>\n    <li>\u7ed3\u679c\u663e\u793a\uff0c\u867d\u7136\u8bc4\u5206\u6b63\u786e\uff0c\u4f46\u7f3a\u4e4f\u57fa\u4e8e\u8bc1\u636e\u7684\u63a8\u7406\uff0c\u63d0\u793aMLLMs\u5728\u793e\u4f1a\u8ba4\u77e5\u65b9\u9762\u7684\u4e0d\u8db3\u3002</li>\n</ul>", "summary_simple": "<ul>\n    <li>Multimodal Large Language Models (MLLMs) are used in roles where understanding personality is important, but current tests only measure their ability to predict personality scores.</li>\n    <li>The authors introduce a new task called Grounded Personality Reasoning (GPR) that requires MLLMs to support personality ratings with clear evidence.</li>\n    <li>They created a new dataset named MM-OCEAN, which includes over 1,100 videos and multiple-choice questions, with detailed behavioral observations and analyses.</li>\n    <li>The study includes a three-part evaluation system and various metrics to assess how well MLLMs understand personality, revealing a significant gap in their grounding of personality ratings.</li>\n    <li>Findings show that many correct ratings do not rely on actual behavioral cues, highlighting a need for better reasoning in MLLMs' social understanding.</li>\n</ul>"}, "publishedAt": "2026-05-20T20:00:00.000Z", "title": "Perception or Prejudice: Can MLLMs Go Beyond First Impressions of Personality?", "summary": "Multimodal Large Language Models (MLLMs) are increasingly deployed in human-facing roles where personality perception is critical, yet existing benchmarks evaluate this capability solely on numerical Big Five score prediction, leaving open whether models truly perceive personality through behavioral understanding or merely prejudge through superficial pattern matching. We address this gap with three contributions. (i) A new task: we formalize Grounded Personality Reasoning (GPR), which requires MLLMs to anchor each Big Five rating in observable evidence through a chain of rating, reasoning, and grounding. (ii) A new dataset: we release MM-OCEAN (1,104 videos, 5,320 MCQs), produced by a multi-agent pipeline with human verification, with timestamped behavioral observations, evidence-grounded trait analyses, and seven categories of cue-grounding MCQs. (iii) Benchmark and analysis: we design a three-tier evaluation (rating, reasoning, grounding) plus four sample-level failure-mode metrics: Prejudice Rate (PR), Confabulation Rate (CR), Integration-failure Rate (IR), and Holistic-grounding Rate (HR), and benchmark 27 MLLMs (13 closed, 14 open). The analysis uncovers a striking Prejudice Gap: across the field, 51% of correct ratings are not grounded in retrieved cues, and the Holistic-Grounding Rate spans only 0-33.5%. These findings expose a disconnect between getting the right score and reasoning for the right reason, charting a roadmap for grounded social cognition in MLLMs.", "thumbnail": "https://cdn-thumbnails.huggingface.co/social-thumbnails/papers/2605.22109.png", "numComments": 1, "submittedBy": {"_id": "63a286c7f30c4642278ed11a", "avatarUrl": "/avatars/974fe4f3023791e97228c53330e9b4f3.svg", "fullname": "Tim Kang", "name": "Ukpkmkkk", "type": "user", "isPro": false, "isHf": false, "isHfAdmin": false, "isMod": false, "isUserFollowing": false}, "organization": {"_id": "6a0fbe68162dc5d32a0057a0", "name": "utokyo-ai", "fullname": "The University of Tokyo", "avatar": "https://cdn-avatars.huggingface.co/v1/production/uploads/63a286c7f30c4642278ed11a/jNLYa73JGG4k3ywpoD_9k.png"}, "isAuthorParticipating": false}, {"paper": {"id": "2605.13779", "authors": [{"_id": "6a053afab1a8cbabc9f08783", "name": "Mind Lab", "hidden": false}, {"_id": "6a053afab1a8cbabc9f08785", "name": "Song Cao", "hidden": false}, {"_id": "6a053afab1a8cbabc9f08786", "name": "Vic Cao", "hidden": false}, {"_id": "6a053afab1a8cbabc9f08787", "user": {"_id": "64303a4484f3ed1ce62a2c5a", "avatarUrl": "/avatars/99667daaab49a4e1f2c80bf472cc742b.svg", "isPro": false, "fullname": "Andrew Chen", "user": "anchen1011", "type": "user", "name": "anchen1011"}, "name": "Andrew Chen", "status": "claimed_verified", "statusLastChangedAt": "2026-05-14T10:55:18.956Z", "hidden": false}, {"_id": "6a053afab1a8cbabc9f08788", "name": "Kaijie Chen", "hidden": false}, {"_id": "6a053afab1a8cbabc9f08789", "name": "Cleon Cheng", "hidden": false}, {"_id": "6a053afab1a8cbabc9f0878a", "name": "Steven Chiang", "hidden": false}, {"_id": "6a053afab1a8cbabc9f0878b", "name": "Kaixuan Fan", "hidden": false}, {"_id": "6a053afab1a8cbabc9f0878c", "name": "Hera Feng", "hidden": false}, {"_id": "6a053afab1a8cbabc9f0878d", "name": "Huan Feng", "hidden": false}, {"_id": "6a053afab1a8cbabc9f0878e", "name": "Arthur Fu", "hidden": false}, {"_id": "6a053afab1a8cbabc9f0878f", "name": "Jun Gao", "hidden": false}, {"_id": "6a053afab1a8cbabc9f08790", "name": "Hongquan Gu", "hidden": false}, {"_id": "6a053afab1a8cbabc9f08791", "name": "Aaron Guan", "hidden": false}, {"_id": "6a053afab1a8cbabc9f08792", "user": {"_id": "668775b5c82095d2543b47a3", "avatarUrl": "https://cdn-avatars.huggingface.co/v1/production/uploads/noauth/gPgYQAj_WOqTtehiWIa-6.jpeg", "isPro": false, "fullname": "NolanHo", "user": "NolanHo", "type": "user", "name": "NolanHo"}, "name": "Nolan Ho", "status": "claimed_verified", "statusLastChangedAt": "2026-05-14T10:55:22.900Z", "hidden": false}, {"_id": "6a053afab1a8cbabc9f08793", "user": {"_id": "64a0154fbfd4d3ffab930448", "avatarUrl": "https://cdn-avatars.huggingface.co/v1/production/uploads/64a0154fbfd4d3ffab930448/lv3tcTlDO-GkjN3kJx5RQ.jpeg", "isPro": false, "fullname": "Hongmutian", "user": "OriReplication", "type": "user", "name": "OriReplication"}, "name": "Mutian Hong", "status": "claimed_verified", "statusLastChangedAt": "2026-05-14T10:55:20.940Z", "hidden": false}, {"_id": "6a053afab1a8cbabc9f08794", "name": "Hailee Hou", "hidden": false}, {"_id": "6a053afab1a8cbabc9f08795", "name": "Peixuan Hua", "hidden": false}, {"_id": "6a053afab1a8cbabc9f08796", "name": "Charles Huang", "hidden": false}, {"_id": "6a053afab1a8cbabc9f08797", "name": "Miles Jiang", "hidden": false}, {"_id": "6a053afab1a8cbabc9f08798", "name": "Nora Jiang", "hidden": false}, {"_id": "6a053afab1a8cbabc9f08799", "name": "Yuyi Jiang", "hidden": false}, {"_id": "6a053afab1a8cbabc9f0879a", "name": "Qiuyu Jin", "hidden": false}, {"_id": "6a053afab1a8cbabc9f0879b", "name": "Fancy Kong", "hidden": false}, {"_id": "6a053afab1a8cbabc9f0879c", "name": "Andrew Lei", "hidden": false}, {"_id": "6a053afab1a8cbabc9f0879d", "user": {"_id": "65756c5e1488186315c6696d", "avatarUrl": "/avatars/2ec67e0d1921b6635c69669b591a3110.svg", "isPro": false, "fullname": "Jingdi Lei", "user": "huaXiaKyrie", "type": "user", "name": "huaXiaKyrie"}, "name": "Kyrie Lei", "status": "claimed_verified", "statusLastChangedAt": "2026-05-14T10:55:26.345Z", "hidden": false}, {"_id": "6a053afab1a8cbabc9f0879e", "name": "Alexy Li", "hidden": false}, {"_id": "6a053afab1a8cbabc9f0879f", "name": "Lucian Li", "hidden": false}, {"_id": "6a053afab1a8cbabc9f087a0", "name": "Ray Li", "hidden": false}, {"_id": "6a053afab1a8cbabc9f087a1", "name": "Theo Li", "hidden": false}, {"_id": "6a053afab1a8cbabc9f087a2", "name": "Zhihui Li", "hidden": false}, {"_id": "6a053afab1a8cbabc9f087a3", "name": "Jiayi Lin", "hidden": false}, {"_id": "6a053afab1a8cbabc9f087a4", "name": "Kairus Liu", "hidden": false}, {"_id": "6a053afab1a8cbabc9f087a5", "name": "Kieran Liu", "hidden": false}, {"_id": "6a053afab1a8cbabc9f087a6", "name": "Logan Liu", "hidden": false}, {"_id": "6a053afab1a8cbabc9f087a7", "name": "Xiang Liu", "hidden": false}, {"_id": "6a053afab1a8cbabc9f087a8", "name": "Irvine Lu", "hidden": false}, {"_id": "6a053afab1a8cbabc9f087a9", "name": "Maeve Luo", "hidden": false}, {"_id": "6a053afab1a8cbabc9f087aa", "name": "Runze Lv", "hidden": false}, {"_id": "6a053afab1a8cbabc9f087ab", "name": "Pony Ma", "hidden": false}, {"_id": "6a053afab1a8cbabc9f087ac", "name": "Verity Niu", "hidden": false}, {"_id": "6a053afab1a8cbabc9f087ad", "name": "Anson Qiu", "hidden": false}, {"_id": "6a053afab1a8cbabc9f087ae", "name": "Vincent Wang", "hidden": false}, {"_id": "6a053afab1a8cbabc9f087af", "name": "Rio Yang", "hidden": false}, {"_id": "6a053afab1a8cbabc9f087b0", "name": "Maxwell Yao", "hidden": false}, {"_id": "6a053afab1a8cbabc9f087b1", "name": "Carrie Ye", "hidden": false}, {"_id": "6a053afab1a8cbabc9f087b2", "name": "Regis Ye", "hidden": false}, {"_id": "6a053afab1a8cbabc9f087b3", "name": "Wenlin Ye", "hidden": false}, {"_id": "6a053afab1a8cbabc9f087b4", "user": {"_id": "6240c0c9d35be2c16ccfbe41", "avatarUrl": "/avatars/d30d6c029a89939e7802f590480c5492.svg", "isPro": false, "fullname": "Josh Ying", "user": "zfying", "type": "user", "name": "zfying"}, "name": "Josh Ying", "status": "claimed_verified", "statusLastChangedAt": "2026-05-14T10:55:14.972Z", "hidden": false}, {"_id": "6a053afab1a8cbabc9f087b5", "name": "Danney Zeng", "hidden": false}, {"_id": "6a053afab1a8cbabc9f087b6", "name": "Yuhan Zhan", "hidden": false}, {"_id": "6a053afab1a8cbabc9f087b7", "name": "Anya Zhang", "hidden": false}, {"_id": "6a053afab1a8cbabc9f087b8", "user": {"_id": "64bce15bafd1e46c5504ad38", "avatarUrl": "https://cdn-avatars.huggingface.co/v1/production/uploads/64bce15bafd1e46c5504ad38/vkEjiu-mIagKlrXzDH75o.png", "isPro": false, "fullname": "Di Zhang", "user": "di-zhang-fdu", "type": "user", "name": "di-zhang-fdu"}, "name": "Di Zhang", "status": "claimed_verified", "statusLastChangedAt": "2026-05-14T10:55:16.976Z", "hidden": false}, {"_id": "6a053afab1a8cbabc9f087b9", "name": "Ruijia Zhang", "hidden": false}, {"_id": "6a053afab1a8cbabc9f087ba", "name": "Sueky Zhang", "hidden": false}, {"_id": "6a053afab1a8cbabc9f087bb", "name": "Ya Zhang", "hidden": false}, {"_id": "6a053afab1a8cbabc9f087bc", "name": "Wei Zhao", "hidden": false}, {"_id": "6a053afab1a8cbabc9f087bd", "name": "Ada Zhou", "hidden": false}, {"_id": "6a053afab1a8cbabc9f087be", "name": "Changhai Zhou", "hidden": false}, {"_id": "6a053afab1a8cbabc9f087bf", "name": "Yuhua Zhou", "hidden": false}, {"_id": "6a053afab1a8cbabc9f087c0", "name": "Xinyue Zhu", "hidden": false}, {"_id": "6a053afab1a8cbabc9f087c1", "name": "Murphy Zhuang", "hidden": false}], "publishedAt": "2026-05-13T00:00:00.000Z", "submittedOnDailyAt": "2026-05-14T00:00:00.000Z", "title": "MinT: Managed Infrastructure for Training and Serving Millions of LLMs", "submittedOnDailyBy": {"_id": "64303a4484f3ed1ce62a2c5a", "avatarUrl": "/avatars/99667daaab49a4e1f2c80bf472cc742b.svg", "isPro": false, "fullname": "Andrew Chen", "user": "anchen1011", "type": "user", "name": "anchen1011"}, "summary": "We present MindLab Toolkit (MinT), a managed infrastructure system for Low-Rank Adaptation (LoRA) post-training and online serving. MinT targets a setting where many trained policies are produced over a small number of expensive base-model deployments. Instead of materializing each policy as a merged full checkpoint, MinT keeps the base model resident and moves exported LoRA adapter revisions through rollout, update, export, evaluation, serving, and rollback, hiding distributed training, serving, scheduling, and data movement behind a service interface. MinT scales this path along three axes. Scale Up extends LoRA RL to frontier-scale dense and MoE architectures, including MLA and DSA attention paths, with training and serving validated beyond 1T total parameters. Scale Down moves only the exported LoRA adapter, which can be under 1% of base-model size in rank-1 settings; adapter-only handoff reduces the measured step by 18.3x on a 4B dense model and 2.85x on a 30B MoE, while concurrent multi-policy GRPO shortens wall time by 1.77x and 1.45x without raising peak memory. Scale Out separates durable policy addressability from CPU/GPU working sets: a tensor-parallel deployment supports 10^6-scale addressable catalogs (measured single-engine sweeps through 100K) and thousand-adapter active waves at cluster scale, with cold loading treated as scheduled service work and packed MoE LoRA tensors improving live engine loading by 8.5-8.7x. MinT thus manages million-scale LoRA policy catalogs while training and serving selected adapter revisions over shared 1T-class base models.", "upvotes": 143, "discussionId": "6a053afab1a8cbabc9f087c2", "projectPage": "https://macaron.im/mindlab/mint", "githubRepo": "https://github.com/MindLab-Research/mindlab-toolkit", "githubRepoAddedBy": "user", "ai_summary": "MinT is a managed infrastructure system that enables efficient low-rank adaptation training and serving by keeping base models resident and moving lightweight adapter revisions, scaling across multiple dimensions including large model architectures, reduced storage requirements, and distributed policy management.", "ai_keywords": ["Low-Rank Adaptation", "LoRA", "post-training", "online serving", "base-model deployments", "full checkpoint", "adapter revisions", "distributed training", "serving", "scheduling", "data movement", "service interface", "scale up", "dense architectures", "MoE architectures", "MLA attention", "DSA attention", "scale down", "adapter-only handoff", "scale out", "tensor-parallel deployment", "policy catalogs", "GRPO", "peak memory", "cold loading", "packed MoE tensors"], "githubStars": 31, "organization": {"_id": "69d05e49e99e437a3b18bebc", "name": "mindlab-research", "fullname": "Mind Lab", "avatar": "https://cdn-avatars.huggingface.co/v1/production/uploads/64303a4484f3ed1ce62a2c5a/0L3sMuvL2JGls3zUKOKYU.jpeg"}, "summary_zh": "<ul>\n    <li>MindLab Toolkit (MinT) \u662f\u4e00\u4e2a\u7528\u4e8e\u4f4e\u79e9\u9002\u5e94\uff08LoRA\uff09\u540e\u8bad\u7ec3\u548c\u5728\u7ebf\u670d\u52a1\u7684\u7ba1\u7406\u57fa\u7840\u8bbe\u65bd\u7cfb\u7edf\u3002</li>\n    <li>MinT \u65e8\u5728\u5904\u7406\u8bb8\u591a\u8bad\u7ec3\u7b56\u7565\u5728\u5c11\u91cf\u6602\u8d35\u57fa\u7840\u6a21\u578b\u90e8\u7f72\u4e2d\u7684\u60c5\u51b5\uff0c\u4e0d\u9700\u8981\u5c06\u6bcf\u4e2a\u7b56\u7565\u5408\u5e76\u4e3a\u5b8c\u6574\u68c0\u67e5\u70b9\u3002</li>\n    <li>\u6b64\u7cfb\u7edf\u901a\u8fc7\u670d\u52a1\u63a5\u53e3\u9690\u85cf\u4e86\u5206\u5e03\u5f0f\u8bad\u7ec3\u3001\u670d\u52a1\u3001\u8c03\u5ea6\u548c\u6570\u636e\u79fb\u52a8\u7684\u590d\u6742\u6027\u3002</li>\n    <li>MinT \u5728\u591a\u4e2a\u65b9\u9762\u8fdb\u884c\u6269\u5c55\uff0c\u5305\u62ec\u652f\u6301\u66f4\u5927\u89c4\u6a21\u7684 LoRA \u5f3a\u5316\u5b66\u4e60\u548c\u9ad8\u6548\u7684\u6a21\u578b\u67b6\u6784\u3002</li>\n    <li>\u5b83\u80fd\u591f\u7ba1\u7406\u767e\u4e07\u7ea7\u7684 LoRA \u7b56\u7565\u76ee\u5f55\uff0c\u5e76\u5728\u5171\u4eab\u7684\u57fa\u7840\u6a21\u578b\u4e0a\u8fdb\u884c\u8bad\u7ec3\u548c\u670d\u52a1\u3002</li>\n</ul>", "summary_simple": "<ul>\n    <li>MindLab Toolkit (MinT) is a system designed to manage Low-Rank Adaptation (LoRA) for machine learning models after training and during online use.</li>\n    <li>MinT avoids creating multiple full model versions by keeping a base model and using smaller LoRA adapters for different trained policies.</li>\n    <li>The system improves efficiency by reducing the size of the LoRA adapters and speeding up processes like training and serving models.</li>\n    <li>It can handle very large models with over a trillion parameters and allows for quick access to many different model policies without needing more memory.</li>\n    <li>MinT enables the management of a large number of LoRA policies while using shared base models, making it effective for large-scale applications.</li>\n</ul>"}, "publishedAt": "2026-05-12T20:00:00.000Z", "title": "MinT: Managed Infrastructure for Training and Serving Millions of LLMs", "summary": "We present MindLab Toolkit (MinT), a managed infrastructure system for Low-Rank Adaptation (LoRA) post-training and online serving. MinT targets a setting where many trained policies are produced over a small number of expensive base-model deployments. Instead of materializing each policy as a merged full checkpoint, MinT keeps the base model resident and moves exported LoRA adapter revisions through rollout, update, export, evaluation, serving, and rollback, hiding distributed training, serving, scheduling, and data movement behind a service interface. MinT scales this path along three axes. Scale Up extends LoRA RL to frontier-scale dense and MoE architectures, including MLA and DSA attention paths, with training and serving validated beyond 1T total parameters. Scale Down moves only the exported LoRA adapter, which can be under 1% of base-model size in rank-1 settings; adapter-only handoff reduces the measured step by 18.3x on a 4B dense model and 2.85x on a 30B MoE, while concurrent multi-policy GRPO shortens wall time by 1.77x and 1.45x without raising peak memory. Scale Out separates durable policy addressability from CPU/GPU working sets: a tensor-parallel deployment supports 10^6-scale addressable catalogs (measured single-engine sweeps through 100K) and thousand-adapter active waves at cluster scale, with cold loading treated as scheduled service work and packed MoE LoRA tensors improving live engine loading by 8.5-8.7x. MinT thus manages million-scale LoRA policy catalogs while training and serving selected adapter revisions over shared 1T-class base models.", "thumbnail": "https://cdn-thumbnails.huggingface.co/social-thumbnails/papers/2605.13779.png", "numComments": 3, "submittedBy": {"_id": "64303a4484f3ed1ce62a2c5a", "avatarUrl": "/avatars/99667daaab49a4e1f2c80bf472cc742b.svg", "fullname": "Andrew Chen", "name": "anchen1011", "type": "user", "isPro": false, "isHf": false, "isHfAdmin": false, "isMod": false, "followerCount": 5, "isUserFollowing": false}, "organization": {"_id": "69d05e49e99e437a3b18bebc", "name": "mindlab-research", "fullname": "Mind Lab", "avatar": "https://cdn-avatars.huggingface.co/v1/production/uploads/64303a4484f3ed1ce62a2c5a/0L3sMuvL2JGls3zUKOKYU.jpeg"}, "isAuthorParticipating": true}, {"paper": {"id": "2605.18747", "authors": [{"_id": "6a0bd45c8ca2d0b2563803fe", "name": "Xuying Ning", "hidden": false}, {"_id": "6a0bd45c8ca2d0b2563803ff", "name": "Katherine Tieu", "hidden": false}, {"_id": "6a0bd45c8ca2d0b256380400", "name": "Dongqi Fu", "hidden": false}, {"_id": "6a0bd45c8ca2d0b256380401", "name": "Tianxin Wei", "hidden": false}, {"_id": "6a0bd45c8ca2d0b256380402", "name": "Zihao Li", "hidden": false}, {"_id": "6a0bd45c8ca2d0b256380403", "name": "Yuanchen Bei", "hidden": false}, {"_id": "6a0bd45c8ca2d0b256380404", "name": "Jiaru Zou", "hidden": false}, {"_id": "6a0bd45c8ca2d0b256380405", "name": "Mengting Ai", "hidden": false}, {"_id": "6a0bd45c8ca2d0b256380406", "name": "Zhining Liu", "hidden": false}, {"_id": "6a0bd45c8ca2d0b256380407", "name": "Ting-Wei Li", "hidden": false}, {"_id": "6a0bd45c8ca2d0b256380408", "name": "Lingjie Chen", "hidden": false}, {"_id": "6a0bd45c8ca2d0b256380409", "name": "Yanjun Zhao", "hidden": false}, {"_id": "6a0bd45c8ca2d0b25638040a", "name": "Ke Yang", "hidden": false}, {"_id": "6a0bd45c8ca2d0b25638040b", "name": "Bingxuan Li", "hidden": false}, {"_id": "6a0bd45c8ca2d0b25638040c", "name": "Cheng Qian", "hidden": false}, {"_id": "6a0bd45c8ca2d0b25638040d", "name": "Gaotang Li", "hidden": false}, {"_id": "6a0bd45c8ca2d0b25638040e", "name": "Xiao Lin", "hidden": false}, {"_id": "6a0bd45c8ca2d0b25638040f", "name": "Zhichen Zeng", "hidden": false}, {"_id": "6a0bd45c8ca2d0b256380410", "name": "Ruizhong Qiu", "hidden": false}, {"_id": "6a0bd45c8ca2d0b256380411", "name": "Sirui Chen", "hidden": false}, {"_id": "6a0bd45c8ca2d0b256380412", "name": "Yifan Sun", "hidden": false}, {"_id": "6a0bd45c8ca2d0b256380413", "name": "Xiyuan Yang", "hidden": false}, {"_id": "6a0bd45c8ca2d0b256380414", "name": "Ruida Wang", "hidden": false}, {"_id": "6a0bd45c8ca2d0b256380415", "name": "Rui Pan", "hidden": false}, {"_id": "6a0bd45c8ca2d0b256380416", "name": "Chenyuan Yang", "hidden": false}, {"_id": "6a0bd45c8ca2d0b256380417", "name": "Dylan Zhang", "hidden": false}, {"_id": "6a0bd45c8ca2d0b256380418", "name": "Liri Fang", "hidden": false}, {"_id": "6a0bd45c8ca2d0b256380419", "name": "Zikun Cui", "hidden": false}, {"_id": "6a0bd45c8ca2d0b25638041a", "name": "Yang Cao", "hidden": false}, {"_id": "6a0bd45c8ca2d0b25638041b", "name": "Pan Chen", "hidden": false}, {"_id": "6a0bd45c8ca2d0b25638041c", "name": "Dorothy Sun", "hidden": false}, {"_id": "6a0bd45c8ca2d0b25638041d", "name": "Ren Chen", "hidden": false}, {"_id": "6a0bd45c8ca2d0b25638041e", "name": "Mahesh Srinivasan", "hidden": false}, {"_id": "6a0bd45c8ca2d0b25638041f", "name": "Nipun Mathur", "hidden": false}, {"_id": "6a0bd45c8ca2d0b256380420", "name": "Yinglong Xia", "hidden": false}, {"_id": "6a0bd45c8ca2d0b256380421", "name": "Hong Li", "hidden": false}, {"_id": "6a0bd45c8ca2d0b256380422", "name": "Hong Yan", "hidden": false}, {"_id": "6a0bd45c8ca2d0b256380423", "name": "Pan Lu", "hidden": false}, {"_id": "6a0bd45c8ca2d0b256380424", "name": "Lingming Zhang", "hidden": false}, {"_id": "6a0bd45c8ca2d0b256380425", "name": "Tong Zhang", "hidden": false}, {"_id": "6a0bd45c8ca2d0b256380426", "name": "Hanghang Tong", "hidden": false}, {"_id": "6a0bd45c8ca2d0b256380427", "name": "Jingrui He", "hidden": false}], "publishedAt": "2026-05-18T00:00:00.000Z", "submittedOnDailyAt": "2026-05-19T00:00:00.000Z", "title": "Code as Agent Harness", "submittedOnDailyBy": {"_id": "6039478ab3ecf716b1a5fd4d", "avatarUrl": "https://cdn-avatars.huggingface.co/v1/production/uploads/6039478ab3ecf716b1a5fd4d/_Thy4E7taiSYBLKxEKJbT.jpeg", "isPro": true, "fullname": "taesiri", "user": "taesiri", "type": "user", "name": "taesiri"}, "summary": "Recent large language models (LLMs) have demonstrated strong capabilities in understanding and generating code, from competitive programming to repository-level software engineering. In emerging agentic systems, code is no longer only a target output. It increasingly serves as an operational substrate for agent reasoning, acting, environment modeling, and execution-based verification. We frame this shift through the lens of agent harnesses and introduce code as agent harness: a unified view that centers code as the basis for agent infrastructure. To systematically study this perspective, we organize the survey around three connected layers. First, we study the harness interface, where code connects agents to reasoning, action, and environment modeling. Second, we examine harness mechanisms: planning, memory, and tool use for long-horizon execution, together with feedback-driven control and optimization that make harness reliable and adaptive. Third, we discuss scaling the harness from single-agent systems to multi-agent settings, where shared code artifacts support multi-agent coordination, review, and verification. Across these layers, we summarize representative methods and practical applications of code as agent harness, spanning coding assistants, GUI/OS automation, embodied agents, scientific discovery, personalization and recommendation, DevOps, and enterprise workflows. We further outline open challenges for harness engineering, including evaluation beyond final task success, verification under incomplete feedback, regression-free harness improvement, consistent shared state across multiple agents, human oversight for safety-critical actions, and extensions to multimodal environments. By centering code as the harness of agentic AI, this survey provides a unified roadmap toward executable, verifiable, and stateful AI agent systems.", "upvotes": 137, "discussionId": "6a0bd45c8ca2d0b256380428", "githubRepo": "https://github.com/YennNing/Awesome-Code-as-Agent-Harness-Papers", "githubRepoAddedBy": "user", "ai_summary": "Large language models are increasingly used as operational substrates for agent reasoning and execution in agentic systems, with code serving as a unified infrastructure layer across multiple domains and applications.", "ai_keywords": ["large language models", "agentic systems", "agent harness", "code as agent harness", "agent infrastructure", "reasoning", "action", "environment modeling", "planning", "memory", "tool use", "feedback-driven control", "optimization", "multi-agent coordination", "DevOps", "enterprise workflows"], "githubStars": 24, "summary_zh": "<ul>\n    <li>\u6700\u8fd1\u7684\u5927\u578b\u8bed\u8a00\u6a21\u578b\u5728\u7406\u89e3\u548c\u751f\u6210\u4ee3\u7801\u65b9\u9762\u8868\u73b0\u51fa\u5f3a\u5927\u7684\u80fd\u529b\uff0c\u9002\u7528\u4e8e\u7ade\u4e89\u7f16\u7a0b\u548c\u8f6f\u4ef6\u5de5\u7a0b\u3002</li>\n    <li>\u4ee3\u7801\u4e0d\u4ec5\u662f\u8f93\u51fa\u7ed3\u679c\uff0c\u8fd8\u6210\u4e3a\u4ee3\u7406\u63a8\u7406\u3001\u884c\u52a8\u3001\u73af\u5883\u5efa\u6a21\u548c\u6267\u884c\u9a8c\u8bc1\u7684\u57fa\u7840\u3002</li>\n    <li>\u672c\u6587\u5c06\u4ee3\u7801\u89c6\u4e3a\u201c\u4ee3\u7406\u5de5\u5177\u201d\uff0c\u5e76\u4ece\u4e09\u4e2a\u5c42\u9762\u8fdb\u884c\u7814\u7a76\uff1a\u63a5\u53e3\u3001\u673a\u5236\u548c\u591a\u4ee3\u7406\u6269\u5c55\u3002</li>\n    <li>\u7814\u7a76\u5185\u5bb9\u5305\u62ec\u7f16\u7801\u52a9\u624b\u3001GUI/\u64cd\u4f5c\u7cfb\u7edf\u81ea\u52a8\u5316\u3001\u79d1\u5b66\u53d1\u73b0\u7b49\u5b9e\u9645\u5e94\u7528\uff0c\u4ee5\u53ca\u5de5\u7a0b\u4e2d\u7684\u5f00\u653e\u6311\u6218\u3002</li>\n    <li>\u901a\u8fc7\u5c06\u4ee3\u7801\u4f5c\u4e3a\u4ee3\u7406AI\u7684\u57fa\u7840\uff0c\u63d0\u4f9b\u4e86\u53ef\u6267\u884c\u3001\u53ef\u9a8c\u8bc1\u548c\u72b6\u6001\u4fdd\u6301\u7684AI\u4ee3\u7406\u7cfb\u7edf\u7684\u7edf\u4e00\u8def\u7ebf\u56fe\u3002</li>\n</ul>", "summary_simple": "<ul>\n    <li>Recent language models can understand and generate code, making it useful for software engineering and problem-solving.</li>\n    <li>Code is becoming essential for AI agents, helping them think, act, and model their environments.</li>\n    <li>The survey explores three main areas: how code connects agents to their tasks, the mechanisms that help agents execute plans, and how to scale these systems for multiple agents working together.</li>\n    <li>It covers practical uses of code in various fields like coding assistance, automation, and scientific research.</li>\n    <li>The survey also identifies challenges in harnessing code for AI, such as improving reliability, ensuring safety, and managing multiple agents effectively.</li>\n</ul>"}, "publishedAt": "2026-05-17T20:00:00.000Z", "title": "Code as Agent Harness", "summary": "Recent large language models (LLMs) have demonstrated strong capabilities in understanding and generating code, from competitive programming to repository-level software engineering. In emerging agentic systems, code is no longer only a target output. It increasingly serves as an operational substrate for agent reasoning, acting, environment modeling, and execution-based verification. We frame this shift through the lens of agent harnesses and introduce code as agent harness: a unified view that centers code as the basis for agent infrastructure. To systematically study this perspective, we organize the survey around three connected layers. First, we study the harness interface, where code connects agents to reasoning, action, and environment modeling. Second, we examine harness mechanisms: planning, memory, and tool use for long-horizon execution, together with feedback-driven control and optimization that make harness reliable and adaptive. Third, we discuss scaling the harness from single-agent systems to multi-agent settings, where shared code artifacts support multi-agent coordination, review, and verification. Across these layers, we summarize representative methods and practical applications of code as agent harness, spanning coding assistants, GUI/OS automation, embodied agents, scientific discovery, personalization and recommendation, DevOps, and enterprise workflows. We further outline open challenges for harness engineering, including evaluation beyond final task success, verification under incomplete feedback, regression-free harness improvement, consistent shared state across multiple agents, human oversight for safety-critical actions, and extensions to multimodal environments. By centering code as the harness of agentic AI, this survey provides a unified roadmap toward executable, verifiable, and stateful AI agent systems.", "thumbnail": "https://cdn-thumbnails.huggingface.co/social-thumbnails/papers/2605.18747.png", "numComments": 3, "submittedBy": {"_id": "6039478ab3ecf716b1a5fd4d", "avatarUrl": "https://cdn-avatars.huggingface.co/v1/production/uploads/6039478ab3ecf716b1a5fd4d/_Thy4E7taiSYBLKxEKJbT.jpeg", "fullname": "taesiri", "name": "taesiri", "type": "user", "isPro": true, "isHf": false, "isHfAdmin": false, "isMod": false, "followerCount": 300, "isUserFollowing": false}, "isAuthorParticipating": false}, {"paper": {"id": "2605.15298", "authors": [{"_id": "6a0aaa5275184a0d71e02730", "name": "Shijie Lian", "hidden": false}, {"_id": "6a0aaa5275184a0d71e02731", "user": {"_id": "63d3b5f1640bb0f77173baea", "avatarUrl": "https://cdn-avatars.huggingface.co/v1/production/uploads/1674819020331-noauth.jpeg", "isPro": false, "fullname": "yubin", "user": "VLyb", "type": "user", "name": "VLyb"}, "name": "Bin Yu", "status": "claimed_verified", "statusLastChangedAt": "2026-05-18T07:46:18.138Z", "hidden": false}, {"_id": "6a0aaa5275184a0d71e02732", "name": "Xiaopeng Lin", "hidden": false}, {"_id": "6a0aaa5275184a0d71e02733", "name": "Changti Wu", "hidden": false}, {"_id": "6a0aaa5275184a0d71e02734", "name": "Hang Yuan", "hidden": false}, {"_id": "6a0aaa5275184a0d71e02735", "name": "Xiaolin Hu", "hidden": false}, {"_id": "6a0aaa5275184a0d71e02736", "name": "Zhaolong Shen", "hidden": false}, {"_id": "6a0aaa5275184a0d71e02737", "name": "Yuzhuo Miao", "hidden": false}, {"_id": "6a0aaa5275184a0d71e02738", "name": "Haishan Liu", "hidden": false}, {"_id": "6a0aaa5275184a0d71e02739", "name": "Yuxuan Tian", "hidden": false}, {"_id": "6a0aaa5275184a0d71e0273a", "name": "Yukun Shi", "hidden": false}, {"_id": "6a0aaa5275184a0d71e0273b", "name": "Cong Huang", "hidden": false}, {"_id": "6a0aaa5275184a0d71e0273c", "name": "Kai Chen", "hidden": false}], "publishedAt": "2026-05-14T00:00:00.000Z", "submittedOnDailyAt": "2026-05-18T00:00:00.000Z", "title": "PhysBrain 1.0 Technical Report", "submittedOnDailyBy": {"_id": "65ec01fd770aa0e25d9374dc", "avatarUrl": "https://cdn-avatars.huggingface.co/v1/production/uploads/65ec01fd770aa0e25d9374dc/yvLWwBEdAdHb-8EdUHg3n.jpeg", "isPro": false, "fullname": "Shijie Lian", "user": "LiamLian0727", "type": "user", "name": "LiamLian0727"}, "summary": "Vision-language-action models have advanced rapidly, but robot trajectories alone provide limited coverage for learning broad physical understanding. PhysBrain 1.0 studies a complementary route: converting large-scale human egocentric video into structured physical commonsense supervision before robot adaptation. Our data engine extracts scene elements, spatial dynamics, action execution, and depth-aware relations, then turns them into question-answer supervision for training PhysBrain VLMs. The resulting physical priors are further transferred to VLA policies through a capability-preserving and language-sensitive adaptation design. Across multimodal QA benchmarks and embodied control benchmarks, including ERQA, PhysBench, SimplerEnv-WidowX, LIBERO, and RoboCasa, PhysBrain 1.0 achieves SOTA results and shows especially strong out-of-domain performance on SimplerEnv. These results suggest that scaling physical commonsense from human interaction video can provide an effective bridge from multimodal understanding to robot action.", "upvotes": 130, "discussionId": "6a0aaa5375184a0d71e0273d", "projectPage": "https://phys-brain.github.io/", "githubRepo": "https://github.com/Phys-Brain/PhysBrain-VLA", "githubRepoAddedBy": "user", "ai_summary": "PhysBrain 1.0 leverages human egocentric video to generate physical commonsense supervision for vision-language-action models, achieving state-of-the-art performance in embodied control tasks through capability-preserving adaptation.", "ai_keywords": ["vision-language-action models", "physical commonsense supervision", "multimodal QA benchmarks", "embodied control benchmarks", "VLA policies", "capability-preserving adaptation", "language-sensitive adaptation"], "githubStars": 9, "organization": {"_id": "6948d884070dda0c2ae35a78", "name": "DeepCybo", "fullname": "DeepCybo", "avatar": "https://cdn-avatars.huggingface.co/v1/production/uploads/65ec01fd770aa0e25d9374dc/QOsz6P_7AxyqGrjsRHTGk.png"}, "summary_zh": "<ul>\n    <li>PhysBrain 1.0 \u901a\u8fc7\u5c06\u4eba\u7c7b\u7b2c\u4e00\u4eba\u79f0\u89c6\u9891\u8f6c\u5316\u4e3a\u7ed3\u6784\u5316\u7684\u7269\u7406\u5e38\u8bc6\u76d1\u7763\uff0c\u6765\u5e2e\u52a9\u673a\u5668\u5b66\u4e60\u7269\u7406\u7406\u89e3\u3002</li>\n    <li>\u6570\u636e\u5f15\u64ce\u63d0\u53d6\u573a\u666f\u5143\u7d20\u3001\u7a7a\u95f4\u52a8\u6001\u3001\u52a8\u4f5c\u6267\u884c\u548c\u6df1\u5ea6\u5173\u7cfb\uff0c\u5e76\u5c06\u8fd9\u4e9b\u4fe1\u606f\u8f6c\u5316\u4e3a\u95ee\u7b54\u76d1\u7763\uff0c\u7528\u4e8e\u8bad\u7ec3\u7269\u7406\u8bed\u8a00\u6a21\u578b\u3002</li>\n    <li>\u8fd9\u4e9b\u7269\u7406\u5148\u9a8c\u77e5\u8bc6\u901a\u8fc7\u4e00\u79cd\u80fd\u529b\u4fdd\u6301\u548c\u8bed\u8a00\u654f\u611f\u7684\u9002\u5e94\u8bbe\u8ba1\uff0c\u8f6c\u79fb\u5230\u89c6\u89c9\u8bed\u8a00\u884c\u52a8\u653f\u7b56\u4e2d\u3002</li>\n    <li>\u5728\u591a\u6a21\u6001\u95ee\u7b54\u548c\u673a\u5668\u4eba\u63a7\u5236\u57fa\u51c6\u6d4b\u8bd5\u4e2d\uff0cPhysBrain 1.0 \u8fbe\u5230\u4e86\u6700\u65b0\u7684\u6280\u672f\u6c34\u5e73\uff0c\u5e76\u5728\u67d0\u4e9b\u6d4b\u8bd5\u4e2d\u8868\u73b0\u51fa\u8272\u3002</li>\n    <li>\u7814\u7a76\u8868\u660e\uff0c\u4ece\u4eba\u7c7b\u4ea4\u4e92\u89c6\u9891\u4e2d\u6269\u5c55\u7269\u7406\u5e38\u8bc6\u53ef\u4ee5\u6709\u6548\u5730\u8fde\u63a5\u591a\u6a21\u6001\u7406\u89e3\u4e0e\u673a\u5668\u4eba\u884c\u52a8\u3002</li>\n</ul>", "summary_simple": "<ul>\n    <li>PhysBrain 1.0 improves robot learning by using human videos to understand physical interactions better.</li>\n    <li>It extracts important details like scene elements and actions from videos and creates questions and answers for training.</li>\n    <li>The model shows strong performance across various benchmarks, especially in new environments.</li>\n    <li>This approach helps robots connect understanding from different types of data to perform better actions.</li>\n</ul>"}, "publishedAt": "2026-05-13T20:00:00.000Z", "title": "PhysBrain 1.0 Technical Report", "summary": "Vision-language-action models have advanced rapidly, but robot trajectories alone provide limited coverage for learning broad physical understanding. PhysBrain 1.0 studies a complementary route: converting large-scale human egocentric video into structured physical commonsense supervision before robot adaptation. Our data engine extracts scene elements, spatial dynamics, action execution, and depth-aware relations, then turns them into question-answer supervision for training PhysBrain VLMs. The resulting physical priors are further transferred to VLA policies through a capability-preserving and language-sensitive adaptation design. Across multimodal QA benchmarks and embodied control benchmarks, including ERQA, PhysBench, SimplerEnv-WidowX, LIBERO, and RoboCasa, PhysBrain 1.0 achieves SOTA results and shows especially strong out-of-domain performance on SimplerEnv. These results suggest that scaling physical commonsense from human interaction video can provide an effective bridge from multimodal understanding to robot action.", "thumbnail": "https://cdn-thumbnails.huggingface.co/social-thumbnails/papers/2605.15298.png", "numComments": 1, "submittedBy": {"_id": "65ec01fd770aa0e25d9374dc", "avatarUrl": "https://cdn-avatars.huggingface.co/v1/production/uploads/65ec01fd770aa0e25d9374dc/yvLWwBEdAdHb-8EdUHg3n.jpeg", "fullname": "Shijie Lian", "name": "LiamLian0727", "type": "user", "isPro": false, "isHf": false, "isHfAdmin": false, "isMod": false, "followerCount": 11, "isUserFollowing": false}, "organization": {"_id": "6948d884070dda0c2ae35a78", "name": "DeepCybo", "fullname": "DeepCybo", "avatar": "https://cdn-avatars.huggingface.co/v1/production/uploads/65ec01fd770aa0e25d9374dc/QOsz6P_7AxyqGrjsRHTGk.png"}, "isAuthorParticipating": false}, {"paper": {"id": "2605.13301", "authors": [{"_id": "6a05351eb1a8cbabc9f0872f", "name": "Yafu Li", "hidden": false}, {"_id": "6a05351eb1a8cbabc9f08730", "name": "Runzhe Zhan", "hidden": false}, {"_id": "6a05351eb1a8cbabc9f08731", "name": "Haoran Zhang", "hidden": false}, {"_id": "6a05351eb1a8cbabc9f08732", "name": "Shunkai Zhang", "hidden": false}, {"_id": "6a05351eb1a8cbabc9f08733", "name": "Yizhuo Li", "hidden": false}, {"_id": "6a05351eb1a8cbabc9f08734", "name": "Zhilin Wang", "hidden": false}, {"_id": "6a05351eb1a8cbabc9f08735", "name": "Jiacheng Chen", "hidden": false}, {"_id": "6a05351eb1a8cbabc9f08736", "name": "Futing Wang", "hidden": false}, {"_id": "6a05351eb1a8cbabc9f08737", "name": "Xuyang Hu", "hidden": false}, {"_id": "6a05351eb1a8cbabc9f08738", "name": "Yuchen Fan", "hidden": false}, {"_id": "6a05351eb1a8cbabc9f08739", "name": "Bangjie Xu", "hidden": false}, {"_id": "6a05351eb1a8cbabc9f0873a", "name": "Yucheng Su", "hidden": false}, {"_id": "6a05351eb1a8cbabc9f0873b", "name": "Xinmiao Han", "hidden": false}, {"_id": "6a05351eb1a8cbabc9f0873c", "name": "Chenxi Li", "hidden": false}, {"_id": "6a05351eb1a8cbabc9f0873d", "name": "Haodi Lei", "hidden": false}, {"_id": "6a05351eb1a8cbabc9f0873e", "name": "Yufeng Zhao", "hidden": false}, {"_id": "6a05351eb1a8cbabc9f0873f", "name": "Zejin Lin", "hidden": false}, {"_id": "6a05351eb1a8cbabc9f08740", "name": "Qianjia Cheng", "hidden": false}, {"_id": "6a05351eb1a8cbabc9f08741", "name": "Tong Zhu", "hidden": false}, {"_id": "6a05351eb1a8cbabc9f08742", "name": "Xiaoye Qu", "hidden": false}, {"_id": "6a05351eb1a8cbabc9f08743", "name": "Ganqu Cui", "hidden": false}, {"_id": "6a05351eb1a8cbabc9f08744", "name": "Peng Ye", "hidden": false}, {"_id": "6a05351eb1a8cbabc9f08745", "name": "Yun Luo", "hidden": false}, {"_id": "6a05351eb1a8cbabc9f08746", "name": "Zhouchen Lin", "hidden": false}, {"_id": "6a05351eb1a8cbabc9f08747", "name": "Yu Qiao", "hidden": false}, {"_id": "6a05351eb1a8cbabc9f08748", "name": "Bowen Zhou", "hidden": false}, {"_id": "6a05351eb1a8cbabc9f08749", "name": "Ning Ding", "hidden": false}, {"_id": "6a05351eb1a8cbabc9f0874a", "name": "Yu Cheng", "hidden": false}], "publishedAt": "2026-05-13T00:00:00.000Z", "submittedOnDailyAt": "2026-05-15T00:00:00.000Z", "title": "Achieving Gold-Medal-Level Olympiad Reasoning via Simple and Unified Scaling", "submittedOnDailyBy": {"_id": "63f3502a520c14618925825a", "avatarUrl": "/avatars/e986a2a6625e7be6890616a417f908d2.svg", "isPro": false, "fullname": "Yafu Li", "user": "yaful", "type": "user", "name": "yaful"}, "summary": "Recent progress in reasoning models has substantially advanced long-horizon mathematical and scientific problem solving, with several systems now reaching gold-medal-level performance on International Mathematical Olympiad (IMO) and International Physics Olympiad (IPhO) problems. In this paper, we introduce a simple and unified recipe for converting a post-trained reasoning backbone into a rigorous olympiad-level solver. The recipe first uses a reverse-perplexity curriculum for SFT to instill rigorous proof-search and self-checking behaviors, then scales these behaviors through a two-stage RL pipeline that progresses from RL with verifiable rewards to more delicate proof-level RL, and finally boosts solving performance with test-time scaling. Applying this recipe, we train a 30B-A3B backbone with SFT on around 340K sub-8K-token trajectories followed by 200 RL steps. The resulting model, SU-01, supports stable reasoning on difficult problems with trajectories exceeding 100K tokens, while achieving gold-medal-level performance on mathematical and physical olympiad competitions, including IMO 2025/USAMO 2026 and IPhO 2024/2025. It also demonstrates strong generalization of scientific reasoning to domains beyond mathematics and physics.", "upvotes": 126, "discussionId": "6a05351fb1a8cbabc9f0874b", "projectPage": "https://simplified-reasoning.github.io/SU-01", "githubRepo": "https://github.com/Simplified-Reasoning/SU-01", "githubRepoAddedBy": "user", "ai_summary": "A systematic approach transforms post-trained reasoning models into rigorous olympiad-level solvers through reverse-perplexity curriculum, two-stage reinforcement learning, and test-time scaling, achieving gold-medal performance on mathematical and physics competitions.", "ai_keywords": ["reasoning models", "mathematical problem solving", "scientific problem solving", "International Mathematical Olympiad", "International Physics Olympiad", "reverse-perplexity curriculum", "supervised fine-tuning", "proof-search", "self-checking behaviors", "reinforcement learning", "verifiable rewards", "proof-level RL", "test-time scaling", "trajectory", "token", "backbone", "SFT", "RL"], "githubStars": 54, "summary_zh": "<ul>\n    <li>\u6700\u8fd1\u7684\u63a8\u7406\u6a21\u578b\u8fdb\u5c55\u663e\u8457\u63d0\u5347\u4e86\u6570\u5b66\u548c\u79d1\u5b66\u95ee\u9898\u7684\u89e3\u51b3\u80fd\u529b\u3002</li>\n    <li>\u8be5\u8bba\u6587\u63d0\u51fa\u4e86\u4e00\u79cd\u7b80\u5355\u7edf\u4e00\u7684\u65b9\u6cd5\uff0c\u5c06\u540e\u8bad\u7ec3\u7684\u63a8\u7406\u6a21\u578b\u8f6c\u5316\u4e3a\u4e25\u683c\u7684\u5965\u6797\u5339\u514b\u7ea7\u522b\u89e3\u9898\u8005\u3002</li>\n    <li>\u65b9\u6cd5\u5305\u62ec\u4f7f\u7528\u53cd\u56f0\u60d1\u8bfe\u7a0b\u548c\u4e24\u9636\u6bb5\u5f3a\u5316\u5b66\u4e60\uff0c\u4ee5\u57f9\u517b\u4e25\u8c28\u7684\u8bc1\u660e\u641c\u7d22\u548c\u81ea\u6211\u68c0\u67e5\u884c\u4e3a\u3002</li>\n    <li>\u8bad\u7ec3\u51fa\u7684\u6a21\u578bSU-01\u5728\u89e3\u51b3\u590d\u6742\u95ee\u9898\u65f6\u8868\u73b0\u7a33\u5b9a\uff0c\u80fd\u591f\u5904\u7406\u8d85\u8fc710\u4e07tokens\u7684\u8f68\u8ff9\u3002</li>\n    <li>SU-01\u5728\u56fd\u9645\u6570\u5b66\u5965\u6797\u5339\u514b\u548c\u56fd\u9645\u7269\u7406\u5965\u6797\u5339\u514b\u7b49\u6bd4\u8d5b\u4e2d\u8fbe\u5230\u4e86\u91d1\u724c\u7ea7\u522b\u7684\u8868\u73b0\uff0c\u5e76\u5728\u79d1\u5b66\u63a8\u7406\u4e0a\u5177\u6709\u826f\u597d\u7684\u6cdb\u5316\u80fd\u529b\u3002</li>\n</ul>", "summary_simple": "<ul>\n  <li>Recent advancements in reasoning models have improved problem solving in math and science, achieving top performance in international competitions.</li>\n  <li>This paper presents a method to train these models into effective olympiad-level solvers using a structured approach.</li>\n  <li>The method involves a two-stage reinforcement learning process to enhance proof-search and self-checking skills.</li>\n  <li>The resulting model, SU-01, can handle complex problems and has performed well in competitions like IMO and IPhO.</li>\n  <li>SU-01 also shows good reasoning skills in areas outside math and physics.</li>\n</ul>"}, "publishedAt": "2026-05-12T20:00:00.000Z", "title": "Achieving Gold-Medal-Level Olympiad Reasoning via Simple and Unified Scaling", "summary": "Recent progress in reasoning models has substantially advanced long-horizon mathematical and scientific problem solving, with several systems now reaching gold-medal-level performance on International Mathematical Olympiad (IMO) and International Physics Olympiad (IPhO) problems. In this paper, we introduce a simple and unified recipe for converting a post-trained reasoning backbone into a rigorous olympiad-level solver. The recipe first uses a reverse-perplexity curriculum for SFT to instill rigorous proof-search and self-checking behaviors, then scales these behaviors through a two-stage RL pipeline that progresses from RL with verifiable rewards to more delicate proof-level RL, and finally boosts solving performance with test-time scaling. Applying this recipe, we train a 30B-A3B backbone with SFT on around 340K sub-8K-token trajectories followed by 200 RL steps. The resulting model, SU-01, supports stable reasoning on difficult problems with trajectories exceeding 100K tokens, while achieving gold-medal-level performance on mathematical and physical olympiad competitions, including IMO 2025/USAMO 2026 and IPhO 2024/2025. It also demonstrates strong generalization of scientific reasoning to domains beyond mathematics and physics.", "thumbnail": "https://cdn-thumbnails.huggingface.co/social-thumbnails/papers/2605.13301.png", "numComments": 1, "submittedBy": {"_id": "63f3502a520c14618925825a", "avatarUrl": "/avatars/e986a2a6625e7be6890616a417f908d2.svg", "fullname": "Yafu Li", "name": "yaful", "type": "user", "isPro": false, "isHf": false, "isHfAdmin": false, "isMod": false, "followerCount": 9, "isUserFollowing": false}, "isAuthorParticipating": false}]
};
